INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(1, '10 Top Bred Jordans Of All-Time', '&lt;h1&gt;10.) Air Jordan 8&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/OHXbaHs.jpg&quot; alt=&quot;Air Jordan 8&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;9.) Air Jordan 9&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/B4RCdBN.png&quot; alt=&quot;Air Jordan 9&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;8.) Air Jordan 16&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/0AZdjou.png&quot; alt=&quot;Air Jordan 8&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;8.) Air Jordan 7&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3njHywW.png&quot; alt=&quot;Air Jordan 7&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;6.) Air Jordan 13&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/a28rfFG.jpg&quot; alt=&quot;Air Jordan 13&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;5.) Air Jordan 12&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/tBwNy2Z.jpg&quot; alt=&quot;Air Jordan 12&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;4.) Air Jordan 6&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zbqvKCL.jpg&quot; alt=&quot;Air Jordan 6&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;3.) Air Jordan 4&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/SUsmXhL.png&quot; alt=&quot;Air Jordan 4&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;2.) Air Jordan 11&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/8hAzoEQ.png&quot; alt=&quot;Air Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;1.) Air Jordan 1&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/R2pnboj.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/OHXbaHs.jpg', 'top-10-bred-jordans-alltime', 'jordans,bred,retro,nike', '2018-11-17 00:52:26', '2018-11-17 00:52:26'),
(2, 'How To Tell If Your Yeezy Boost 700 Wave Runners Are Fake', '&lt;h3&gt;How To Tell If Your Yeezy Boost 700 Wave Runners Are Fake&lt;/h3&gt;\n&lt;p&gt;The adidas Yeezy Boost 700 was released on March 10th on adidas.com/YEEZY and on YEEZY SUPPLY in the U.S. only. If you copped a pair or planning to buy one. Use this Yeezy guide to tell if your Yeezy Boost 700 Wave runners might be fake. Don''t get got or caught out here slipping with replicas.&lt;/p&gt;\n&lt;h2&gt;Toe Box Suede Quality&lt;/h2&gt;\n&lt;p&gt;The suede toe box on the real Yeezy 700 wave runners is a little rougher, displaying some grain. Compared to the fake pair which is incredibly smooth and looks really cheap.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/MTkzf6B.jpg&quot; alt=&quot;Fake Yeezy 700 Toe Box&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/6RnCS9T.jpg&quot; alt=&quot;Fake Yeezy 700 Toe Box Above&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Leather Quality&lt;/h2&gt;\n&lt;p&gt;Like the toe box the leather on the real Wave Runners is not completely smooth and has some tumble to it indicating better quality. The stitching on the real Yeezy 700s are darker and more embedded.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Prcp4Eh.jpg&quot; alt=&quot;yeezy 700 leather stitching&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/xu3YlMy.jpg&quot; alt=&quot;yeezy 700 leather stitching&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;3M Material&lt;/h2&gt;\n&lt;p&gt;Like Jordan and other sneakers, Yeezy Boost 700 Wave Runners have 3m reflected material on certain parts of the site. You can see these by using a flash from your phone to see them. On a real par the 2 circular shapes in the black material are larger than on the fakes and also appear closer together.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/NQMZKEH.jpg&quot; alt=&quot;yeezy 700 3m reflective&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check The Mesh Pattern&lt;/h2&gt;\n&lt;p&gt;The Yeezy Boost 700&rsquo;s have a uniquely and intricate design upper. The real pay should be darker and closely space giving it a very tight look.\nThe fake 700 will have a looser pattern than is a bit lighter in color.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ClaV9ZM.jpg&quot; alt=&quot;yeezy 700 mesh&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Sneaker Shape&lt;/h2&gt;\n&lt;p&gt;The shape of the fakes tend be taller and blockier. The wave runners are already a bulky shoe but the fake 700s tend to look bulkier.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3tImezZ.jpg&quot; alt=&quot;yeezy 700 sneaker shape&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Sneaker Heel&lt;/h2&gt;\n&lt;p&gt;The heel comes down to the leather quality and look at the mesh areas around the heel.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/nAv98aX.jpg&quot; alt=&quot;yeezy 700 sneaker heel&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Yeezy Box&lt;/h2&gt;\n&lt;p&gt;Most fakes have a different and often low quality box and more than often in terrible condition. The Yeezy 700 box can be far t0o small or missing key stickers along the front face.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/4Te8c9T.jpg&quot; alt=&quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/efx55yc.jpg&quot; alt=&quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/rnsBwRQ.jpg&quot; alt=&quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Checkout Some of the latest Yeezy 700s available for sale on Stockx&lt;/p&gt;', 'https://i.imgur.com/4Te8c9T.jpg', 'how-to-spot-fake-yeezy-700-waverunner', 'yeezy,700,waverunner,adidas', '2018-08-02 01:23:14', '2018-08-02 01:23:14'),
(3, 'adidas Originals YEEZY BOOST 700 "Wave Runner" on Foot', '&lt;p&gt;The adidas YEEZY BOOST 700 on foot preview. The adidas YEEZY BOOST 700 by walking sneak peak. The Wave Runner''s thick padded sole houses BOOST padding while at the same time being introduced in Chalk White with insights of dark and orange for included detail. As you climb towards the upper you''ll discover softened cowhide on its overlay while calfskin and work are set on its underlays. The upper blends dark, center dark, green and light blue while its bands are dealt with in lime green. Also, 3M intelligent specifying is put on its foot sole area, trailed by unobtrusive Three Stripes on every sidelong and average side and toe box.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/YlTGZnE.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/zE4WK1u.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/pnkTNc8.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/kLl4lus.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/5xikY5E.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/REh9IUo.jpg&quot; alt=&quot;Yeezy Boost 700&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/YlTGZnE.jpg', 'wave-runner-yeezy-on-foot', 'yeezy,waverunner', '2018-08-18 17:45:32', '2018-08-18 17:45:32'),
(5, 'The definitive ranking of the top 10 Air Jordan 1s', '&lt;h1&gt;The definitive ranking of the top 10 Air Jordan 1s&lt;/h1&gt;\n&lt;h1&gt;10.) Air Jordan 1 Top 3&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/PInxfv0.jpg&quot; alt=&quot;Air Jordan 1 Top 3&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;9.) Air Jordan 1 UNC&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/CqoDQLV.jpg&quot; alt=&quot;Air Jordan 1 UNC&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;8.) Air Jordan 1 Bred Toe&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/apkm8Ac.png&quot; alt=&quot;Air Jordan 1 Bred Toe&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;7.) Air Jordan 1 Shadow&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/yeBz9ax.png&quot; alt=&quot;Air Jordan 1 Shadow&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;6.) Air Jordan 1 Reverse Shattered Backboard&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/e94JVi8.jpg&quot; alt=&quot;Air Jordan 1 Reverse Shattered Backboard&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;5.) Air Jordan 1 Black Toe&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/u6ZiVrt.png&quot; alt=&quot;Air Jordan 1 Black Toe&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;4.) Air Jordan 1 Royal Blue&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/FpwspAL.jpg&quot; alt=&quot;Air Jordan 1 Royal Blue&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;3.) Air Jordan 1 Shattered Backboard&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/NeQIKdC.png&quot; alt=&quot;Air Jordan 1 Shattered Backboard&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;2.) Air Jordan 1 Chicago&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/UbzAF9t.jpg&quot; alt=&quot;Air Jordan 1 Chicago&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;1.) Air Jordan 1 Bred&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/R2pnboj.jpg&quot; alt=&quot;Air Jordan 1 Bred&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/R2pnboj.jpg', 'top-10-air-jordan-1-colorway', 'air,jordan,1,colorway', '2018-08-29 21:03:35', '2018-08-29 21:03:35'),
(6, 'How To Tell If Your Yeezy Boost 500 Utility Black Are Fake', '&lt;h2&gt;How To Tell If Your Yeezy Boost 500 Utility Black Are Fake&lt;/h2&gt;\n&lt;p&gt;The adidas Yeezy Boost 700 was released on March 10th on adidas.com/YEEZY and on YEEZY SUPPLY in the U.S. only. If you copped a pair or planning to buy one. Use this Yeezy guide to tell if your Yeezy Boost 700 Wave runners might be fake. Don''t get got or caught out here slipping with replicas.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/kgK3ZY8.jpg&quot; alt=&quot;Yeezy 500 box&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Real Yeezy 500 Utility Black box&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Style code is F36640. Fakes may have incorrect style code&lt;/li&gt;\n&lt;li&gt;UPC on box should match on sneaker tags, fakes will not match&lt;/li&gt;\n&lt;li&gt;Colors code tag are UTIBLK/UTIBLK/UTIBLK\nFakes have been seen to not have the correct style, boldness, or size in the fonts&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Suede Quality&lt;/h2&gt;\n&lt;p&gt;The suede on real Yeezy 500 Utility Black is a little rough, displaying some grain. Compared to a fake pair which is incredibly smooth and looks really cheap. The stitching on the legit pair should be perfect without any loose stitching or flaws. Fakes will usually have loose stiching or incorrect threading used that doesn''t make the Yeezy 500 utility blacks original color. Take a close look at the indented groves on the rubber on the heel tab and confirm they are the same height.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/IY6a1we.jpg&quot; alt=&quot;Yeezy 500 side&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/N8PGuS3.jpg&quot; alt=&quot;Yeezy 500 toe box&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/q5ZtSy4.jpg&quot; alt=&quot;Yeezy 500 heel&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Size tag&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/TPZI498.jpg&quot; alt=&quot;Yeezy 500 size tag&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Production date on the utlity black 500 is 03/18. Confirm the production on your pairs. If it incorrect then your pair may be fake, there hasn''t been any new production of the 500 utility blacks yet. Make sure UPC # matches the one on the front of the box as previously mentioned earlier.&lt;/p&gt;', 'https://i.imgur.com/HydtIyx.jpg', 'how-to-spot-fake-yeezy-500-utility-black', 'yeezy,500,utility,black', '2018-12-03 00:16:04', '2018-12-03 00:16:04'),
(7, 'Yeezy Beluga 2.0 sz 8.5 authentic reference pictures', '&lt;p&gt;Yeezy Beluga 2.0 sz 8.5 authentic reference pictures&lt;/p&gt;\n&lt;p&gt;Adidas officially debut the next generation of their 350 Boost with the release of the adidas Yeezy Boost 350 V2 &quot;Beluga&quot; on September. 24, 2016 for $220. The sneaker features a Primeknit upper done in a mix of steel grey and beluga with a solar red stripe. &lt;/p&gt;\n&lt;p&gt;These pictures below feature an authentic pair of Yeezy V2 Belugas &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Bmwu8UW.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/WGDLtSv.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/6w78MJp.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/ntMScex.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/mmzOiHZ.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/o6RsqRE.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/zSasFJo.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/2l4EWUR.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/L7LwpAf.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/S117XOD.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/ih3aWj6.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/oryj1Dk.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/JCgKAto.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/fC0YEhX.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/0cIvIDw.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/EiUBnGe.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Luz7x8p.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/4U2p9XS.jpg&quot; alt=&quot;Yeezy 350 beluga&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/Bmwu8UW.jpg', 'yeezy-beluga-v2-real-vs-fake-reference-photos', 'yeezy,beluga,v2', '2018-12-04 05:29:08', '2018-12-04 05:29:08'),
(8, 'Guide To Flipping and Reselling Sneakers', '&lt;h1&gt;Guide To Flipping and Reselling Sneakers&lt;/h1&gt;\n&lt;p&gt;So you want to make some side money flipping sneakers part time? If you&rsquo;re looking to get started and learn a few tips on reselling, this is the ultimate reselling  sneaker guide. The most important thing to keep in mind upon entering the reselling business is that you always want to sell your sneakers more than what you''ve paid for them. Many people enter the reselling game to simply flip sneakers but are unaware that they''re breaking even after fees or even worse, losing money. Don''t hustle backwards.&lt;/p&gt;\n&lt;h2&gt;Researching new sneakers&lt;/h2&gt;\n&lt;p&gt;The first step in starting your journey to flipping sneakers is to begin knowing when popular sneakers are going to be releasing. Most of the money you make from reselling will be buying sneakers on release dates and reselling them shortly after for profit.&lt;/p&gt;\n&lt;h3&gt;Keep track of all the latest sneaker release dates below.&lt;/h3&gt;\n&lt;p&gt;&lt;a href=&quot;http://soleinsider.com/releases-dates&quot;&gt;http://soleinsider.com/releases-dates&lt;/a&gt; - All Releases\n&lt;a href=&quot;http://soleinsider.com/yeezy-releases&quot;&gt;http://soleinsider.com/yeezy-releases&lt;/a&gt; - Yeezy Releases\n&lt;a href=&quot;http://soleinsider.com/jordan-releases&quot;&gt;http://soleinsider.com/jordan-releases&lt;/a&gt; - Jordan Releases\n&lt;a href=&quot;http://soleinsider.com/nike-releases&quot;&gt;http://soleinsider.com/nike-releases&lt;/a&gt; - Nike Releases&lt;/p&gt;\n&lt;h2&gt;Which sneakers to buy?&lt;/h2&gt;\n&lt;p&gt;You want to buy sneakers which are high in demand. Here are some of the signs you should look for sneakers that will likely be in high demand or have a lot of buzz. Some of the more popular sneakers right now that will almost guarentee you 100% profit are:&lt;/p&gt;\n&lt;ul&gt;\n&lt;li&gt;Off-White and Nike collobs&lt;/li&gt;\n&lt;li&gt;Acronym and Nike collabs&lt;/li&gt;\n&lt;li&gt;Other highly covered nike Collabs&lt;/li&gt;\n&lt;li&gt;Limited release Yeezys. Restocks will not be as profitable&lt;/li&gt;\n&lt;li&gt;Jordans 1s High OGs or popular jordans retro&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Where to buy?&lt;/h2&gt;\n&lt;h2&gt;Where should you sell them?&lt;/h2&gt;\n&lt;h3&gt;Ebay&lt;/h3&gt;\n&lt;p&gt;One of the oldest, if not oldest auction site. eBay has the largest selection of sneakers and has the biggest buyer and seller user base. Upon purchase of your sneakers, you should list them on eBay. Keep in mind that ebay charges a final value fee for succesfully completing your sale. Also, you will most likely accept paypal as your payment method. Paypal also charges their own transaction fee for accepting payments.&lt;/p&gt;\n&lt;h3&gt;Stock X.&lt;/h3&gt;\n&lt;p&gt;The world&rsquo;s most famous sneakers stock exchange. A live auction place where you will be able to bid and ask for the most wanted sneakers, worldwide. Shipping is free for sellers in the US, $20 for sellers in Canada and $30 for sellers in every other country. Only brand new merchandise in the original box is accepted.&lt;/p&gt;', 'https://i.imgur.com/VlwE7km.jpg', 'sneaker-flipping-guide', 'sneakers,reselling,flipping', '2019-09-27 23:42:46', '2019-09-27 23:42:46'),
(9, 'How To Tell If Your Yeezy 350 V2 Are Fake', '&lt;h3&gt;How To Tell If Your Yeezy 350 V2 Are Fake&lt;/h3&gt;\r\n&lt;p&gt;No doubt that the fake designer market is a huge and lucrative one. In recent times you can purchase any newly released sneakers thinking it&rsquo;s the original one. In order words, it is possible to buy fake sneakers for the price of the original one. Since Kanye West released the Yeezy sneaker in 2015. The Yeezy 350 v2 series has become the most popular sneakers in the market today. \r\nThe majority of people tend to buy this product based on the features and quality associated with the sneakers. The hard truth is that the fake Yeezy 350 v2 tends to populate the market than the original one. In this article, we shall be looking out some of the best ways to spot fake sneakers. This is to give you adequate information concerning Yeezy 350 v2 before making a purchase.\r\nBest Way To Spot Fake Sneaker Yeezy 350 V2\r\nHere we shall be looking at the various ways, methods, to ascertain fake sneakers from the real ones. This includes but not limited to the following:&lt;/p&gt;\r\n&lt;h3&gt;Stitching Areas&lt;/h3&gt;\r\n&lt;p&gt;Here is one of the best ways to identify either sneaker Yeezy 350 v2 is real or fake. The down stitching and the center of your Yeezy''s toe should cross over in form of &quot;X&quot; thereby forming a square shape. Try this pattern with care and you see the difference. The fake ones won&rsquo;t be able to form this exact shape.\r\nThe Heel Tab Region\r\nThis is another important area to spot fake or real sneaker Yeezy 350 v2. The edge of the heel tab should be very close to the ankle collar. The back rectangle on the heel tab should be in an appropriate position at the center. In order to know the fake one, you find out that the heel tab is not properly aligned with the center.&lt;/p&gt;\r\n&lt;h3&gt;Insole Writing&lt;/h3&gt;\r\n&lt;p&gt;The writing on the insoles should be written in grey color. The fake ones if often written in stark white. The writing on both pairs should reflect one another. Another way to know if the sneaker is fake or real is when you turn the soles upside down, the original has some intricate embossed the entire sole while the fake ones are skewed or nothing at all.&lt;/p&gt;\r\n&lt;h3&gt;Check The Heel Tab interior&lt;/h3&gt;\r\n&lt;p&gt;When buying the Yeezy 350 v2 make sure you lookout for the interior design color of the stripes on the heel tab. On the original sneaker, the stripes should be part and parcel of the fabric, this is not so on the fake pair. The lines should elongate from the down to the sole of the shoe this is how you spot original Yeezy 350 v2.&lt;/p&gt;\r\n&lt;h3&gt;Size Tag&lt;/h3&gt;\r\n&lt;p&gt;The size tag of your real pair Yeezy 350 v2 should ''Made In China''. These is also a unique barcode in the size tag. If you see anything else, most likely your pair is fake.ions, gender specification and serial codes.&lt;/p&gt;\r\n&lt;h3&gt;Conclusion&lt;/h3&gt;\r\n&lt;p&gt;On a final note, the above ways are some of the best and more visible ways to spot fake sneaker Yeezy 350 v2. It is imperative to look out for the above tips before making a purchase of any pair of sneakers.&lt;/p&gt;', 'https://i.imgur.com/nLrKWrF.jpg', 'spot-fake-yeezy-350-v2', 'sneakers,yeezys,boost,fakevsreal', '2020-02-03 00:31:30', '2020-02-03 00:31:30'),
(10, 'How to tell if your Air Jordan 1s are fake', '&lt;h3&gt;How to tell if your Air Jordan 1s are fake&lt;/h3&gt;\r\n&lt;p&gt;Fake Jordan 1s are everywhere. You can find them all over eBay and other online websites. Fakes are also sold in some stores, like local sneaker stores.  The air Jordan is 1 of the most replicated show, mostly because of the simplicity of it&rsquo;s design. Although the design is simple, there are a few tell-tale signs of real vs fake pairs.  Our guide is here to help You avoid buying a pair of fake Jordan 1s buy showing you the signs fake vs real Jordan 1&lt;/p&gt;\r\n&lt;h3&gt;Price&lt;/h3&gt;\r\n&lt;p&gt;When buying Air Jordan 1s the first thing to look out for is price. The minimum Air Jordan 1 high price is usually $160. Mids and Low tops are usually priced at $140 and $120 respectively.  Anything less than that is most likely fake unless is being sold in a certified Nike outlet.  Low prices and beat up boxes are your first clue that you have a fake, counterfeit, or ilegal b-grade Jordan 1 shoes. Remember, slightly used does not mean the shoes were real Nikes to start with. Slightly used is usually a way for sellers to try and pass of the signs of fake sneakers as normal wear and tear.&lt;/p&gt;\r\n&lt;h3&gt;Air Jordan Box&lt;/h3&gt;\r\n&lt;p&gt;The box on fake pairs is usually very low quality. Looking at the box, you will notice that the fake pair is often thinner, the print on the box is often more faint and the tag is usually off. A lot of fake jordan 1 boxes tend to be beat up really bad, this happens during shipping from China. Sometimes the boxes are also damaged because the shoes are shipped out 1 at a time for the company that is selling the fakes. This will often cause the box to be damaged since proper care isn''t given the wrapping,&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/Fake-Air-jordan-1-Royal-Satin-5.jpg\r\n&quot; alt=&quot;Air Jordan 1 box&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;Below is a real box that features the new Jordan 1 black tag. Newer pairs like the Air Jordan 1 Shadows have this new black tag. Look out for this.&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/DYwuhKHV4AAGEje.jpg&quot; alt=&quot;Air Jordan 1 box&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Air Jordan wings&lt;/h3&gt;\r\n&lt;p&gt;Left is real. Right is fake pair or Jordan 1s&lt;/p&gt;\r\n&lt;p&gt;The Air Jordan logo should be embossed and not flat on the leather. You should be able to feel the logo by running your fingers across it. The real Nike does not have any stitching guides to help the stitchers locate the panels during assembly. The red logo panel of the fake Nike is loaded with these little assembly guides.&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image6.png&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Toebox&lt;/h3&gt;\r\n&lt;p&gt;You will notice peaks on the fake pair there is a peak right on the toe box. Air Jordan 1 toe boxes should be smooth all the way around and should not come to a peak in the middle of the toe box.&lt;/p&gt;\r\n&lt;p&gt;You will also notice below the toe box holes should be arched. On the fake pair you&rsquo;ll often see the holes are not arched and sometimes form a straight line.&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image9.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Sneaker Tongue&lt;/h3&gt;\r\n&lt;p&gt;Look at the Nike Air logo on the tongue tag\r\nNext we&rsquo;re going to have a look at the Nike logo found on the tongue.&lt;/p&gt;\r\n&lt;p&gt;The curvature of the fake pair tends to be a little off compared the authentic. The Nike  swoosh on the fake pair is also fuzzier and not as detailed.  The quality of the print is definitely inferior to that of the authentic pair. The fake pair also tend to cut off the Nike Air text. There should be some padding/spacing at the bottom of the text and the end of the tag,&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image1.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Heel shape also known as the hourglass shape&lt;/h3&gt;\r\n&lt;p&gt;The most common and easiest way to tell a fake pair of Jordan 1s is the heel. It seems the manufacturers have not been able to get the hourglass shape of the heel correct. As you can see below, the real pair has an hourglass shape. The fake pair, the heel just flows straight down in one rectangular shape.\r\nImage result for jordan 1 fake vs real heal&quot;&lt;/p&gt;\r\n&lt;p&gt;The yellow lines should call attention to the distinctions that happen at the edges between the two images. The yellow square shapes are intended to show the difference in the materials between the two pairs of Jordan 1s.&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image7.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;\r\n&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image2.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Nike logo on insole&lt;/h3&gt;\r\n&lt;p&gt;Check the quality on the Nike air logo on the insole. The fake pair will have a low quality logo that almost looks ready to fade. It will most likely fade after just a few wears. On a real pair, the logo will still be visible after multiple wears.&lt;/p&gt;\r\n&lt;p&gt;&lt;img class=&quot;lazy&quot; data-src=&quot;https://soleinsider-articles.s3.amazonaws.com/image5.jpg&quot; alt=&quot;Air Jordan 1&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;The too long didn&rsquo;t read guide (tldr), to spotting a fake pair or Air Jordan 1s instantly.&lt;/p&gt;\r\n&lt;p&gt;1.Check whether the hourglass shape is present. This is always the easiest way to spot a fake pair. Most fakes will not have an hourglass shape. If you have a really good quality air Jordan 1 replica that is able to replicate the shape, then i would check the next step below.&lt;/p&gt;\r\n&lt;ol start=&quot;2&quot;&gt;\r\n&lt;li&gt;\r\n&lt;p&gt;Check out the Jordan wings logo. Look out for any inconsistent letters. Check the spacing make sure the characters are not too far apart or touching. The letters should all be evenly spaced.&lt;/p&gt;\r\n&lt;/li&gt;\r\n&lt;li&gt;\r\n&lt;p&gt;Look at the toe box. Check for any peaks at the toe box. Fakes tend to have peaks while the toe box of a legit pair will be perfectly smooth all around the toe box.&lt;/p&gt;\r\n&lt;/li&gt;\r\n&lt;li&gt;\r\n&lt;p&gt;Check if the pair came with extra laces in the bag. Most air Jordan 1 high pairs come with extra laces.&lt;/p&gt;\r\n&lt;/li&gt;\r\n&lt;li&gt;\r\n&lt;p&gt;If the box is really beat up. The pair is most likely fake. The box would have been damaged during shipping and improper handling at the factor. Check the quality of the box, fake boxes often use thinner and cheaper quality cardboard that doesn&rsquo;t have the same sturdiness as normal Air Jordan 1 boxes.&lt;/p&gt;\r\n&lt;/li&gt;\r\n&lt;/ol&gt;\r\n&lt;p&gt;One of the best choices you can make is to buy your Jordan 1 for authorized sneaker sellers and avoid smaller stores, auction sites and craigslist. If you want to buy online. I would look at Stockx.&lt;/p&gt;', 'https://soleinsider-articles.s3.amazonaws.com/012234_01.jpg', 'how-to-spot-fake-jordan-1', 'jordans,jordan1,fakevsreal, nike,air', '2021-08-07 15:36:24', '2021-08-07 15:36:24'),
(11, 'How to  tell if your Supreme hoody is fake', '&lt;h3&gt;How to  tell if your Supreme hoody is fake&lt;/h3&gt;\r\n&lt;p&gt;Supreme is indeed one of the most famous and coolest streetwear labels in the world right now. So it makes sense that there is a huge market for both new and resale products of the brand. But, while getting your hand on an excellent piece from Supreme can be exciting, finding out that you accidentally bought a fake can be both embarrassing and costly. &lt;/p&gt;\r\n&lt;p&gt;Unfortunately, this is one problem faced by many customers these days. Thankfully, it is possible to spot the difference between real and fake products from Supreme. Here is our handy guide which will help you in spotting the difference. &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/D8STbK6.png&quot; alt=&quot;Supreme Logo&quot; title=&quot;Supreme Logo&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Signs of Fake Supreme&lt;/h3&gt;\r\n&lt;p&gt;When you are buying a Supreme piece, you want to make sure that your money is going into a real thing. By checking some key elements such as a logo, print, labels, drawstring, stitching, and overall quality of the piece, you should be able to determine if it''s genuine or not. Of course, while inspecting these features, it is essential to know what you are looking for. &lt;/p&gt;\r\n&lt;h3&gt;How to Spot A Fake Supreme Logo&lt;/h3&gt;\r\n&lt;p&gt;You may think that just by looking at the logo, you can spot a fake Supreme. But it''s not that easy. A lot of people create Supreme hoodies and other items as close as the real thing. &lt;/p&gt;\r\n&lt;p&gt;To check for a fake product, it is essential to make sure that the box logo should be embroidered entirely with a high-quality stitch. If the stitching looks off or is broken, the product is most likely fake. Another way of spotting a fake product is the color of the logo. The red on real Supreme is bright and vibrant dark red color. A fake is either too light or too dark &lt;/p&gt;\r\n&lt;p&gt;Another trick is to check the lettering. There should be plenty of space around the word &lsquo;Supreme,&rsquo;and the embroidery should be in matte white. Fake Supreme logos have a grey tinge to them. &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/RsCpKHC.jpg&quot; alt=&quot;Supreme Box Logo&quot; title=&quot;Supreme Box Logo&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;You can look the back stitching goes into the bottom of the p. Look at the picture below for a closer look at what this looks like&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3IEcX9I.png&quot; alt=&quot;Supreme Box Logo&quot; title=&quot;Supreme Box Logo&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;The Label&lt;/h3&gt;\r\n&lt;p&gt;The label of Supreme clothing is the easiest way to tell if a product is genuine or fake. It&rsquo;s all in the small details as the manufacturer will try to be as convincing as possible. Firstly, take a look inside the top label of the hoodie. The main difference between a real and fake is the size and spacing of the word &lsquo;Supreme.&rsquo; On an authentic hoodie, the word &lsquo;Supreme&rsquo; will take up the whole lower space of the tag, and the small &lsquo;made in tag&rsquo; will come down as far as the E of Supreme. &lt;/p&gt;\r\n&lt;p&gt;Next is the wash label, which is found on the left-hand side. On a real product, the wash label will have a single line of stitch going along the top with some label sticking out above it. On a fake, this label will be tucked into the overlocking of the hoodie covering the top of the label completely. &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/yg74Upw.png&quot; alt=&quot;Supreme Label&quot; title=&quot;Supreme Label&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Drawstring&lt;/h3&gt;\r\n&lt;p&gt;When it comes to spotting a fake Supreme, you can tell a lot from drawstring. If the drawstring is round, the product is most likely fake. Supreme uses flat drawstring in all of their hoodies. &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/4WEAbT7.jpg&quot; alt=&quot;Supreme Drawstrings&quot; title=&quot;Supreme Drawstrings&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Print&lt;/h3&gt;\r\n&lt;p&gt;If a Supreme hoodie has a print on the back, the best way to tell if it&rsquo;s real is by checking the quality. The colors differ and are dull or too dark/light on one compared to the other. &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/7ys3KrS.jpg&quot; alt=&quot;Supreme Print&quot; title=&quot;Supreme Print&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Stitching&lt;/h3&gt;\r\n&lt;p&gt;When it comes to checking whether a Supreme T-shirt is fake or authentic, start by looking at the stitching along the neckline. A real Supreme T-shirt has no visible stitching, whether it&rsquo;s one or two lines of it. A fake T-shirt will have a single stitch running down the two edges. Most fakes will have a double stitch. &lt;/p&gt;\r\n&lt;p&gt;Some people prefer to buy fake Supreme products as they are priced much lower. Others get tricked into spending a lot of money on something which they believe to be real when it&rsquo;s actually fake. &lt;/p&gt;\r\n&lt;p&gt;Whenever you are considering to buy Supreme products online, ask the seller to take a picture of the item with a stated name, symbol, or date to make sure it''s legit. Another trick is to look at the price and availability of the product. &lt;/p&gt;\r\n&lt;h3&gt;Washing tag&lt;/h3&gt;\r\n&lt;p&gt;Another easy way to detect that a piece is old is by checking the washing tag. The older pieces have a different washing tag than the new ones. Below is a picture of the old wash tag&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;http://i.imgur.com/wjayVni.jpg&quot; alt=&quot;Supreme Print&quot; title=&quot;Supreme Print&quot; /&gt;&lt;/p&gt;\r\n&lt;h3&gt;Pricing&lt;/h3&gt;\r\n&lt;p&gt;If the product is cheap and or extremely underpriced it may be fake. At this point you want to proceed with caution. Checked if the item is used or just in bad condition. Also checkthe history of the seller. I could possibly be someone who is unware of the full value of the item. If your searching for Surpreme items on ebay, check the sellers past sales. if they have plenty of past sells selling Supreme items with positive feedback, more than likely the item could be real. Also check out stockx and goat for Supreme items. These market Consider the points mentioned above to make sure you''re buying a genuine product. Stay fly.&lt;/p&gt;', 'https://i.imgur.com/D8STbK6.png', 'how-to-spot-fake-supreme', 'supreme,clothing,box hoody', '2020-02-03 00:31:18', '2020-02-03 00:31:18'),
(12, 'How to tell if your Air Jordan 1 "Travis Scott" are fake', '&lt;h1&gt;How to tell if your Air Jordan 1 "Travis Scott" are fake&lt;/h1&gt;\r\n&lt;p&gt;Below will outline the steps to determine if your pair of Air Jordan 1 Travis Scotts are real or Fake. Follow all the steps make sure you dont end up with a fake pair of Air Jordan 1 &quot;Travis Scott&quot;&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/tUfVRSY.jpg&quot; alt=&quot;Jordan 1 Travis Scott&quot; title=&quot;Jordan 1 Travis Scott&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;The packaging/wrapping paper&lt;/h1&gt;\r\n&lt;p&gt;The wax paper found on the fakes is thinner and much cheaper than the authentics. The shade of pink will be incorrect on the fake pairs.&lt;/p&gt;\r\n&lt;p&gt;Fake manufacturers are sending out these Jordans with a darker pink shade when it should be much lighter. See pictures below of real Packaging for the Travis Scott 1s&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/PaFkcT1.jpg&quot; alt=&quot;wrapping paper&quot; title=&quot;Wrapping Paper&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;The Toungue&lt;/h1&gt;\r\n&lt;p&gt;Check out the toungue tag, most replicas don&rsquo;t pay much attention to detail in this area. The main reason it&rsquo;s ignored is because it&rsquo;s usually covered by your jeans or pant leg.&lt;/p&gt;\r\n&lt;p&gt;Check out the pictures below to see a side by side comparison of the tongue tags&lt;/p&gt;\r\n&lt;p&gt;First thing to look at is the font. The font on a a real pair is thick and well filled in while the fake pair is much thinner. Check out the picture to see the different in font boldness. The font on the real pair will also be symmetrical and also straight and cleanly printed. The fake pairs usually ignore this minor detail of the quality.&lt;/p&gt;\r\n&lt;p&gt;The spacing of the text &ldquo;made in China&rdquo; will be ioff on the fake pair, the spacing will be too wide on the fake pair and much tighter on the real pair. \r\nAgain, weird spacing occurs as well on authentic tags &mdash; however, never would you find such wide gaps between letters on genuine pairs.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/TAKGE2l.jpg&quot; alt=&quot;wrapping paper&quot; title=&quot;Wrapping Paper&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;QR Code&lt;/h1&gt;\r\n&lt;p&gt;Have a brief look at the size tag, see if the QR code is present. Also check the size tag. Travis Scott Jordans usually dont have the same size tag you''ll find on other Air Jordan 1 retros&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/6PRSPgV.jpg&quot; alt=&quot;qr code&quot; title=&quot;QR Code&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;Heel logo&lt;/h1&gt;\r\n&lt;p&gt;The heat-stamp / logo should be very defined and thick. The fake pairs of a mch less defined stamp. And the authentic pair has a code bottle like shape, zero in on the yellow lines. The pair pairs have a blocky and more block shape. First indication that they are fake.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/4v656vz.jpg&quot; alt=&quot;heel logo&quot; title=&quot;Heel logo&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;The soles of the sneaker&lt;/h1&gt;\r\n&lt;p&gt;The soles of all Air Jordans 1s have a star pattern and they should be slightly pronounced. On fake pairs they will way too much detail and are very pronounced. I would not use this as a reliable tell, the fakes will get &lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/z4yCKFO.jpg&quot; alt=&quot;Sole&quot; title=&quot;Sole&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;The Nike checkmark&lt;/h1&gt;\r\n&lt;p&gt;The stiching around the the nike swoosh on the fake pairs stops much lower along the check as compared to the right. The leather on the real pair also glossier and higher quality than the fake pair. The fake leather is more regid and is also lackluster. The wings logo should also have some shine or reflection when looked at in the light. The fake pair have very flat wings logos.\r\n&lt;img src=&quot;https://i.imgur.com/jBxrxM7.jpg&quot; alt=&quot;Nike Check&quot; title=&quot;Nike Check&quot; /&gt;&lt;/p&gt;\r\n&lt;h1&gt;The Nike Box&lt;/h1&gt;\r\n&lt;p&gt;You can clearly see that the &ldquo;Jordan.com&rdquo; logo is not alighed with the BR text and number. This attention to detail is missed on the fake pairs.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/FfOzTEN.jpg&quot; alt=&quot;Box&quot; title=&quot;Box&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/tUfVRSY.jpg', 'how-to-spot-travis-scott-air-jordan-1', 'jordans,travis,scott', '2020-02-03 00:31:11', '2020-02-03 00:31:11'),
(13, 'Adidas Yeezy Boost 350 V2 Yecheil FW5190 Stock', '&lt;h3&gt;Adidas Yeezy Boost 350 V2 Yecheil FW5190, How Many Pairs Will Be Available?&lt;/h3&gt;\n&lt;h3&gt;Europe&lt;/h3&gt;\n&lt;p&gt;Out of all the European countries, France tends to get more pairs per stores than the other countries. There will be a total of 374 stores in Europe stocking the Adidas Yeezy Boost 350 V2 Yecheil FW5190 &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/2xNziGU.jpg&quot; alt=&quot;Yecheil Stockist&quot; title=&quot;Yecheil Stockist&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Asia&lt;/h3&gt;\n&lt;p&gt;Japan will have the most stores with inventory for a total of 56 stores. Taiwan and the UAE received a little more pairs this time as well. Closely followed by Saudi Arabia and Indiea. Very little pairs are allocated for Jordan and Bahrain. Total number of stores in Asia stocking the Adidas Yeezy Boost 350 V2 Yecheil FW5190 is around 179&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/K1Sx5Uz.jpg&quot; alt=&quot;Yecheil Stockist&quot; title=&quot;Yecheil Stockist&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Australia&lt;/h3&gt;\n&lt;p&gt;15 stores will be stocking the Adidas Yeezy Boost 350 V2 Yecheil FW5190 in Australia. New Zealand as usual will  have very little allocation as compared to Australia.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Yhri3Ng.jpg&quot; alt=&quot;Yecheil Stockist&quot; title=&quot;Yecheil Stockist&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Africa&lt;/h3&gt;\n&lt;p&gt;The total from Africa is about 21 with South Africa having the highest allocation. Morroco and Egypt round out the top 3 Yeezy Yecheil stockist inAfrica.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/NlRmCPM.jpg&quot; alt=&quot;Yecheil Stockist&quot; title=&quot;Yecheil Stockist&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;South America/Canada&lt;/h3&gt;\n&lt;p&gt;I projected 60,000 pairs for the Adidas Yeezy 350 Yeezreel but in the picture above, individual  asserted that 130,000 pairs were rather  produced. I can&rsquo;t verify that information but I realized that for this to be true each store allocated would&rsquo;ve had to receive about 120 pairs.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/0KQG783.jpg&quot; alt=&quot;Yecheil Stockist&quot; title=&quot;Yecheil Stockist&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Adidas Yeezy Boost 350 V2 Yecheil FW5190 Projected Allocation&lt;/h3&gt;\n&lt;p&gt;The total stock will probably be around 120,000 pairs&lt;/p&gt;', 'https://i.imgur.com/WPJXUCa.png', 'yecheil-350-total-stock', 'yeezy,yecheil', '2019-12-19 03:23:24', '2019-12-19 03:23:24'),
(14, 'How to Tell if your Jordan Retro 11s are fake', '&lt;h1&gt;How to Tell if your Jordan Retro 11s are fake&lt;/h1&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/kLbiYIW.jpg&quot; alt=&quot;Air Jordan 11 Concord&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;In recent years, bogus Jordan pages have sprung up all around the internet. Although their goods are &quot;knock-offs&quot; they have come a long way with their techniques. A number of manufacturers will make sneaker replicas that are nearly similar to the original product.&lt;/p&gt;\r\n&lt;p&gt;There are a lot of ways to find out if your Jordan 11s are real or fake&ndash;we''ve brought them all together in this article.&lt;/p&gt;\r\n&lt;h2&gt;Review the package quality:&lt;/h2&gt;\r\n&lt;p&gt;Jordan''s are a gorgeously packaged sneaker. Before you even look at the sneakers, there are a number of things you should check: Nike bundles their trainers in a durable case with the mark on the top and on the side of the box. Examine the box closely for errors in the brand logo, spelling and the box''s own quality of alignment and finish. Authentic Nike shoeboxes have a close-fitting, gapless top. The paint on the box will be identical and on one side or on the cover will not appear to fade or to be lighter or darker. The box''s appearance will be standardized too.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/j1nspTw.jpg&quot; alt=&quot;Air Jordan 11 &quot; /&gt;&lt;/p&gt;\r\n&lt;h2&gt;Search the packaging sticker (bottom box):&lt;/h2&gt;\r\n&lt;p&gt;You can even dig a lot of information on a deeper note by looking at the tag on the outside of the box: Adidas shoe boxes are made with a label attached to one side of the box that lists descriptions of the shoe''s style name, shoe size, color mix and country of manufacture. A model number will also appear on the label which is nine digits long. Pay particular attention to pronunciation, standard text size and even spacing on the package name.&lt;/p&gt;\r\n&lt;h2&gt;Look at the tag inside the sneaker:&lt;/h2&gt;\r\n&lt;p&gt;A label with the same information that is printed on the box label is located inside the shoe. It will include the year of manufacture and country, the shoe''s style and name. The number of the nine digits&rsquo; style should match the number of the style found on the shoe box outside. Check for details on the shoe label, such as spelling errors and neat and straight stitching. Another much-missed detail is the formation of the letter &quot;Q.&quot; The Q tail will continue inside the circle, in the term &quot;Fabrique.&quot; It''s incredible how simple things like spelling can be left out on knock offs!&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/31ooVHq.jpg&quot; alt=&quot;Air Jordan 11 &quot; /&gt;&lt;/p&gt;\r\n&lt;h2&gt;Cross-check the production date of the sneaker:&lt;/h2&gt;\r\n&lt;p&gt;Sometimes a simple search by Google as to when that version of the sneaker was created can help: The production date printed on the shoe label should match the original production run. The date of production in replica shoes shall be later than the original run.&lt;/p&gt;\r\n&lt;h2&gt;Look how the label is attached:&lt;/h2&gt;\r\n&lt;p&gt;It can also be an indicator of how the label of the box is attached: the label itself should be attached to the shoe so that it is flat, without any bumps or wrinkles in the fabric. The sticker may be disfigured, wrinkled, bumpy in imitation clothing, seem to have been carelessly put, and hard to read.&lt;/p&gt;\r\n&lt;h2&gt;Check the Jumpman inside the tongue:&lt;/h2&gt;\r\n&lt;p&gt;The iconic Michael Jordan &quot;Jumpman&quot; logo is also an easy test: Authentic Nike Air Jordan 11s will have a band of fabric across the top of the shoe''s tongue, centered and neatly embroidered with the Jumpman Jordan. The jump-man''s color should match the shoe''s own color styling and color combination.\r\nThe mark below the tongue: \r\nRaise the shoe''s sole and check the label below the tongue: it will have a sticker with the words, &quot;the greatest player ever.&quot;&lt;/p&gt;\r\n&lt;h2&gt;The printed Jumpman logo:&lt;/h2&gt;\r\n&lt;p&gt;The 11s will have the jump man''s printed logo on the insole as well. The jump man''s proportions should be normal, and not in any way impaired. The legs, feet, and ball descriptions should all be simple, distinct and readily identifiable. The edges on the insole of the Jumpman should be sharp and crisp so that the logo does not appear blurred or smeared.\r\nCheck the laces '' small details: \r\nLook closely at the shoelaces, shoelace tabs, and tongue details. Search for a gap even between the shoelace tabs and the positions of the tongue marks.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/HdNCBpT.jpg&quot; alt=&quot;Air Jordan 11 &quot; /&gt;&lt;/p&gt;\r\n&lt;h2&gt;Position of the logo sign:&lt;/h2&gt;\r\n&lt;p&gt;Another indication of genuine Air Jordan 11 is the position of the logo badge. The logo at the top of the tongue in the Air Jordan should be clearly positioned in the third lace area, balancing seamlessly between the laces, and easy to see when looking down on the feet. The logo can be found in the second or fourth lace space in the replica shoes, and may not exactly fit between the laces. In replica shoes, the placement of the tongue logo may even have slight variations between the left and right shoes.\r\nThe shoelace tabs should be the same height: \r\nA closer look at the shoelace tabs will show that they are all the same dimension, form and distance apart. All should have the same degree of tension attached to them. One or more of the shoelace tabs in a replica pair of shoes may be looser than the others. We may be somewhat different in size but not all of them should be similar.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3uVYs5a.jpg&quot; alt=&quot;Air Jordan 11 &quot; /&gt;&lt;/p&gt;\r\n&lt;h2&gt;Is it a colorway that you never saw?&lt;/h2&gt;\r\n&lt;p&gt;Another clue that the Nike Air Jordan 11s aren''t authentic can be a unique combination of colors: Google the sneaker''s color&ndash;are images of it on reputable sites?\r\nThey might be a personalized sneaker-make sure the exact colorway and sneaker maker (if you know who made them) is Google. Jordan replicas tend to have scandalous colorways&ndash;this is by far the easiest gift.&lt;/p&gt;\r\n&lt;h2&gt;The patent leather around the toe:&lt;/h2&gt;\r\n&lt;p&gt;Look at the patent leather design around the foot: the patent leather shows higher or much lower on the top of the shoe on imitation shoes than it does on original shoes. In some cases, this patent leather contrast may appear to have been glued to the edge of the patent leather, and glue residue may be visible. There should be two even rows of stitching for the OG patent leather&ndash;these should be smooth and even.&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/KjS93UK.jpg&quot; alt=&quot;Air Jordan 11 &quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/kLbiYIW.jpg', 'jordan-retro-11-fake-vs-real', 'jordans,jordan1,fakevsreal, nike,air', '2020-02-03 00:30:51', '2020-02-03 00:30:51');
INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(15, 'How to tell if your Air Jordan 4s are fake?', '&lt;h1&gt;How to tell if your Air Jordan IVs are fake?&lt;/h1&gt;\n&lt;p&gt;When the Air Jordan IV came out, fakes were very easy to spot. The speckle was off, the mesh was not parallel, and on top of that the shoe heel didn&rsquo;t have any bump. But today fakes are getting better and better. As a result, it can be very hard to see if the Jordan Retro IV you own right now is a fake or the real deal.&lt;/p&gt;\n&lt;h3&gt;Heel tab&lt;/h3&gt;\n&lt;p&gt;The back heel tab tends to be very thick on fakes. The Jordan Retro IV has a very thing heel tab, so you can spot this very quickly. On top of that, it&rsquo;s seamlessly attached to the shoes, whereas fakes make it feel like it&rsquo;s just something extra that doesn&rsquo;t fit. In addition, the lace tabs are clear for the originals, whereas fakes have paint speckling.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/QcCwoBf.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Shoe tree&lt;/h3&gt;\n&lt;p&gt;When you see the real shoe trees for the Jordan Retro IV, you will see they have all the information horizontally and there&rsquo;s no info on the sides. Fakes tend to misplace the labels and that makes them easier to spot.\n&lt;img src=&quot;https://i.imgur.com/q1Vytky.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Insole branding&lt;/h3&gt;\n&lt;p&gt;Original Jordan Retro IV will always have the NIKE letters very close to one another. The logo has very good coloring, it&rsquo;s never faded. If it&rsquo;s faded, then you are obviously dealing with a fake. The same thing happens with the insole stickers. Fake stickers will not have full black coloring, and they also change the font too.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zFBx0Gg.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Outsoles&lt;/h3&gt;\n&lt;p&gt;In the case of the fake outsoles, you will notice that the manufacturing is very sloppy. You can find pieces of material hanging on the sides. Obviously that won&rsquo;t happen with the Jordan Retro IV as the original has pristine coloring and visuals.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zhGAYdd.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Tongue height&lt;/h3&gt;\n&lt;p&gt;When you look at the original Jordan Retro IV, you will notice that it has a rather long tongue. Fake pairs usually have a shorter tongue, way shorter than the original at any rate. This will give you a good idea of what you need to be looking out for. Speaking of the Jordan Retro IV tongue, the mesh of a fake is very smashes and loose. The original looks a lot better, and it shows a sense of value and quality.&lt;/p&gt;\n&lt;h3&gt;Midsole paint&lt;/h3&gt;\n&lt;p&gt;Normally the original will have a rather thick paint speckling on the midsole. However, the fakes tend to have a light paint speckling, and it gets particularly obvious if you put the units one near the other. This is the same for the speckles themselves. Even the box pull holes look of a high quality and they are larger on the original.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zhGAYdd.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Box tag&lt;/h3&gt;\n&lt;p&gt;Sometimes you can spot a fake from its box. Fakes tend to have a bolder font for the color way code. In addition, you can have color fading and some missing points like suggested retail pricing that&rsquo;s usually attached by Nike. Obviously fakes don&rsquo;t share that, so it&rsquo;s a good way to spot them.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/NuqiMqn.png&quot; alt=&quot;Air Jordan IV&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Conclusion&lt;/h3&gt;\n&lt;p&gt;Overall, it&rsquo;s not that hard to find differences between the original Jordan Retro IV and fake counterparts. In order to do that you need to understand more about how an original should look like and what features you can expect. It&rsquo;s important to know these differences, as it will make it easier for you to avoid wasting money on Jordan Retro IV fakes instead of the real deal.\n&nbsp;&lt;/p&gt;', 'https://i.imgur.com/PlNmHpF.jpg', 'how-to-tell-if-your-air-jordan-4-are-fake', 'jordan,retro,sneakers', '2020-02-13 02:46:38', '2020-02-13 02:46:38'),
(16, 'How to win sneakers on the SNKRS app?', '&lt;h1&gt;How to win sneakers on the SNKRS app?&lt;/h1&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/M8eTBQ9.jpg&quot; alt=&quot;SNKRS App&quot; title=&quot;Nike SNKRS App&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;The SNKRS app is a very popular one and a lot of people can check out the latest Nike sneakers on that platform if they want. That being said, you can also win sneakers on the app, which is very exciting. The challenge that comes in such a situation is actively figuring out how you can win and how you can achieve the results you expect. Yes, it&rsquo;s possible to win sneakers on the SNKRS app.&lt;/p&gt;\r\n&lt;h3&gt;Why is Nike offering limited sneakers?&lt;/h3&gt;\r\n&lt;p&gt;As always, it all comes down to marketing. They build up an even larger email database, and they also show customers the value of these products. Plus, it&rsquo;s a fun way to interact with the customer base, something that will help Nike quite a bit. It&rsquo;s important to understand all the cool features and benefits that SNKRS is bringing to the table. It&rsquo;s a great opportunity and the results can actually be very exciting and rewarding. Just take that into consideration for the best value.&lt;/p&gt;\r\n&lt;h3&gt;Winning sneakers from the SNKRS app&lt;/h3&gt;\r\n&lt;p&gt;This is interesting and also quite easy to do. Of course, it&rsquo;s still a raffle, so the chances of winning are very low. There are obviously lots of people trying to win the sneakers that Nike are offering. It&rsquo;s still exciting either way and you just need to give it a try for yourself.\r\nThe way you can win sneakers from Nike here is via downloading the Nike SNKRS app and creating your own Nike+ account. It&rsquo;s important to have notifications enabled, and you will be notified when it&rsquo;s a draw for a limited shoe. These can easily be resold for a lot of money, or you can keep them because you are a collector. &lt;/p&gt;\r\n&lt;p&gt;A thing to note here is that you will win a release. You won&rsquo;t be winning it free of charge, as the way this works is you have to add a payment method. If you win, you will be charged. There&rsquo;s no checkout process, and the great thing is that Nike is a very fast retailer, so it ships all their stuff really fast and without any issues. That alone makes this experience extraordinary and quite exciting at the same time.&lt;/p&gt;\r\n&lt;h3&gt;Should you enter the SNKRS raffles?&lt;/h3&gt;\r\n&lt;p&gt;Yes, if you really want the limited shoe, you can enter their raffles. Of course, you will see the price and you can enroll in it or not. That&rsquo;s all up to you, but the results can be amazing. You just have to give the SNKRS app a try, as it will be well worth checking out. At the end of the day, that&rsquo;s what really matters the most.&lt;/p&gt;\r\n&lt;h3&gt;Conclusion&lt;/h3&gt;\r\n&lt;p&gt;We believe that the SNKRS app does offer you a great way to win sneakers and it will make the process fast and convenient. If you are very passionate about sneakers, you will find the SNKRS app to be one of the coolest tools you can use to win sneakers. It&rsquo;s a great app to begin with, you stay up to date with the latest sneakers, and the overall quality is extraordinary. So you should totally check it out, maybe you can even get some limited edition Nike shoes out of it too!&lt;/p&gt;', 'https://i.imgur.com/M8eTBQ9.jpg', 'how-to-win-sneakers-on-snkrs-app', 'snkrs,app,nike', '2020-02-16 16:33:59', '2020-02-16 16:33:59'),
(17, 'How to make money reselling on Stockx?', '&lt;h1&gt;How to make money reselling on Stockx?&lt;/h1&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/MQNWThq.jpg&quot; alt=&quot;Stockx App&quot; title=&quot;Stockx App&quot; /&gt;\r\n''''\r\nStockx is one of the most popular online marketplaces where you are able to buy and sell authentic sneakers. With a bit of careful observation and focus, you can easily make a lot of money buying and then re-selling sneakers on this platform. There are people making thousands of dollars just by flipping expensive sneakers. Here are some of the things you can do to make money on Stockx!&lt;/p&gt;\r\n&lt;h3&gt;Find the most popular sneakers online&lt;/h3&gt;\r\n&lt;p&gt;The reason why you want to study tools like Google Trends is because you get to see what shoes are hot right now.  Google trends can point out upshots and sneaker term searches that are on the rise. These are the sneakers you want to buy and sell. There should be a high demand according to the trend and hopefully less supply. As a result, people will be willing to pay more than what you got them for, which is what makes reselling on Stockx such a great experience.&lt;/p&gt;\r\n&lt;h3&gt;Buy low and sell high&lt;/h3&gt;\r\n&lt;p&gt;In many ways, Stockx is very similar to trading. It requires you to study prices and buy stuff when the price is very low. Then you can go back and buy when the price is high. It helps a lot and it will give you the experience and results you need. It&rsquo;s totally worth it, and you will not have to worry about anything in a situation like this. &lt;/p&gt;\r\n&lt;h3&gt;What sneakers are the best resale purchase?&lt;/h3&gt;\r\n&lt;p&gt;That depends on the product. The Air Jordan 12, Nike Air Yeezy 2 or the Nike Air Mag Back To The Future are some amazing products. They are all in rather limited quantities, so you will find them at really high prices. Of course, these are the major hits, but you can make good money even with less expensive stuff, that&rsquo;s something to keep in mind. Companies like Under Armour also provide great kicks, so they can be a wonderful resale product too. You just have to check it out for yourself and the results will be well worth it.&lt;/p&gt;\r\n&lt;h3&gt;How can you make a good profit?&lt;/h3&gt;\r\n&lt;p&gt;The best thing that you can do is to know what releases are big and then you buy them on an app like Frenzy. This way you avoid staying in front of a physical store for hours and worry if you would even get a product like that. When you start making money on Stockx, the most important thing is to start off with the lower priced sneakers and then go up to the highly priced ones as you go along. You need to build up your profile and show people they can trust you.&lt;/p&gt;\r\n&lt;h3&gt;Start making $$$ on StockX&lt;/h3&gt;\r\n&lt;p&gt;Making money on a platform like Stockx is very important and it will bring in front a great experience every time. You just need to give it a try for yourself and see how it works. It will be well worth it if you do it right. Don&rsquo;t expect to have lots of sales right away, but if you start with low priced sneakers and generate lots of sales that way, you will build up trust and that will eventually bring in the bigger sales.&lt;/p&gt;', 'https://i.imgur.com/MQNWThq.jpg', 'how-to-make-money-reselling-on-stockx', 'stockx,resellingsneakers', '2020-02-16 16:34:14', '2020-02-16 16:34:14'),
(19, 'How tell the difference between real and fake pair of Air Jordan VI?', '&lt;h1&gt;How to tell the difference between real and fake Air Jordan VI&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/kLxCyYV.jpg&quot; alt=&quot;Air Jordan VI&quot; title=&quot;Air Jordan VI&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;The Air Jordan VI is an essential pair of sneakers in any Jordan collectors closet. Unfortunately there will always be a market flooded with fakes. &lt;/p&gt;\n&lt;p&gt;Which is why you need to know the differences between a real and fake Air Jordan VI sneakers. Here are some things that you need to need to consider and check when verifying a pair of Air Jordan VIs&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/j5JQekx.jpg&quot; alt=&quot;Air Jordan VI&quot; title=&quot;Air Jordan VI&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Heel tab&lt;/h3&gt;\n&lt;p&gt;You will notice that most of the time the replica&rsquo;s heel tab will be exaggerated. The red on those fakes will be narrow, while the real ones tend to have a wider heel tab. It&rsquo;s a simple thing you need to notice, but it&rsquo;s easy to spot after a while.&lt;/p&gt;\n&lt;h3&gt;Holes&lt;/h3&gt;\n&lt;p&gt;Most of the time fakes will have holes that lack a white or reflective component. They feel cheaply made, and you will also notice that the spacing between the edge of the pod and the upper hole is smaller on fakes. Usually it&rsquo;s wider on the real pair.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/WPXnK7x.jpg&quot; alt=&quot;Air Jordan VI&quot; title=&quot;Air Jordan VI&quot; /&gt;&lt;/p&gt;\n&lt;h4&gt;Air bubble&lt;/h4&gt;\n&lt;p&gt;When it comes to the air bubble, real ones tend to have a wider bubble. They also have the screen around an inch from the edge of the midsole. Fakes on the other hand will have the screen adjacent to the edge. Fakes will also tend to have an orange highlight, whereas the original ones will focus more on the red coloring. It&rsquo;s a very reliable way to tell if a sneaker is fake or not.&lt;/p&gt;\n&lt;h3&gt;Heel liner&lt;/h3&gt;\n&lt;p&gt;Fakes will have a heel liner that seems more like a chenille patch. Also, the spacing between the Nike text and the tab is small on the fake pair. Real Air Jordan VIs will have more spacing, and that&rsquo;s how you know they are real.&lt;/p&gt;\n&lt;h3&gt;The box&lt;/h3&gt;\n&lt;p&gt;Another thing you can do is to check the box. Fakes will have a snow white coloring, whereas real pairs will have an off-white color. The box should have a gap between the box lid and the label edge on fakes. Speaking of numbers, the production date on fakes is much earlier and the inside label also at times can be too white &lt;/p&gt;\n&lt;h3&gt;Nike logo&lt;/h3&gt;\n&lt;p&gt;You need to check and you will see that the Nike logo is very bright, glossy and fuller on a fake pair. Real pairs will not be extremely glossy.&lt;/p&gt;\n&lt;h3&gt;Conclusion&lt;/h3&gt;\n&lt;p&gt;While it&rsquo;s not easy to spot a fake from a real pair, it&rsquo;s important to use this guide to see whether the Air Jordan VI pair you want to buy is a real one. There are some nuanced changes from fakes to the real that will make it easier for you to spot a fake. Use our tips and we guarantee it will be easier to spot any fake Air Jordan VI pair!&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Xfz3xX7.jpg&quot; alt=&quot;Air Jordan VI&quot; title=&quot;Air Jordan VI&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/kLxCyYV.jpg', 'how-to-tell-real-vs-fake-air-jordan-vi', 'jordan,vi,jordans', '2020-02-16 19:19:56', '2020-02-16 19:19:56'),
(20, 'How tell the difference between real and fake pair of Air Jordan V?', '&lt;h1&gt;How tell the difference between real and fake pair of Air Jordan V?&lt;/h1&gt;\n&lt;p&gt;The Air Jordan V is one of the most beautiful Air Jordans out there. While not the most sought after, it does stand out with its amazing features and incredible quality. But you do have to wonder, how can you spot the fake Air Jordan V and what makes them different from the real ones? Let&rsquo;s find out.&lt;/p&gt;\n&lt;h3&gt;Factory codes&lt;/h3&gt;\n&lt;p&gt;Ideally you want to see that the shoes have their FT1 or LN3 factory codes on the tag, only the real ones have such a thing. The box also needs to have that same code and manufacturing country. If there&rsquo;s no match between the codes and origin country, then these are fakes.&lt;/p&gt;\n&lt;h3&gt;Tongue height&lt;/h3&gt;\n&lt;p&gt;The tongue height is very close to the top of the shoe on the real deal. Fake Air Jordan Vs will usually have the tongue height a lot lower. If it extends up to the upper side of the shoe, then that&rsquo;s something you need to keep in mind. It&rsquo;s definitely going to be worth it, that&rsquo;s for sure.&lt;/p&gt;\n&lt;h3&gt;Numbers&lt;/h3&gt;\n&lt;p&gt;Air Jordan Vs will have the 23 on the side. Real ones will have a clear gap between the numbers. Most of the time those fakes will have the numbers connected. This is actually one of the best ways to spot if you are dealing with fakes or not. So try to take that into consideration while deciding weather or not to buy.&lt;/p&gt;\n&lt;h3&gt;Jumpman&lt;/h3&gt;\n&lt;p&gt;The real Jumpman will have hands that are very flat, fingers are uniform. In the case of a fake you will notice a very low quality. The real one has a very high quality. If it feels like a sloppy job here, it shows that you&rsquo;re dealing with a fake, so you need to figure out how to eliminate the issue as fast as possible. Also, the real Jumpman is rather close to the sole. Fakes tend to have it a lot higher, maybe 2-3 times higher, so that makes it easier to spot.&lt;/p&gt;\n&lt;h3&gt;Side cushion&lt;/h3&gt;\n&lt;p&gt;An authentic Air Jordan V will go back to the original shape when you press on the side cushion. If the cushion doesn&rsquo;t return instantly to its original shape, then you are most likely dealing with fakes, so that&rsquo;s something that you need to avoid as much as possible. Also, a fake will have a very wide stitching on the side, something that regular ones will not have.&lt;/p&gt;\n&lt;h3&gt;Final thoughts&lt;/h3&gt;\n&lt;p&gt;There are some other things to look out for. The Jumpman at the bottom of the shoe should be clear, if it&rsquo;s not that shows you have a fake. Also, most fakes tend to have the legs not spread as wide. On top of that, the real lace locks will have the Jumpman, fakes will just show the Nike name. It&rsquo;s important to study all these little differences, as that&rsquo;s what will make the process so convenient and interesting. Just check them out and study everything to ensure that you&rsquo;re not dealing with fakes.&lt;/p&gt;', 'https://i.imgur.com/mCmYLc8.jpg', 'how-to-tell-real-vs-fake-air-jordan-v', 'jordan,vi,jordans', '2020-02-17 00:19:23', '2020-02-17 00:19:23'),
(21, 'How to tell if your Air Force 1 Cactus Jack Sneakers are real or fake?', '&lt;h1&gt;How to tell if your Air Force 1 Cactus Jack Sneakers are real or fake?&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/5nYVUTX.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Air Force 1 &ldquo;Cactus Jack&rdquo; is one of the most coveted sneakers today. Unfortunately, this also attracts many counterfeits. Even before the release, there were many different fake sneakers in different qualities. For this reason, here we are going to discuss on how to spot fake Air Force 1 Cactus Jack Sneakers.&lt;/p&gt;\n&lt;h2&gt;The letters on the label should be spaced regularly:&lt;/h2&gt;\n&lt;p&gt;There is an incorrect color code on the labels of some fake sneakers. There are also differences in the font used and the white part of the barcode is larger. &lt;/p&gt;\n&lt;p&gt;There may also be deviations in the text. Some labels do not say &ldquo;Air Force 1 Low / Cactus Jack&rdquo;, but &ldquo;Air Force 1 Low Travis Scott&rdquo;. Also, make sure, a standard sole is used on the AF 1 TS. Here it happens that the structure of the sole is more defined in some pairs than in others.&lt;/p&gt;\n&lt;h2&gt;Logo on the box:&lt;/h2&gt;\n&lt;p&gt;The logo on the box should have a strong blue and stand out from the rest of the box. Fake boxes can often be recognized by the fact that a different cardboard material is used and the Nike logo is not highlighted.&lt;/p&gt;\n&lt;p&gt;Nevertheless, original boxes are already used in many fake sneakers, which is why the box can only detect a counterfeit to a limited extent.&lt;/p&gt;\n&lt;p&gt;The Nike logo on the side of the box should also be finished with a relief varnish and stand out from the box. Many boxes of fake sneakers lack this detail.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/CmBXxIK.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/QmXbgNV.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the QR Code&lt;/h2&gt;\n&lt;p&gt;As with all newer original shoes from Nike, the AF1 also comes with a QR code on the inner label. The production period on the tag should be between the second and fourth quarters of 2019.\nMany fake sneakers use a different font as well as the font thickness and arrangement of the letters, which ultimately leads to a changed picture.&lt;/p&gt;\n&lt;h2&gt;Additional laces:&lt;/h2&gt;\n&lt;p&gt;In original Air Force 1 Cactus Jack Sneakers, the shoes come with two additional laces. A dark blue and cream pair. And also, the plastic bags should be the right size so that there is little free space in the bags. In the fake sneakers, these things are missing.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/gyqoKkc.jpgg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Visible logo:&lt;/h2&gt;\n&lt;p&gt;In the original pair of Air Force 1 Cactus Jack Sneakers, the &ldquo;Nike Air&rdquo; logo should be visible. While in the fake one, the same thing is not clear and visible.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/sP94hut.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Space on the white midsole:&lt;/h2&gt;\n&lt;p&gt;On the real sneakers, the space on the white midsole for the Air logo is 3 mm while on the fake pairs, you will notice this space 2 mm. It seems a small point to consider but it is very important. It can easily break the company&rsquo;s patent.&lt;/p&gt;\n&lt;h2&gt;Ridges on the gum:&lt;/h2&gt;\n&lt;p&gt;This is the last point but not the least, the ridge on the gum rubber sole leads to the pattern stars on the toe and heels are spaced improperly that creates a different feeling in tractions.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/rt63M0N.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/DX1gkij.jpg&quot; alt=&quot;&quot; title=&quot;Air Force 1 Cactus Jack&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/sP94hut.jpg', 'how-to-tell-if-your-air-force-1-cactus-jack-are-real-or-fake', 'cactus,jack,air,force-1,travis,scott', '2020-03-29 16:19:30', '2020-03-29 16:19:30'),
(22, 'How To Tell If Your Gucci Ace Sneakers are Fake', '&lt;h1&gt;Fake Vs Real Gucci Ace sneakers:&lt;/h1&gt;\n&lt;p&gt;Gucci Ace sneakers will remind you of the bright seventies. These sneakers not only have a slight metallic touch on the back, but they are also customizable with embroidered and interchangeable patches to make multiple combinations that you can put on the instep of tennis and they will surely make you stand out.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Hl2OIMk.jpg&quot; alt=&quot;&quot; title=&quot;Gucci Ace Sneakers&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;We know that many times we want to achieve the aspiration of buying luxury brands such as the original Gucci sneakers, which undoubtedly this brand is characterized by the authenticity of its products. So you must know these characteristics to avoid buying a fake one.\nSome of the things you should verify when buying Gucci Ace:&lt;/p&gt;\n&lt;h2&gt;Inspect the Footbed&lt;/h2&gt;\n&lt;p&gt;The footbed of the Gucci Ace is the most reliable spot to consider when checking fake vs real one. You need to go inside to check the real by removing the insole.\nIn reality, the color of the footbed must be brown with the classic Gucci connected print. While in the fake one, you will see the logo print black instead of brown.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/LI4ijGS.jpg&quot; alt=&quot;&quot; title=&quot;Gucci Ace Sneakers&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the &ldquo;Gucci&rdquo; print:&lt;/h2&gt;\n&lt;p&gt;On the fake sneakers, the letters of &ldquo;Gucci&rdquo; appear to be printed like a sticker and it is glued on the shoes. While in real shoes, those letters are stitched in the sneakers itself. Or if there is a design, the design will be stiched on, not glued on&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/BPerv55.jpg&quot; alt=&quot;&quot; title=&quot;Gucci Ace Sneakers&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Bag packing&lt;/h2&gt;\n&lt;p&gt;You must check the bag and/or the shoe box are packed boxes. All products that belong to this brand are always accompanied by a bag, boxes and even some gift bags for your product, this bag is a dark brown color. Also, they have the word Gucci in silver or gold raised metal letters running parallel to the short side of the case. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Y2Z8dwN.jpg&quot; alt=&quot;&quot; title=&quot;Gucci Ace Sneakers&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Ace insole&lt;/h2&gt;\n&lt;p&gt;On the fake shoes, there would be a text missing on the rear side of the insole while in real Gucci Ace shoes, you will see a highlighted text which always is present.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/KWxPNRg.jpg&quot; alt=&quot;&quot; title=&quot;Gucci Ace Sneakers Insole&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Examine the overall quality: *&lt;/h2&gt;\n&lt;p&gt;First of all, you should check the seam of the sneakers since most are inspired by a tribute to the typical Gucci shoes, if the seam is not completely straight, smooth and there are no signs of glue, then they are not real shoes. &lt;/p&gt;\n&lt;p&gt;The inner surface of all Gucci sneakers is white, in addition to that color and width of the stripes on the sides of the shoes is also a tribute to typical knock-off Gucci sneakers, Gucci tennis roots have two green stripes Forests alternate, with a red Ferrari stripe between them, on the side of each shoe. Each strip is about 3/4-inch wide.&lt;/p&gt;\n&lt;h2&gt;Serial number:&lt;/h2&gt;\n&lt;p&gt;This is also another important element since this cannot be fake so you must check the serial number for Gucci Ace sneakers. The authentic shoes of this brand will have an 8-digit serial number printed on the leather cover on the inside of the shoe, near the shoe size mark. \nNow you know very well, how to recognize the original Gucci Ace sneakers of this prestigious brand. &lt;/p&gt;', 'https://i.imgur.com/Hl2OIMk.jpg', 'how-to-tell-fake-gucci-ace-sneakers-real-vs-fake', 'gucci,ace,sneakers', '2020-03-29 16:45:16', '2020-03-29 16:45:16'),
(23, 'Are your Nike LD Waffle Sacai Real or Fake?', '&lt;h1&gt;Are your Nike LD Waffle Sacai Real or Fake?&lt;/h1&gt;\n&lt;p&gt;If you&rsquo;re interested in buying the new Nike LD Waffle Sacai., you would be wise to keep a few things in mind. Theres been a release of a few high quality Waffle Sacai fakes out there, we&rsquo;re trying hard to help you avoid them. Here is our list of the few things to look out for to avoid buying a fake pair.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/you9haN.jpg&quot; alt=&quot;&quot; title=&quot;Nike LD Waffle Sacai&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the &ldquo;US Patent&rdquo; in the sole&lt;/h2&gt;\n&lt;p&gt;The sole inscription is one of the major keys to spot if your sneakers are fake or real. The fake sneakers, you will notice thick texts while on the real sneakers&rsquo; sole, it&rsquo;s much thinner. Fake Nike LD Waffle, the &ldquo;US Patent&rdquo;  text is placed too close to the left squares of the sole. On the real sneakers, it will have a little bit more spacing between those square buttons. Also, the replicas often are made of poor-quality plastic.&lt;/p&gt;\n&lt;h2&gt;The color of the sneakers:&lt;/h2&gt;\n&lt;p&gt;Do not miss to check overall quality and the color of the Nike LD Waffle Sacai. Fake sneakers will often be s a slightly darker shade of red when compared with the real pairs. This is one of the easiest ways to spot a fake pair Nike LD Waffle Sacai.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3gC0eF5.jpg&quot; alt=&quot;&quot; title=&quot;Nike LD Waffle Sacai&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The font on the sneakers:&lt;/h2&gt;\n&lt;p&gt;Take a close look at the font printed on the sneakers. The real shoes have a light grey shade with some gloss finishing whereas the fake pairs have a darker shade with the matte finishing.&lt;/p&gt;\n&lt;h2&gt;Check the quality of the Suede:&lt;/h2&gt;\n&lt;p&gt;On the rear side, the real pair has a better suede quality if you will compare it with the fake ones. Fake pair manufacturers are now using the synthetic leather panel which is a give away if you look carefully. Also, the replicas poor-quality plastic is often used.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/UuHLEzK.jpg&quot; alt=&quot;&quot; title=&quot;Nike LD Waffle Sacai&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check &ldquo;Nike&rdquo; tags:&lt;/h2&gt;\n&lt;p&gt;On the fake pair, you will see 2 main flaws. First, the letter &ldquo;R&rdquo; that appears too small and also the whole word &ldquo;SPORTSWEAR&rdquo; looks too thin. This is one of the major points to notice.&lt;/p&gt;\n&lt;p&gt;Apart from these steps, there are many factors to considers spotting fake Nike LD Waffle Sacai sneakers&lt;/p&gt;\n&lt;h2&gt;Be cautious of Low Price:&lt;/h2&gt;\n&lt;p&gt;As all Nike LD Waffle Sacai are now sold out. You can expect to pay over $400 for a brand new pair depending on your size. If a brand new pair is cheaper than this, it&rsquo;s a sign that the sneakers might be fake or that a large restock is about to happen.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ZAWzbhD.jpg&quot; alt=&quot;&quot; title=&quot;Nike LD Waffle Sacai&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The reputation of the seller:&lt;/h2&gt;\n&lt;p&gt;If you are going to buy online, don&rsquo;t skip checking the seller rating and other buyer&rsquo;s feedback. If there are negative comments that are related to not shipping or fake pairs. Stay Away!&lt;/p&gt;\n&lt;p&gt;Some sellers don&rsquo;t even know if they sell real Nike or not, so feedback is an important indicator.&lt;/p&gt;', 'https://i.imgur.com/ZAWzbhD.jpg', 'nike-ld-waffle-sacai-real-vs-fake', 'sacai,nike,ld,waffle', '2020-04-20 19:49:38', '2020-04-20 19:49:38'),
(24, 'Off-White Air Jordan 1 NRG Real Vs Fake:', '&lt;h1&gt;Off-White Air Jordan 1 NRG Real Vs Fake:&lt;/h1&gt;\n&lt;p&gt;Off-White Air Jordan 1 NRG White is one of the most popular releases from the Nike X Off-White collaboration. Taking a look at Stockx, the prices are well over $3,500. The value of these sneakers may continue to rise so we wrote up this guide to help you if you plan on buying a pair.&lt;/p&gt;\n&lt;p&gt;Below are the things to look out for to make sure you&rsquo;re buying an authentic pair.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/cMBOfy4.jpg&quot; alt=&quot;&quot; title=&quot;Off-White Air Jordan 1 NRG&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The pattern on the rear side&lt;/h2&gt;\n&lt;p&gt;On the real Jordan 1 pattern on the backside is denser than the elements on the fake sneakers. On the fake Air Jordan 1, you will notice the pattern is always the same.&lt;/p&gt;\n&lt;h2&gt;Check the tightness of the blue patch&lt;/h2&gt;\n&lt;p&gt;Now we will check how tight the blue stitches on the rear side of the Nike Swoosh logo. On the fake one, those blue stitches at times can be too loose. On the real Jordan 1, it will always have their blue stitches as tight with no extra stitching hanging off of the shoe.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/CBqnY1s.jpg&quot; alt=&quot;&quot; title=&quot;Off-White Air Jordan 1 NRG&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Be careful if the price is extremely low&lt;/h2&gt;\n&lt;p&gt;There is no denying that each of us wants to buy new Off-White Air Jordan 1 NRG White shoes at the lowest possible prices. The production of fake, the quality of which is poor, is also significantly cheaper than the production of the original shoes. &lt;/p&gt;\n&lt;p&gt;However, original shoes always have their price. A printed price usually means that the products are counterfeit. Such an investment is not worth it. Original sneakers are much more durable than they&rsquo;re fake.&lt;/p&gt;\n&lt;p&gt;For a brand new pair, you should except at the time of this article is published to pay over $1,000. A used pair should on a average be about $2,550&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/71itz4d.jpg&quot; alt=&quot;&quot; title=&quot;Off-White Air Jordan 1 NRG&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Letter errors in the name&lt;/h2&gt;\n&lt;p&gt;You do not have to be Sherlock Holmes to notice all the differences between a fake and an original. These are mostly such mistakes in letters as &ldquo;Nike&rdquo; instead of logo Swoosh from Nike. &lt;/p&gt;\n&lt;p&gt;Sometimes not only names and logos, but also design details are imitated. In this case, it is more difficult to identify fake sneakers. In this case, we should carefully check the quality of the seams, soles or labels. Important: you also have to check whether you are dealing with a photo of the actual product and not an advertising photo. The photo should be compared with photos on the manufacturer&rsquo;s website.&lt;/p&gt;\n&lt;h2&gt;Verify the &ldquo;Air&rdquo; text&lt;/h2&gt;\n&lt;p&gt;Text &ldquo;AIR&rdquo; on the real Off-White Air Jordan 1 NRG must be placed perfectly on the midsole of the sneakers. And the many times, the fake sneaker&rsquo;s text &ldquo;AIR&rdquo; print looking a lot upper or lower than the real one.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/DcdRB64.png&quot; alt=&quot;&quot; title=&quot;Off-White Air Jordan 1 NRG&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Be extremely cautious&lt;/h2&gt;\n&lt;p&gt;When buying new sneakers, you have to be patient. It would be better to double-check an interesting offer than to regret it later. It is worth asking a seller for great photos of the product offered. &lt;/p&gt;\n&lt;p&gt;They are also photos showing the inside of the shoes and a label with the serial number. The range of the online shop should, of course, be compared with the range of the manufacturer. Above all, you should be careful if the prices are extremely low.&lt;/p&gt;\n&lt;h1&gt;soleinsider&lt;/h1&gt;', 'https://i.imgur.com/CMrR0yJ.jpg', 'off-white-air-jordan-1-nrg-real-vs-fake', 'off-white,jordan', '2020-05-30 16:16:34', '2020-05-30 16:16:34'),
(25, 'How can you start reselling sneakers', '&lt;h1&gt;How can you start reselling sneakers&lt;/h1&gt;\n&lt;p&gt;It''s no longer a secret that sneaker reselling can be an extremely lucrative pastime. We''ve put together a guide that can allow you to hop into the reselling game and start making some money.&lt;/p&gt;\n&lt;h4&gt;Research and keep track of the latest sneaker releases&lt;/h4&gt;\n&lt;p&gt;Performing comprehensive research is necessary for making your sneaker reselling business successful. Before buying the shoes, make sure it is in the trend. Check ebay, stockx and other marketplaces a few days up to release. If the prices are way above retail, there''s a high chance that the sneaker will be profitable to resell on release day. Most general release sneakers tend to drop in price a bit on release day and after. They slowly climb back up if they are sold out without a plan to restock.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/3B8eM9t.png&quot; alt=&quot;Research pricing&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Pricing strategy&lt;/h3&gt;\n&lt;p&gt;Setting the right price is the key to your success. As a beginner, it will be difficult to fix the right price that would give profit to you and as well attracts the buyers. If you''re selling on ebay, check the sold listing and other current listings to see what other users are selling for.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ZCr2SQP.png&quot; alt=&quot;Pricing Strategy&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Select the best platform&lt;/h3&gt;\n&lt;p&gt;Where you sell your product is always vital in all businesses. There are multiple online platforms to become a seller and earn money. The famous sites like eBay, Stockx, Facebook, and Instagram market, and many such platforms allow you to sell sneakers.&lt;/p&gt;\n&lt;p&gt;First, it is recommended to open your account in all such platforms. Because it will help to understand which one suits you and you will get more customers with less fee. Once you get to know the right platform, you can start concentrating on that particular site, which may have the most profit opportunity at the moment.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/TqQb6Kj.png&quot; alt=&quot;Sneaker platform selection&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Shipping&lt;/h3&gt;\n&lt;p&gt;Because there''s a lot of options to choose from when it comes to shipping. Choosing the cheapest yet fastest option will help you increase your profits. In general if you''re near a USPS, that should be your first choice for single shoe orders. They tend to be cheaper when compared to competitors. If you''re shipping multiple items or internationally UPS or Fedex would be the better option.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Txa0sWO.png&quot; alt=&quot;Sneaker platform selection&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Stock your sneaker inventory and have them ready to be shipped&lt;/h3&gt;\n&lt;p&gt;Keeping an adequate level of stocks is very necessary to fulfil the demand of the customers. Establishing a streamlined process for packing and sending for shipping is vital. The more time you take to ship the products, the more it will affect your ratings. Pack and ship as soon as possible to establish an excellent reputation for your business.&lt;/p&gt;', 'https://i.imgur.com/TqQb6Kj.png', 'how-can-you-resell-sneakers', '', '2020-06-14 01:34:09', '2020-06-14 01:34:09'),
(26, 'How To Tell If Your Nike MAGs are real', '&lt;h1&gt;How to Spot Real vs Fake Nike MAG sneakers&lt;/h1&gt;\n&lt;p&gt;The Nike Mag is a great sneaker that has been the most sought out within the past few years.\nPrices for these sneakers have reached over $15,000, so it''s incredibly important that you make sure that you''re buying the real thing. Identifying the real Nike Mag from the fake can be a herculean task, therefore in this article, you will have a better understanding of how to identify the real Nike Mag from the fake. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/OUq9DU6.png&quot; alt=&quot;Nike Mag&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/8mQInb5.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the Nike Swoosh logo&lt;/h2&gt;\n&lt;p&gt;The Nike Swoosh logo is a great way to check for the authenticity of these sneakers. Check for the shape of the logo, if it is too curvy it is a fake as the real one won''t be very curvy.\nThe real is made with authentic material while the fake has a bulky and has a thicker cut. Below is a picture of an authentic logo. Check how streamlined and thin the logo appears. Also check for the green accent above the swoosh.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/wueJxc5.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;You can identify a real from fake Nike MAG through the rear heel text&lt;/h2&gt;\n&lt;p&gt;Note that the bottom side of the letter &ldquo;N&rdquo; on the original is expected to be round, bumpy, and curvy in shape. But reverse is the case on the fake, it is less curvy, not bumpy and not round enough, so make sure you note that. Let''s also take a look at the letter &quot;M&quot;. On the fake sneakers, you will discover that the letter &ldquo;M&rdquo; and &quot;G&quot; are very thick, and they appear to be too showy on the shoe, but the real Nike Air Mags will have their &ldquo;M&rdquo; to be a lot thinner, so it doesn''t look too flashy on the sneakers, it is just moderate and perfect.&lt;/p&gt;\n&lt;p&gt;Real\n&lt;img src=&quot;https://i.imgur.com/h3eUsgM.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Fake\n&lt;img src=&quot;https://i.imgur.com/Z3e6qhg.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Take a very close look at the size tag of the Air mags&lt;/h2&gt;\n&lt;p&gt;Another great way to identify a fake is taking a look inside the shoe at the size tag. Take note of the numbers and how they are written, if there is any incoherence and improper arrangements of fonts and they don''t align? Then it''s a fake. Finally, check for the TEXT of the place of production, if it''s moderately written or too thin, it''s REAL but when it''s not thin, it''s a fake. Below is a picture of an authentic tag to compare yours to.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/MsViZP0.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the lighting on the back to Air Mag&lt;/h2&gt;\n&lt;p&gt;The real Nike Air Mag has a very attractive sneaker because it features a lighting system near the heel. This is one of the best ways to detect an authentic vs fake pair because the fakes have not figured out how to clone the lighting 1:1 yet. If you can have both products placed side by side, you will realize that the lightning on the original shines brighter and more radiant than the fakes. \nLastly, note that if the stripe is shorter and maybe half-length on the shoe, that''s an indication it''s a fake. Authentic below is on the left, fake is on the right\n&lt;img src=&quot;https://i.imgur.com/CyK98Cb.png&quot; alt=&quot;Nike Mag&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;With the above tips, I hope you now find it easier to identify the real Nike MAG from the fake and won''t fall victim of fake products. So, I implore you to carefully check the sneakers before picking one at the store or from a reseller.&lt;/p&gt;', 'https://i.imgur.com/ULfuLWQ.jpg', 'real-vs-fake-nike-mag-sneakers', 'nike,mag,sneakers', '2020-06-28 14:22:21', '2020-06-28 14:22:21'),
(27, 'Iconic Allen Iverson photos', '&lt;h1&gt;Iverson VS Jordan&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://imgur.com/ColiO03.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;\n&lt;img src=&quot;https://imgur.com/uNhopli.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Iverson Vs Kobe&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ZyYHtnh.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;\n&lt;img src=&quot;https://imgur.com/ySQ7gKz.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;\n&lt;img src=&quot;https://imgur.com/8tGL9iP.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;\n&lt;img src=&quot;https://imgur.com/oGWM8CV.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Iverson Vs Lebron&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://imgur.com/yxwNqsN.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Iverson Vs Tmac&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://imgur.com/v1Zl2Dw.jpg&quot; alt=&quot;Iconic Iverson Photos&quot; /&gt;&lt;/p&gt;', 'https://imgur.com/uNhopli.jpg', 'iconic-allen-iverson-photos', '', '2020-09-15 00:12:00', '2020-09-15 00:12:00'),
(28, 'Adidas Y-3 by Yohji Yamamoto: Designer Sneakers', '&lt;p&gt;The Adidas Y-3 brand takes designer sneakers into very flashy territory. Adidas is no stranger to collaborations, but this match up soars to new heights of design. The &quot;Y&quot; stands famed Japanese fashion designer Yohji Yamamoto. Acclaimed for his avant-garde design and dramatic silhouettes, he lends his wild creativity to the Adidas Y-3 sneakers and sportswear brand. The &quot;3&quot; represents the famous 3 stripes of the Adidas logo, stripes which are also seen on the sides of their sneakers.&lt;/p&gt;\n&lt;p&gt;Y-3 was born in 2004. It gained a following unmatched by other Adidas collaborations, resulting in the launch of its own standalone stores beyond the normal Adidas shops. Possessing their own boutiques is a fitting move, since Y-3 sneakers are clearly in an echelon of their own. The first Y-3 store launched in Tokyo, followed by shops in Paris, Beijing, Miami, Manchester, then New York''s Meatpacking District and Soho neighborhood. Today 37 Y-3 shops stand in cities across the world from Singapore to Dubai.&lt;/p&gt;\n&lt;p&gt;Yohji Yamamoto''s signature comes across in both the clothing line and sneakers, but it is the designer sneakers that are truly the star of the show. Yamamoto plays with upscale and often unexpected materials - holographs, patent leather, suede, grained leather, Norwegian wool, oiled leather. Much of the work is sleek and shiny, but Yamamoto plays with textures on the sneakers, working in crocodile and snake skin effects, adding silvery reflective holographs, piping details, etc. Black and white dominate the collections, but here and there Yamamoto will shock with color - a bright yellow boxing sneaker, a futuristic red high top shoe, a running shoe with a graphic multi-color print.&lt;/p&gt;\n&lt;p&gt;The Y-3 line encompasses a number of sneaker models. The Y-3 Warrior High takes its inspiration from military boots but elevates the basic form to a very edgy style. The Y-3 Honja High is one of the most popular recurring sneakers in the brand. It can typically be recognized by a heel silhouette that maintains a sharp straight line just slightly angled back in towards the body, the famous 3-stripes along the side, and a slight convex mini &quot;hill&quot; over the top of the foot. The Y-3 Hayworth High features a heel more contoured to the curves of the ankle. The Y-3 Kazuhiri expresses a minimalist look, quintessentially Yohji Yamamoto avant-garde. Other Adidas Y-3 sneakers include the Moto, Sprint, Field, Boxing, Wrestling, Sala, Pacer, Yohji Star, and Yohji Smith. Each have their own individuality but share the modern vibe of the Adidas - Yohji Yamamoto Y-3 collaboration.&lt;/p&gt;\n&lt;p&gt;By Kai Youngblood &lt;/p&gt;', 'https://i.imgur.com/vwjJmci.png', 'adidas-y3-history', 'sneakers', '2020-07-28 23:51:32', '2020-07-28 23:51:32'),
(29, 'Air Jordan 1: A Shoe Story', '&lt;p&gt;Once upon a time, a shoe was just shoe. Sure, athletes sought out high performance sports shoes, ladies lavished their attention on finding the perfect heels, and kids might have had brand they were partial to - but the humble sneaker was nothing special. And then out of the blue, the Air Jordan 1 was born.&lt;/p&gt;\n&lt;p&gt;In 1984, Michael Jordan entered the NBA as celebrated college player and Olympic gold medalist, grabbing attention in his new professional career with the Chicago Bulls. One of his first eye-catching moves was not his on-court skills (though those were incredibly impressive) but his choice in footwear. In a pre-season game, he debuted a basketball shoe unlike any that had ever graced an NBA court. Designed by Peter Moore, the Air Jordan 1 was a black leather sneaker decked out with a red Nike swoosh, and matching red laces. The NBA was not having it.&lt;/p&gt;\n&lt;p&gt;NBA Commissioner David Stern banned the kicks for their non-regulation colors. While black and red honored the Chicago Bulls, the basketball association insisted that the departure from the traditional white shoes was sacrilege. &quot;Gentlemen,&quot; the NBA wrote to Nike in a now public letter, &quot;In accordance with our conversations, this will confirm and verify that the National Basketball Association''s rules and procedures prohibited the wearing of certain red and black NIKE basketball shoes by Chicago Bulls player Michael Jordan on or around October 18, 1984.&quot;&lt;/p&gt;\n&lt;p&gt;The fine: $5000 each time Mr. Jordan stepped on the court in his blasphemous shoes. Fans however loved the Jordan sneaker. In 1985, Nike jiggled the color way, introducing a white background with prominent accents of red and black. The Air Jordan 1 was a runaway success. (At that time, of course, it was still the Nike Air Jordan - no number needed. The dozens of versions only came later.)&lt;/p&gt;\n&lt;p&gt;Since its launch almost three decades ago, the Air Jordan 1 has remained one of the sneaker world''s most celebrated designs. New colors continue to be launched. Fresh Jordan designs are constantly created, but the original has never lost its shine. In fact, old color ways are frequently re-issued as Air Jordan 1 Retro sneakers.&lt;/p&gt;\n&lt;p&gt;While every color imaginable has graced its classic silhouette, the red and black of the Chicago Bulls continue to play a prominent role. Tucked in between issues of sky blue or golden yellow, variations on the Bulls color scheme gain accolades as perennial favorites. No matter which color piques your sneaker urges, the story of the Air Jordan 1 is one of the greatest in sneaker history and will continue to tell its tale for years to come.&lt;/p&gt;\n&lt;p&gt;By Kai Youngblood &lt;/p&gt;', 'https://i.imgur.com/td2iKvW.png', 'jordan-1-shoe-story', 'sneakers,jordan', '2020-09-15 00:14:02', '2020-09-15 00:14:02');
INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(30, 'Nike Dunks SB - For a Complete Skate Boarding Experience', '&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/VTqMel3.jpg&quot; alt=&quot;Nike Dunks&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Nike dunks SB branded shoes are considered to be stylish, comfortable and at the same time extremely sporty. Built out of fine leather, these shoes offer superb skateable support when used for sports such as basketball and skate boarding. Suitable for sudden action, these brands are doubly stitched and high quality. Nike dunks SBs are highly fashionable and regarded as style statements.&lt;/p&gt;\n&lt;p&gt;Nike dunk SB is used all over the world by internationally acclaimed sports personalities. This brand was flaunted by the well known star of basketball Michael Jordan in the introductory period of this brand into the market in 1985. In order to give a sportier look, Nike dunks were combined with multi purpose designs and stitched sole. There are currently more than 65 different varieties of Nike dunks available in the market. Some of the models are namely, Nike dunk SB pro, Nike dunk high, Nike dunk low, Nike dunk premium, etc.&lt;/p&gt;\n&lt;p&gt;In this highly competitive market, Nike stands distinct with its large collection of shoe brands. Nike has become the other name for comfort. Nike SB shoes have been significantly named after the sports it has been particularly designed for, i.e., skate boarding. The flat sole of the Nike SB enables boarders to feel the skate more comfortably. Just to make skate boarding lot more fun, Nike added certain new features in its shoes such as suede toe caps, swollen tongues and the zoom air sole.&lt;/p&gt;\n&lt;p&gt;The best thing about Nike shoes is the varied color combination that it offers so as to enable the buyers pick their choice. It may look awkward sometimes, but all Nike shoes have a multi colored appearance which makes them distinct from other shoes labels. Nike gives importance to individual color selection and encourages free mind. The Nike saying goes &quot;Be true&quot;. The new concept of color coding has come into picture after a very astonishing incident. A game of basketball where all players of a team had decided to match the color of their Nike dunks with the color of their uniforms. Since then, the makers of Nike shoes have begun putting designs of Nike dunks in multi colored fashion.&lt;/p&gt;\n&lt;p&gt;Initially Nike was introduced as a basketball shoes and later on it was also accepted as a skateboarding wear. Nike dunks SBs appear to be longer and narrower than most other brands. To get the correct pair of Nike dunks for one, they must know the right size to look for. Nike dunks are available in many sizes and designs. It is completely your choice to get the best pair suited according to your need.&lt;/p&gt;\n&lt;p&gt;Kevin David provide interesting article about Nike Dunks, Nike dunk SB [&lt;a href=&quot;http://www.nikesportmall.com&quot;&gt;http://www.nikesportmall.com&lt;/a&gt;].&lt;/p&gt;', 'https://i.imgur.com/VTqMel3.jpg', 'nike-dunk-skateboarding', '', '2020-07-30 13:37:58', '2020-07-30 13:37:58'),
(31, 'Air Jordan 11 - A Brief History', '&lt;p&gt;The Air Jordan 11 is by far one of the most popular sneakers in footwear culture, as well as one of the most desirable sneakers in Michael Jordan''s signature line. Originally introduced in 1995, the sneakers are the creation of Tinker Hatfield who took the position as lead designer for MJ''s signature sneakers back in 1988 when he first designed the Air Jordan 3. Jordan''s performance in the shoes was nothing less than amazing. Aside from leading the Chicago Bulls to their 4th NBA Championship, he also become the second athlete in history to win the Most Valuable Player award for the regular season, All-Star Game and NBA Finals.&lt;/p&gt;\n&lt;p&gt;Over the years there have been a total of 5 color options of the Air Jordan 11 made available, not including the less popular low-cut silhouette. Since their hay-day in the mid 90''s, all the original models have been reissued at least once, and have been just as popular, if not more popular, than the first time they were released. If you''re unfamiliar with the styles, allows us to give you a brief history of each one.&lt;/p&gt;\n&lt;p&gt;AJ11 &quot;Bred&quot;&lt;/p&gt;\n&lt;p&gt;The first Air Jordan 11 to release was the &quot;Bred&quot; version, which featured a staple color palette for the Air Jordan collection. The shoes were released in April of 1995 and retailed for $125, which is a steal these days when such retro releases tip the scales at $180. To coincide with the colors of MJ''s then Chicago Bulls uniform, the Air Jordan 11 &quot;Bred&quot; features a black ballistic nylon upper with black patent leather along the base, a white midsole and a translucent outsole tinted in True Red. The iconic Jumpman logo on the ankle is embroidered in True Red as well. Since originally releasing in ''95, the shoes have been re-issued twice, once in 2001 and again in 2008 as part of the Air Jordan 11/12 Countdown Pack.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/x9Zl20Y.jpg&quot; alt=&quot;Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;AJ11 &quot;Concord&quot;&lt;/p&gt;\n&lt;p&gt;After the Chicago Bulls-colored version released the next to come was the &quot;Concord&quot; edition. These get their name from the fact that the white based upper is wrapped in Dark Concord patent leather. Further use of contrasting black details were employed on the inner lining and the Jumpman logo, while a white mid-sole is capped with an icey clear translucent outsole. The Air Jordan 11 &quot;Concord&quot; was originally released in November, 1995, and again in 2000. They also appeared in 2006 alongside an Air Jordan 6 in the Defining Moments Pack. Unlike the original design though, this particular pair featured a gold Jumpman logo.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/j09fjQ8.jpg&quot; alt=&quot;Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;AJ11 &quot;Space Jam&quot;&lt;/p&gt;\n&lt;p&gt;One of the more sought after styles of the Air Jordan 11 is the &quot;Space Jam&quot; version. These got their nickname when Michael Jordan was first seen wearing the shoes in the movie &quot;Space Jam&quot; in which he starred in back in 1996. The sneakers sport a solid black upper constructed from ballistic nylon and patent leather, with a white midsole, an icey clear outsole and subtle accents of Varsity Royal on the Jumpman logo along the ankle. Although Michael Jordan was seen wearing the shoes throughout the movie, and again during the 1996 NBA Semifinals, the Air Jordan 11 &quot;Space Jam&quot; wasn''t released to the public until 2001. A second limited release followed in 2009. Both times the sneakers were released they were one of the biggest sellers of the year.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/avrsAze.jpg&quot; alt=&quot;Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;AJ11 &quot;Columbia&quot;&lt;/p&gt;\n&lt;p&gt;The Air Jordan 11 &quot;Columbia&quot; is just as desirable as any of the other AJ11 colorways. In a solid coat of white, the shoes feature the standard ballistic nylon and patent leather construction used on all the other non-low-top Air Jordan 11 models. Accent colors come in the form of Columbia Blue, which appear on the Jumpman logo, the &quot;Jordan Jumpman&quot; tag across the tongue and translucent outsole. The shoes were originally released in 1996 and again in 2001. However, the 2001 version did not feature a blue tinged, translucent outsole like the original pair. Instead the translucent outsole left icey clear. A change which many weren''t too happy with.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/N2AzREU.jpg&quot; alt=&quot;Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;AJ11 &quot;Cool Grey&quot;&lt;/p&gt;\n&lt;p&gt;The Air Jordan 11 &quot;Cool Grey&quot; is not one of the original models that released when the sneakers did in 1995-1996, but that hasn''t stopped them from becoming a hot commodity among collectors. The Air Jordan 11 &quot;Cool Grey&quot; was first introduced in March of 2001, 6-years after the first AJ11 was revealed to the public. Like their counterparts, the sneakers got their nickname from the chosen color scheme in which they use. Medium Grey provides color to the ballistic nylon upper, while Cool Grey coats the patent leather around the base of the shoes. The upper sits atop a white midsole which is capped with the beloved icey clear outsole. Since being released in 2001, the Air Jordan 11 &quot;Cool Grey&quot; hasn''t been re-issued once. That''s all about to change later this year though when the shoes make their first comeback in 9 years.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/bx1iCfp.jpg&quot; alt=&quot;Jordan 11&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Davin Iverson is an editor for a leading online consumers buyers guide pertaining to the latest information on sneakers, including the Jordan 11&lt;/p&gt;\n&lt;p&gt;By Davin Iverson&lt;/p&gt;', 'https://i.imgur.com/j09fjQ8.jpg', 'jordan-11-brief-history', '', '2020-08-12 13:53:22', '2020-08-12 13:53:22'),
(32, 'Basic Guide to Cleaning Your Sneakers', '&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/55NojQL.jpg&quot; alt=&quot;Sneaker Cleaner&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;No matter what you do to try and avoid it, if you wear them, your sneakers are going to get dirty. Thankfully, it''s simple to keep your sneakers looking fresh-outta-the-box. If you make a steady habit of cleaning your sneakers as soon as they get dirty, they''ll continue to look brand new for years to come. A quick, basic sneaker cleaning is something that can be done by anybody in a matter of minutes too.&lt;/p&gt;\n&lt;p&gt;For a basic sneaker cleaning, I highly recommend using a specially designed sneaker cleaner. One of the brand names I''ve used and trusted for a number of years is Jason Markk. This product can be found through the company''s webstore, however, use of such a product is not mandatory in cleaning your sneakers. It only better helps the cleaning process as a product as such is formulated to remove dirt, grease and oil stains. Dish soap by any major brand can act as a substitute for a sneaker cleaner.&lt;/p&gt;\n&lt;p&gt;Start off by filling a bowl with lukewarm water. Take a toothbrush, preferably a clean one that you won''t be using to brush your teeth with afterwards, and dip the brush head in the water. Next, pour a tiny amount of dish soap, or a sneaker cleaner as mentioned above, on the toothbrush and once again dip it in the water. Lightly begin scrubbing your sneakers in a circular motion with the bristles of the toothbrush causing the soap to foam and remove any visible stains. Once satisfied, take a damp cloth and rub the sneakers down to remove the soap and look for any spots you may have missed, following the process with another rubdown using a dry cotton cloth. It''s not recommended to place your sneakers near a heater as they shouldn''t get that wet in the cleaning process to begin with, not to mention the extreme temperature will quickly dry out the leather on your sneakers. Simply let them air dry.&lt;/p&gt;\n&lt;p&gt;The same cleaning method can also be applied to the soles of your sneakers. More than likely, these will need a more thorough cleaning and may require you to repeat the cleaning process more than once.&lt;/p&gt;\n&lt;p&gt;Just like the exterior of your sneakers, the inner lining should get a cleaning once in awhile too. Just think of all the sweat they''ve absorbed, which will eventually discolor the lining, especially if it''s white. To clean the inner lining, dump the water out you used to clean the base of the sneaker and fill your bowl up with some clean water. Dip the toothbrush in the water and shake out any excess water once you remove it. With the bristles of the brush damp, scrub the lining of your sneakers in a small circular motion. It''s up to you whether you want to use soap, as it can be a pain to get it all out sometimes. Try cleaning the lining of your sneakers without it first and if you can''t remove all the stains, apply a small amount of soap. Once you''re finished, pat the lining dry with a soft cotton towel and continue to let the sneakers air dry.&lt;/p&gt;\n&lt;p&gt;Please note, suede, nubuck and any other material aside from leather, needs to be attended to in a much more delicate way. The above sneaker cleaning guide should only be applied to sneakers constructed from leather. If cleaning suede, nubuck or any material other than leather, please do your research on how you should properly go about cleaning these materials.&lt;/p&gt;\n&lt;p&gt;This article was written by Davin Iverson&lt;/p&gt;', 'https://i.imgur.com/55NojQL.jpg', 'sneaker-cleaning-guide', '', '2020-09-17 20:32:16', '2020-09-17 20:32:16'),
(33, 'Michael Jordan - A Sports Persona the Will Never Be Paralleled', '&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/6fLXdNz.jpg&quot; alt=&quot;Michael Jordan Legend&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;There are few NBA stars that possess the ability to have there first names be recognizable above any other name in their sport.&lt;/p&gt;\n&lt;p&gt;Today''s game boasts interesting names such as Kobe and LeBron but before they were even old enough to lace up sneakers one man separated basketball from sports.&lt;/p&gt;\n&lt;p&gt;Michael was, and remains, the most recognizable name in not just sports but in popular entertainment. His air-ness may share his name with the King of Pop and their achievements may be similar on a global stage but Michael Jordan''s ability to combine his achievements as an athlete and his ability to bolster his public image with his successes in the business world undoubtedly separate him from the other Michael.&lt;/p&gt;\n&lt;p&gt;Jordan entered a league dominated by Magic, Doctor J., Larry, Kareem and Moses. Among those titans of basketball, Jordan managed to captivate the sporting world while playing for an untalented Bulls team.&lt;/p&gt;\n&lt;p&gt;Jordan''s career seemed to reach new levels each season but his team was not always recognized as the second (behind Russell''s Celtics) greatest dynasty in basketball history.&lt;/p&gt;\n&lt;p&gt;Though MJ led his Bulls to the 8th seed playoff spot his first several seasons, a feat that is underappreciated on Chicago teams that were untalented and under achieving, his early career was marred by injuries and controversies caused by jealous opponents.&lt;/p&gt;\n&lt;p&gt;The NBA''s most jealous superstar, Isiah Thomas, unsurprisingly led the charge in 1984. Michael Jordan was voted as a starter, by the fans, to the all-star game in his rookie season. Isiah, feeling the attention Jordan was receiving was unjust, led a player revolt in the all-star game. In a move most forgotten for unsportsmanlike behavior, Isiah refused to pass Michael the ball throughout the game.&lt;/p&gt;\n&lt;p&gt;Jordan went on to win Rookie of the Year honors and his battles with Isiah had just begun.&lt;/p&gt;\n&lt;p&gt;His next two seasons were busted by foot and knee problems.&lt;/p&gt;\n&lt;p&gt;In 1986, Jordan returned from knee surgery in time to face the Boston Celtics in the first round of the NBA playoffs. Though the Bulls were swept by Larry''s Celtics, Jordan managed to set an unbroken playoff record of 63 points in game 2.&lt;/p&gt;\n&lt;p&gt;In 1987, Jordan averaged an astonishing 37 points per game but was again swept by the Celtics.&lt;/p&gt;\n&lt;p&gt;It wasn''t until 1988, perhaps Jordan''s most successful season individually, the Bulls emerged from the first round of&lt;/p&gt;\n&lt;p&gt;Jordan holding on of his 6 Larry O''Brien Trophies\nthe playoffs. That season, Jordan averaged 35 points per game, 52 percent from the field. He won his first of five NBA Most Valuable Player award and the NBA Defensive Player of the Year award.&lt;/p&gt;\n&lt;p&gt;It''s rare to have a player succeed on the offensive and defensive ends of the court in such a dominant fashion.&lt;/p&gt;\n&lt;p&gt;In 1988, the first of 4 epic post season battles, Isiah Thomas and his Detroit Pistons eliminated the Chicago Bulls in five games.&lt;/p&gt;\n&lt;p&gt;The Pistons and Bulls would meet again in 1989 and the Pistons, now famous, &quot;Jordan Rules&quot; defense facilitated in once again eliminating the Bulls.&lt;/p&gt;\n&lt;p&gt;In 1990 the Bulls emerging talent surrounding Jordan again fell to the Pistons as the &quot;Jordan Rules&quot; was now a famous and effective method for slowing down Jordan and stopping the Bulls.&lt;/p&gt;\n&lt;p&gt;It wasn''t until 1991 that Michael and his now ultra talented squad finally beat the Detroit Pistons. The Bulls were able to finally get revenge and swept the Pistons led by Jordan opting for the assist over the shot, made difficult by the Pistons &quot;Jordan Defensive Rules&quot;.&lt;/p&gt;\n&lt;p&gt;Isiah Thomas, in typical unsportsmanlike fashion, walked off the court before the final buzzer without congratulating his opponent.&lt;/p&gt;\n&lt;p&gt;After defeating the Detroit Pistons in 1991, Jordan led his Bulls to their first title.&lt;/p&gt;\n&lt;p&gt;The Bulls would go on to win 6 titles in 7 years.&lt;/p&gt;\n&lt;p&gt;Michael Jordan, a man who achieved personal stats unmatched by any player in NBA history, won 6 NBA titles, 5 NBA MVP awards, 6 Finals MVP awards, Rookie of the Year honors, Defensive Player of the Year honors, 14 all-star appearance, 10 all NBA first team appearances, 9 time defensive first team honors, 3 all-star game MVP awards, 2 Dunk contest championships, and now he will be inducted into the Basketball Hall of Fame.&lt;/p&gt;\n&lt;p&gt;Jordan, nearly single handedly, made famous such globally branded products as Nike and Gatorade.&lt;/p&gt;\n&lt;p&gt;Even in retirement, Jordan''s endorsements of products such as Nike and Gatorade continues to ensure their profits. On the day of Jordan''s first retirement, the NY Stock Exchange actually took a dip because of Jordan''s effect on global business.&lt;/p&gt;\n&lt;p&gt;No professional athlete can boast such a claim.&lt;/p&gt;\n&lt;p&gt;I consider myself to be a somewhat astute NBA historian and yet I had to research all of Jordan''s accolades online as to not forget any.&lt;/p&gt;\n&lt;p&gt;Above all of his personal and team achievements, perhaps Jordans most admirable contributions to professional sports was his ability to face defeat, adversity, world fame, and tremendous success with grace, maturity, sportsmanlike conduct, and humility.&lt;/p&gt;\n&lt;p&gt;His brilliance on the basketball court is missed but his presence is still felt by the players that follow him. Players such as Kobe and LeBron emulate Jordan in their on court highlights. We can often be found, jaw dropped, at an amazing move made by today''s players while thinking and sometimes shouting:&lt;/p&gt;\n&lt;p&gt;&quot;That was a Jordan move!&quot;&lt;/p&gt;\n&lt;p&gt;Today''s players may be able to resemble Jordan in their play but they certainly cannot reach the levels Michael achieved, always carrying himself with class, on and off the court&lt;/p&gt;\n&lt;p&gt;Nick Gelso&lt;/p&gt;', 'https://i.imgur.com/6fLXdNz.jpg', 'michael-jordan-legend', '', '2020-09-17 20:35:36', '2020-09-17 20:35:36'),
(34, 'Off-White Jordan 5 Retro Black Real Vs Fake', '&lt;h2&gt;Off-White Jordan 5 Retro Black Real Vs Fake:&lt;/h2&gt;\n&lt;p&gt;There are a lot of fake pairs of Off-White Jordan 5 Retro Black that are on the market. If you are planning to buy one follow this guide to identify whether the pair you''re buying is real or fake. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/VFtN2Hj.jpg&quot; alt=&quot;Air Jordan 1 Off White&quot; title=&quot;Air jordan 1 off-white&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Step 1: Check medial text:&lt;/h3&gt;\n&lt;p&gt;This is one of the easiest ways to find out a real or fake. In the fake one, the medial text weight must be too thin or too thick. You can especially notice the letter &ldquo;V&rdquo;. In the fake pair, it will look like thinner or scratched than the real Off-White Jordan 5 Retro Black&rsquo;s &ldquo;V&rdquo; character.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/bx9ZgvA.png&quot; alt=&quot;Air Jordan 1 Off White&quot; title=&quot;Air jordan 1 off-white&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Step 2: Check rear details:&lt;/h3&gt;\n&lt;p&gt;In this step, check the rear details of the sneakers. Here you need to check the Nike Air logo. In fake sneakers, you will see Swoosh Logo is usally a bit more round than normal. &lt;/p&gt;\n&lt;p&gt;This is the flaw that is most usually present on the fake pairs and we recommend you to check for this detail first.&lt;/p&gt;\n&lt;p&gt;Then come to the &ldquo;AIR&rdquo; text, on the fake pair, you will see here, the text is a bit higher than the text on the real Off-White Jordan 5 Retro Black. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ZAnpOGa.png&quot; alt=&quot;Air Jordan 1 Off White&quot; title=&quot;Air jordan 1 off-white&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Step 3: Check the elements on the side of the sneakers:&lt;/h3&gt;\n&lt;p&gt;In this step, you need to check the side of the sneakers where you will see the pattern and the placement of the elements. The real pairs you will notice 2 big transparent circles or holes on the side of the shoes. While on the fake there are not as transparent and have an odd texture.&lt;/p&gt;\n&lt;p&gt;The real Off-White Jordan 5 Retro Black, you will notice 2 transparent circles have less definiton and texture. Also, it has less stitching squeezed around the circle shapes than what it looks like on the fake pair.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/LR2gaYu.png&quot; alt=&quot;Air Jordan 1 Off White&quot; title=&quot;Air jordan 1 off-white&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Step 4: Check the tongue logo:\nThis is the next step to check the tongue for the Jumpman logo. The fake sneakers have a stitching problem on the Red Jumpman. So, the fake pairs usually have the hand with the ball in it. It looks thinner than the hand on authentic pairs. &lt;/p&gt;\n&lt;p&gt;The real Off-White Jordan 5 Retro Black has the hand looking denser and thicker than the fake Jumpman&rsquo;s hand.\n&lt;img src=&quot;https://i.imgur.com/33nmNE3.png&quot; alt=&quot;Air Jordan 1 Off White&quot; title=&quot;Air jordan 1 off-white&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/PM89uaT.jpg', 'off-white-jordan-real-vs-fake', 'jordans,off-white,sneakers,retro', '2020-11-03 23:20:08', '2020-11-03 23:20:08'),
(35, 'Start A Sneaker Shoe Company in 2021', '&lt;p&gt;How to Start a Shoe Company? 2021 Guide&lt;/p&gt;\n&lt;p&gt;Many entrepreneurs who relate to the shoe selling business argue that this business is the best. These items are often bought by people, perhaps more so than clothing. If actual fashionistas become daily clients, then a steady income is assured for the entrepreneur. Women never believe they''ve got plenty of these things in the closet. We''re going to talk today about how to open a successful shoe shop.&lt;/p&gt;\n&lt;p&gt;A pair of shoes&lt;/p&gt;\n&lt;p&gt;Description automatically generated\nA step-by-step plan:&lt;/p&gt;\n&lt;p&gt;Selecting a reputable supplier is the key to running any trade-related business. The terms of cooperation should ensure:\nThe quality of the supplied goods.\nStability and consistency.\nSmall wholesale supplies.\nWhen dealing with Chinese vendors, this stage of the business organization needs careful attention. Cheap shoes from China for kids, men, and women are in great demand among buyers today. It is focused mainly on middle-income buyers and is available to most of the population.\nChoosing a place:&lt;/p&gt;\n&lt;p&gt;You can open stores with products from China with better traffic almost anywhere, where shopping areas are provided:\nPavilion at the city clothing market.\nBoutique in a shopping center.\nSelf-service store in a separate non-residential premise.\nAny of these options requires a certain number of funds to be spent in favor of the rent. Experts do not advise investing in the first choice, even though the sale claims to be big. Clothing markets are increasingly becoming outdated as trading platforms.\nWe select an assortment:&lt;/p&gt;\n&lt;p&gt;You need to select the right collection to open a shop. It is recommended that experienced entrepreneurs stick to these rules:\nChoose styles that you would never wear when you buy them.\nThe price and reliability do not always justify one another.\nIt is easier to select the men''s range of genuine leather items from China and the women''s leatherette range.\nInitially, the average customer who comes to the shop may set a target of purchasing one good leather product, but, for the same money, he sometimes buys two or three pairs of leatherette shoes from China.\nAmount to start-up to open a shoe store:&lt;/p&gt;\n&lt;p&gt;One of the main questions of interest to all, without exception, novice entrepreneurs - how much money you need to have to open a shoe store, without loans and the help of investors. Of course, there is no universal answer in this case. An important role is played by your location, the size of the outlet, the assortment, and other factors, but you can make calculations based on the average statistical indicators in this area of ??business.&lt;/p&gt;\n&lt;p&gt;The initial investment required to open a shoe store:\nRegistration and paperwork - $ 200.\nAdvertising campaign - $ 1,000.\nBuy equipment &amp;amp; furniture - $ 2,000.\nIndoor repairs - $ 1,500.\nPurchase of the first batch of goods - $ 5,000-1,000.\nAdditional costs - $ 300\nThe total amount needed to open a store is 10-15 thousand dollars.&lt;/p&gt;\n&lt;p&gt;Unfortunately, the items listed above are not all the costs associated with opening a store. The first month or two, until you reach the &quot;break-even point&quot;, you need to pay staff salaries, rent, utilities, taxes, and also replenish your assortment with the most popular items. The total cost (taking into account that in a month the store will reach the level of self-sufficiency) will be about 2-4 thousand dollars.&lt;/p&gt;\n&lt;p&gt;Based on the above data, we can conclude that the minimum amount for opening a shoe store is 12 thousand dollars. If you plan to sell products that are an order of magnitude higher, you will need capital from $ 19 thousand.\nPurchase of furniture and equipment:&lt;/p&gt;\n&lt;p&gt;For a retail outlet to sell shoes, you need to buy:\nRacks that are installed in the warehouse (premises outside the sales area) for storing shoes.\nShowcases and podiums for placing shoes, as well as hanging shelves for accessories.\nMirrors that are installed in the sales area so that the buyer can see the product he likes from all possible angles.\nOttomans, rugs, and spoons.\nStaff table and chairs.\nAdditional accessories for room decoration.\nIn addition to the listed things, do not forget about the cash register, without it it is forbidden to accept cash from customers.\nRegistration of the necessary documents:&lt;/p&gt;\n&lt;p&gt;For the operation of a shoe outlet, it is necessary, first of all, to draw up documents for an individual entrepreneur or LLC. The choice of the organizational and legal form for your activity is an individual issue that you must decide on your own.\nIn addition to the standard set of documents confirming that you are registered with the tax office as an individual entrepreneur or LLC, and are a taxpayer, you must have:&lt;/p&gt;\n&lt;p&gt;An agreement on the lease of premises or a document confirming that it is your property.\nPapers on registration and maintenance of the cash register.\nGarbage collection agreement.\nQuality certificates for all products sold.\nConclusion of representatives of the fire service.\nEmployee recruitment papers.&lt;/p&gt;\n&lt;p&gt;Also, in a shoe store, it is necessary to arrange a buyer''s corner, in which there should be a &ldquo;Book of complaints and suggestions&rdquo;. In addition to the listed documents and papers, to carry out commercial activities for the sale of shoes, you do not need to obtain additional permits and licenses.&lt;/p&gt;', 'https://i.imgur.com/GYH2VmJ.jpg', 'start-shoe-sneaker-company-2021', '', '2020-12-02 04:37:56', '2020-12-02 04:37:56'),
(36, 'How to start a sneaker store', '&lt;p&gt;Sneakers have grown in popularity over the last few years. More people than ever have entered the sneaker business. The newcomers are either sneaker resellers or sellers who have set up merchant/consignment shops.\nThis guide is tailored towards the entrepreneur who would like to become an independent retailer.\nThe first place to start is to start with an overall store business plan. This will be the core blueprint on how you approach the business side of opening your new store. This business plan is broken into multiple sections outlining different areas of the business.&lt;/p&gt;\n&lt;ol&gt;\n&lt;li&gt;\n&lt;p&gt;Industry Overview\nResearch shows that the Athletic Shoe Stores industry has grown strongly over the five years to 2020 due to economic growth and rising sports participation. The increase in popularity in sneakers has been met with a decrease in supply causing a sharp rise in prices and willingness for buyers to pay 3x premiums for coveted sneakers.&lt;/p&gt;\n&lt;/li&gt;\n&lt;li&gt;\n&lt;p&gt;Executive Summary\nExample: SoleInsider Sneaker Store, Inc. is a registered sneaker store that will be located in Soho Manhattan. We have been able to lease a 2,500 square foot location that is in a heavily trafficked street.&lt;/p&gt;\n&lt;/li&gt;\n&lt;/ol&gt;\n&lt;p&gt;SoleInsider Sneaker Store, Inc. will retail a wide range of men&rsquo;s, women&rsquo;s, children&rsquo;s sneakers, and other types of athletic shoes from different brands. We plan on carrying a wide range of popular brands such as Jordan, Nike, Yeezy, and Adidas. We are set to service a wide range of clientele in and around Soho &ndash; New York.&lt;/p&gt;\n&lt;p&gt;SoleInsider Sneaker Store, Inc. is owned by John Brown. Mr. Brown has 3 retail experience and has worked with some of the leading shoe brands in the United States.&lt;/p&gt;\n&lt;ol start=&quot;3&quot;&gt;\n&lt;li&gt;Products and Services\nOutline the type of products you will be offering in this section. Examples below.&lt;/li&gt;\n&lt;/ol&gt;\n&lt;p&gt;Our product offerings are listed below;\nRetailing sneakers such as Nike, Jordan, and Adidas\nRetailing boots such as Timberland and Converse\nRetailing clothing from streetwear brands such as Palace, Stussy\nRetailing accessories such as cell phone cases and chargers&lt;/p&gt;\n&lt;ol start=&quot;4&quot;&gt;\n&lt;li&gt;Mission and Vision Statement\nExample: Our vision is to become one of the leading brands in the sneaker business in New York City. We want to establish a large social media presence. We want to work with other sneaker brands such as Nike for collaborative releases.&lt;/li&gt;\n&lt;/ol&gt;\n&lt;p&gt;Our mission is to establish a nationwide sneaker business. We want to offer our customers a unique shopping experience with tailored customer service.&lt;/p&gt;\n&lt;ol start=&quot;5&quot;&gt;\n&lt;li&gt;Job Roles and Responsibilities\nChief Executive Officer &ndash; CEO:&lt;/li&gt;\n&lt;/ol&gt;\n&lt;p&gt;Responsible for  signing business deals and cleaning decisions\nResponsible for providing direction for the business\nResponsible for signing documents and legal paperwork on behalf of the company\nResponsible for making organizational-wide decisions.&lt;/p&gt;\n&lt;p&gt;Store Manager:&lt;/p&gt;\n&lt;p&gt;Ensures that the storage facility is in order and goods are properly arranged and easy to locate.Controls distribution and supply inventory&lt;/p&gt;\n&lt;p&gt;Merchandising/Buyer\nManages vendor relations, market visits, and the ongoing education and development of the organizations&rsquo; buying teams\nHelps to ensure that quality sneakers and other athletic shoes from different manufacturers are purchased and retailed in good price that will ensure we make a good profit\nResponsible for planning sales, monitoring inventory, selecting the merchandise, and writing and pricing orders to vendors\nSales and Marketing \nHelps to increase sales and growth for the company&lt;/p&gt;\n&lt;p&gt;Staff:\nResponsible for day to day activities in store\nResponsible for interacting with customers\nResponsible for stocking shelves\nResponsible for cleaning up the store after closing&lt;/p&gt;\n&lt;ol start=&quot;6&quot;&gt;\n&lt;li&gt;Target Market&lt;/li&gt;\n&lt;/ol&gt;\n&lt;p&gt;In view of that, we have positioned our sneaker store to service the residents of Soho, New York. We have conducted our market research and feasibility studies and we have ideas of what our target market would be expecting from us. We are in business to retail a wide range of sneakers to the following groups of people;\nMen and women\nStudents&lt;/p&gt;\n&lt;p&gt;Once you&rsquo;re done outlining your core business plan. You can move on to more logistical and operational aspects. Running a solid operation is at the heart of any sneaker store. It''s what allows it to function and serve the customers that frequent the establishment. If you&rsquo;re planning on stocking your shelves with the more popular and rare products, you will need to make the right connections. This is often why stores with a long history get better sneakers. You will need to build up your reputation while constantly outreaching to other industry connections. This can be done via Social Media or on LinkedIn.\nRunning a sneaker store business isn''t as easy as finding a physical location and filling it to the brim with sneakers. You&rsquo;ll need to also figure out how you will present your store to the buyer once you have suppliers and a retail store in place. You may want to reach out to retail designers to help you layout your store''s concept and research existing stores with terrific layouts like Kith and Extra butter.\nSocial media is truly important. During the execution of your physical store, you&rsquo;ll want to begin your social media planning and push. You should immediately register your store name on all social media platforms you plan on using. Once you have your accounts in place, you can later think about your social media strategy.\nOnce you have your business plan, social media accounts, and locations scouting in place. You&rsquo;re in a perfect position now to begin completing the legal paperwork to get your business up and running. Good luck!&lt;/p&gt;', 'https://i.imgur.com/Pp7Qq7O.jpg', 'how-to-start-a-sneaker-store', '', '2020-12-16 03:54:22', '2020-12-16 03:54:22'),
(37, '4 safety and protection tips for water sports', '&lt;h2&gt;4 safety and protection tips for water sports&lt;/h2&gt;\n&lt;p&gt;The practice of water sports is common, and that means that people who sometimes do not have basic knowledge of safety and rescue procedures in water and other precautions begin to ask about aquatic disciplines. For this reason, we decided to collect some essential tips so that you can practice water sports while minimizing risks as much as possible&mdash;tips to equip yourself properly and be prepared for accidents, injuries, or eventualities in sports.&lt;/p&gt;\n&lt;h2&gt;Use of the correct equipment&lt;/h2&gt;\n&lt;p&gt;This first tip, and one of the most basic, is also one that should not be forgotten. There are a large number of water activities, and each requires a specific type of equipment. It is important to respect it and use it correctly, which is the key to avoiding injuries and accidents in sports under or on water.&lt;/p&gt;\n&lt;p&gt;For example, for those who practice diving or canoeing, it is not enough to wear a swimsuit. Each activity has its rules and its accessories or tools that allow it to be practiced without risk. It is important to be adequately informed about each sport, its rules, scopes, and precautions. Also, if you forget any of the elements, it is always better to postpone the activity until you can do it most safely and save yourself from trouble. A large number of injuries and accidents can easily be prevented with the correct equipment &lt;/p&gt;\n&lt;h2&gt;Learn swimming styles&lt;/h2&gt;\n&lt;p&gt;It is unnecessary to be a professional swimmer to practice water sports, but it is important to have a notion of basic swimming styles. The most advisable thing is to take some classes to learn to swim faster, and with different styles according to the situation, it is also important to be able to read some signs such as the flags of the state of the water in the sea, for example. Fundamental elements of aquatic sports practice that can be easily learned with a little dedication and training.\nAlso, remember that if you have done any other physically exhausting activity outside of the water, it may cause you to have less energy or performance when practicing a water sport, so keep an eye on your physical condition.&lt;/p&gt;\n&lt;h2&gt;Carefully analyze currents&lt;/h2&gt;\n&lt;p&gt;When you practice a water sport outside of a pool, try to stay away from places with strong currents. Contrary to what some believe, strong currents are not beneficial for a strong body workout but create greater dangers.\nIn case you are practicing water sports for the first time, always opt for quieter places. Avoid places near rocks and currents that may drag you there unintentionally.&lt;/p&gt;\n&lt;h2&gt;Control the depth&lt;/h2&gt;\n&lt;p&gt;As the heat and good weather approach, one tends to seek refreshing sports in the water. However, do not forget to study the place chosen for sports carefully. Always seek to control the depth and be able to have knowledge of what you will find below. It is not the same to know that there are algae that can trap your legs or rocks that can hurt your feet. By knowing what is in the depths, you act more consciously in your different alternatives.&lt;/p&gt;\n&lt;p&gt;These are some very basic but fundamental tricks for the safe practice of water sports. Remember to take note and take them forward to avoid unpleasant surprises in a water sports practice with friends or alone.&lt;/p&gt;', 'https://i.imgur.com/eL6eGFV.jpg', '4-safety-tips-for-water-sports', 'safety,water', '2020-12-18 21:37:48', '2020-12-18 21:37:48'),
(38, 'Sneaker trends 2021: We''ll wear these stylish models up and down in 2021!', '&lt;h1&gt;Sneaker trends 2021: We''ll wear these stylish models up and down in 2021!&lt;/h1&gt;\n&lt;p&gt;Comfortable and stylish: sneakers are among our absolute favorite shoes. We''ll show you which sneaker trends you shouldn''t miss in 2021 and which models should move into your shoe cabinet immediately. &lt;/p&gt;\n&lt;p&gt;Over the past few years, sneakers have become an absolute must-have in shoe collection. Not only are they super comfortable, so we can really walk around in them all day without pain, they are also incredibly varied. Meanwhile, sneakers come in all possible colors and shapes, which make our outfits look cool, casual, and extremely stylish. It doesn''t matter whether we combine them with classic blue jeans or a summer maxi dress; sneakers always work. &lt;/p&gt;\n&lt;h2&gt;It goes high: high-top sneakers are trendy in 2021&lt;/h2&gt;\n&lt;p&gt;While we''ve tended to wear sneakers that exposed our ankles over the past few years, the New Year is going high. In 2021, high top sneakers will be one of the must-haves among shoe trends. Their high shaft extends over the ankles, which gives them a slightly masculine and very sporty look.&lt;/p&gt;\n&lt;p&gt;When it comes to sneakers, 2021 is all about casualness, comfort, and sportiness. That doesn''t necessarily mean that a sporty shoe has to be worn with a sporty outfit. High top sneakers can also be combined fantastically with summery maxi dresses - preferably in a completely white design. &lt;/p&gt;\n&lt;h2&gt;Green footprint: sustainable sneakers&lt;/h2&gt;\n&lt;p&gt;Sustainability is much more than just a trend that has now also gained a foothold in the fashion industry. Fortunately, don''t we all want to pay more attention to our ecological footprint? Sustainable sneakers are just what you need. &lt;/p&gt;\n&lt;p&gt;The models are classic, universally combinable, and absolutely timeless. A big plus, because the shoes shouldn''t be sorted out again in the next season, but should still match your personal style in a few years. Stars like Meghan Markle and Reese Witherspoon, who have already been seen wearing sustainability sneakers several times, also find it very popular. The mostly vegan sneakers are made of waxed canvas, organic cotton, and natural rubber, but recycled plastic bottles are also used to produce the shoes. &lt;/p&gt;\n&lt;h2&gt;Show true greatness with trendy platform sneakers&lt;/h2&gt;\n&lt;p&gt;In 2020 we could already spot them here and there, but in 2021 we definitely want to get a taste of the mountain air and make platform sneakers a permanent part of our winter, spring, summer, and autumn wardrobe. The sneakers that cheat us a few centimeters larger fit into every season and can be combined endlessly because of their different designs. &lt;/p&gt;\n&lt;h2&gt;Sneaker trends 2021: Running sneakers&lt;/h2&gt;\n&lt;p&gt;Comfort comes first, the shoe must not pinch. Most of the time, running shoes have a very eye-catching design, bright and bright colors, which ultimately serve the function - you stand out and are not overlooked when jogging in the dark. In 2021, however, the colorful running shoes will get a little more to see than the daily, weekly, or monthly running route. &lt;/p&gt;\n&lt;p&gt;Because running sneakers will be the models in the coming year that we simply will not be able to avoid.&lt;/p&gt;\n&lt;p&gt;This is not only due to their excessive comfort but also to the slightly unconventional design. The colorful color combinations are eye-catchers and give every outfit that certain something. In 2021 we won''t be saying goodbye to this year''s loungewear trend and prefer to combine casual running sneakers with knitted joggers, matching sweaters, or cardigans. &lt;/p&gt;\n&lt;p&gt;If that''s too casual for you, you can also combine the running sneakers with flared blue jeans and oversized blazers, which creates an exciting but classic break in style! &lt;/p&gt;', 'https://i.imgur.com/BZonlLn.jpg', 'sneaker-trends-2021', 'sneaker,trends', '2020-12-18 21:43:09', '2020-12-18 21:43:09');
INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(39, 'How to spot a fake Rolex watch', '&lt;h2&gt;The guide to buying a Rolex and avoiding the fakes&lt;/h2&gt;\n&lt;p&gt;Start with knowing the reputation of the seller. The easiest way to prevent buying a replica or fake Rolex is to buy from a reputable and trusted seller. There&rsquo;s a lot of reputable sellers to begin your search. Some examples are Crown and Caliber, Jomashop, Chrono24, and WatchFinder. The list goes on, please research the seller before deciding to purchase from on. If you can find a seller that does inspections and service of each watch before selling is a huge plus. Additionally, it is recommended that you find a dealer that specializes in Rolex watches if possible but not a requirement. Most gray market sellers will have better deals.&lt;/p&gt;\n&lt;p&gt;Be wary of auction sites but don&rsquo;t completely rule them out. eBay, Craigslist, Mercari, and such sites are often plagued with fake watches. It can be difficult to find trusted and honest Rolex sellers. The good news is that most online sellers are now offering authentication services where your watch can&rsquo;t be sent to a third-party authorization service before routing the watch to you. These 3rd party authentication services are usually covered by the seller of the watch and should not add any additional cost to you. I would not purchase a watch from a marketplace unless the seller is a known and reputable seller or offers a 3rd party authentication service.&lt;/p&gt;\n&lt;h2&gt;Check the serial number&lt;/h2&gt;\n&lt;p&gt;A very reliable way to confirm a Rolex is genuine is to refer to the serial and case reference numbers. The serial and model numbers on a genuine Rolex are deep and perfectly marked in solid and very crisp and legible. The fake serial number tends to have an unsharp finish and lots of stretching because the machine work is sub-par. A quick google search of your serial number should point back to the make/model/year of your watch. If you see any other sites offering a watch with the same serial number, more than likely your watch or the other seller''s watch is a replica.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/lqWnLjA.png&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Rolex Crown&lt;/h2&gt;\n&lt;p&gt;The crown should sit pretty tight near noon on the watch dial. Most fakes have a really bad placement or no placement at all. This is often to lower the cost of producing the watch.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/SZ1xv8S.png&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Rolex Movement&lt;/h2&gt;\n&lt;p&gt;The movement is the most important part of any watch. It is the literal heart and brains of the watch. This is where most fake watch skimp because it easier to use a mass-produce low-cost movement than a genuine Rolex movement. Each genuine movement will always have &ldquo;Rolex&rdquo; engraved on it, and the individual parts will be preciously finished. Historically Rolex has produced quartz movement watches, but a vast majority of the popular and new models of Rolex use mechanical movements. Take a look below at the comparison of a fake vs real Rolex mechanical movement. Also, take a look at some of the photos below showcasing the superb finishing of all Rolex movements&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/BciSoOH.png&quot; alt=&quot;Rolex&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Li6jF2s.jpg&quot; alt=&quot;Rolex&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/ArrkYeY.jpg&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Cyclops&lt;/h2&gt;\n&lt;p&gt;The cyclops is the small magnifying lens on the crystal above the date window. A genuine Rolex, the cyclops magnifies the date 2.5 times for increased readability and the date will fill up the entire cyclops window. On fakes, usually, the cyclops magnification is much weaker, making the date appear smaller&lt;/p&gt;\n&lt;h2&gt;Micro etching on the crystal&lt;/h2&gt;\n&lt;p&gt;In 2002, Rolex began micro-etching a tiny crown logo at the 6 o&rsquo;clock position on the sapphire crystal.  The laser-etched crown can be very difficult to see with the naked eye. Usually, under magnification, you can see the crystal very clear. Because of the difficulty to etch and the side, many replicas watches either skip the micro etching all together or it''s very poorly done. Modern authentic Rolex watches are outfitted with a scratchproof sapphire crystal. This crystal is important for protecting the dial of the watch. Cheaper models will often use a much cheaper acrylic or combination crystal. As a side note, many older Rolex models such as 1980s Datejust models feature acrylic crystals. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/n9CKVfa.jpg&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Dial&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/DyOMKrS.jpg&quot; alt=&quot;Rolex&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/tcVRTN4.jpg&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Most newer model Rolexes feature what''s called a sunburst dial. The texture is similar to brushed metal but instead of parallel lines, the pattern is radial, with the lines coming from the center of the dial. The design makes the dial extremely difficult to produce and very expensive. Because of the cost and difficulty, most fakes skimp on the dial and use flat finished dials as seen in the comparison picture below.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/DyOMKrS.jpg&quot; alt=&quot;Rolex&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Weight&lt;/h2&gt;\n&lt;p&gt;A genuine Rolex will typically wear more and feel more solid than a replica. The reason being is the quality of the steel used for the case and the bracelets are much thicker making the case heavier. It may be tough to compare the weight if you don''t have a comparable model. Use your best instinct at that moment, if the watch feels light, hollow, or loose in any regard, it is more than likely a replica.&lt;/p&gt;\n&lt;h2&gt;Caseback&lt;/h2&gt;\n&lt;p&gt;Every Rolex model made after 1930 features a solid case back. You will not find a sapphire case back on any newer model. The only way to see the movement is to remove the case back to view the movement. Except for the Rolex Sea-Dweller, Milgauss, some Military models or models that were gifted, Rolex does not engrave the exterior of their case backs. Some older lady Rolex Datejust models like the 6917 and 69173 do have &ldquo;Stainless Steel&rdquo; and &ldquo;Registered Design&rdquo; on their case backs. So that is an important part to note.&lt;/p&gt;\n&lt;h2&gt;Summary of the quick red flags to look out for.&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Authentic Rolex watches typically weigh more than most fakes because of the quality of the materials and the thickness of the case. &lt;/li&gt;\n&lt;li&gt;Almost every Rolex movements feature a brand in-house mechanical movement. The exception is the oyster quartz which uses a battery-powered quartz movement.&lt;/li&gt;\n&lt;li&gt;The date is shown in the cyclops lens on the crystal and it should almost fill up the entire bubble.&lt;/li&gt;\n&lt;li&gt;The dial on most Rolex will feature a sunburst pattern. The pattern is very difficult to reproduce and is often very easy to spot because of the visual appeal.&lt;/li&gt;\n&lt;/ul&gt;', 'https://i.imgur.com/DMZfE0N.jpg', 'how-to-spot-a-fake-rolex-watch', '', '2020-12-19 22:04:05', '2020-12-19 22:04:05'),
(40, 'How to spot fake airpods', '&lt;h1&gt;How to spot fake AirPods?&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/8m3wdWf.jpg&quot; alt=&quot;How to spot fake airpods&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;AirPods are earbuds that are connected to Apple devices via Bluetooth. These are wireless and can be used to play the audio automatically from your device. Further, it can be used to make phone calls. One of the best features of Airpods is that it removes background voices while making calls.\nThese features work exceptionally in the real AirPods, but you may find mistakes in the fake AirPods.&lt;/p&gt;\n&lt;h2&gt;How is it possible for us to spot fake AirPods?&quot;&lt;/h2&gt;\n&lt;p&gt;The content given below will help you with the best solution to this problem.\nHow can you spot fake AirPods?\nSome essential features will help you to spot fake AirPods when you are purchasing AirPods.&lt;/p&gt;\n&lt;h2&gt;Check the serial number:&lt;/h2&gt;\n&lt;p&gt;The best and reliable way to spot fake AirPods is to check the serial number. This serial number is specific for each AirPods case. This serial number is written on the top and inner side of the box in which AirPods is placed.\nAnalyze the diffuser closely:&lt;/p&gt;\n&lt;p&gt;The diffuser is present on the top of your headphone. Analyze this area closely. In the real AirPods, the diffuser and slit are in the same line, but in the fake AirPods case, the diffuser and slit are misaligned. \nCheck the shape of the grilled area:&lt;/p&gt;\n&lt;p&gt;There is a grilled area on the headphone; a difference in the grilled area''s quality and shape also helps us spot fake AirPods. These shapes differ in the original and fake AirPods.&lt;/p&gt;\n&lt;p&gt;This area is oval-shaped in the real AirPods, but in fake AirPods, this area seems like a circle rather than an oval.&lt;/p&gt;\n&lt;h2&gt;Inspect the lightening port:&lt;/h2&gt;\n&lt;p&gt;The lightning port is the part of the headphone through which AirPods get charged. This port is surrounded by a metal outline. The thickness of this metal outline shows the difference between genuine and fake AirPods.\nIn the real case, this outline is thin, but in the fake AirPods, this metal outline is comparatively thicker.\nNotice the color of texts:&lt;/p&gt;\n&lt;p&gt;Every Apple device has the text &quot;Designed by Apple in California, Assembled in China.&quot; This text differs in the color and spacing in the real and fake cases.\nThis text is printed in a light grey color and appears thinner. On the other hand, this text appears thicker and is in any other shade than a grey shade in the fake AirPods. &lt;/p&gt;\n&lt;h2&gt;Final thoughts:&lt;/h2&gt;\n&lt;p&gt;Airpods undoubtedly provide exceptional features, but the experience becomes poor if we get a copied or fake Airpod.\nWe have shared some information and features; by checking these features, you can easily spot fake Airpods.&lt;/p&gt;', 'https://i.imgur.com/ms1W1Pw.jpg', 'how-to-spot-fake-airpods', 'airpods', '2020-12-27 04:27:13', '2020-12-27 04:27:13'),
(41, 'How to spot fake rolex datejust', '&lt;h2&gt;How to spot fake Rolex Datejust?&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/JcjeoY6.png&quot; alt=&quot;spot fake rolex datejust&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Are you looking for a real Rolex Datejust? But you are afraid of the scammers; maybe by mistake, you get the fake Rolex Datejust.\nHow can you protect yourself from fake choices? There is no need to worry; we will guide you on the spot fake Rolex Datejust while purchasing.&lt;/p&gt;\n&lt;h2&gt;How Can I spot Fake VS Real Rolex Datejust?&lt;/h2&gt;\n&lt;p&gt;Some significant features will help you to spot a fake Rolex Datejust while buying.&lt;/p&gt;\n&lt;h2&gt;Check date Wheel:&lt;/h2&gt;\n&lt;p&gt;While you check the date wheel, the date wheel in the Rolex Datejust will be appropriately placed, but a fake watch shows its date text improperly.\nOver a real Rolex Datejust, the watching data is quite simple and clear to see, but in fake watches, the date looks blurry.&lt;/p&gt;\n&lt;h2&gt;Check to engrave of the rehaut:&lt;/h2&gt;\n&lt;p&gt;The second thing that you need to check is an engraving of the rehaut; look at the engraving visibility.\nA fake watch will present poor visibility at the engraving of the rehaut, while a real watch will give you a clear view to learn the text.&lt;/p&gt;\n&lt;h2&gt;Check Cyclops lens of the Rolex Datejust:&lt;/h2&gt;\n&lt;p&gt;While buying the Rolex Datejust, never forget to check the Cyclops lens of the watch.\nWhen you check the Cyclops lens, the real Rolex Datejust watch cyclops lens will be shinier and give a brighter view, while the fake watch will give a dim view that does not look better.&lt;/p&gt;\n&lt;h2&gt;Check the date flipping of the watch:&lt;/h2&gt;\n&lt;p&gt;Never forget to check the date flipping feature of the watch. You can also spot the fake Rolex Datejust by flipping the feature of the watch.\nIn the Real watch, date flip is instant when we change or wind the hours, but this feature works slowly and takes time in fake Rolex Datejust.&lt;/p&gt;\n&lt;h2&gt;Check the Lume:&lt;/h2&gt;\n&lt;p&gt;In the Real Rolex Datejust when you turn off the lights while charging, its lume glows shiny, but the dial remains dark, and it gives a clear view.\nBut on the other hand, a fake Rolex Date just does not give a clear view in the dark, and its lume color also looks dull in the dark.&lt;/p&gt;\n&lt;h2&gt;Check the end links of Rolex Datejust:&lt;/h2&gt;\n&lt;p&gt;Do not forget to check the end links of the Rolex Datejust; a real Rolex Datejust watch contains solid end links, and everything is assembled correctly.\nBut you will notice some mistakes on that portion in fake Rolex Datejust.&lt;/p&gt;\n&lt;h2&gt;Final Thoughts:&lt;/h2&gt;\n&lt;p&gt;Rolex Datejust is an exceptional feature containing high-quality wristwatches, but sometimes we get fake Rolex Datejust.\nWe have guided you with some points, which will help you to spot fake Rolex Datejust.&lt;/p&gt;', 'https://i.imgur.com/MsGGia5.png', 'how-to-spot-fake-rolex-datejust', 'rolex', '2020-12-27 04:31:14', '2020-12-27 04:31:14'),
(42, 'Off-White x Air Jordan 1 âCanary Yellowâ Releasing Soon', '&lt;p&gt;There were plenty of rumors about the release of the Off-White x Air Jordan 1 &ldquo;Canary Yellow&rdquo;. It seems like those rumors are closer to becoming a reality in 2021. Virgil teased a list of blurred images with possible sneaker drops this hear. These unreleased collabs were &ldquo;ACTUALLY PENDING.&rdquo; There were references to other models like Nike Dunk Lows, Nike Air Force 1s.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/cWV7tpK.jpg&quot; alt=&quot;Air jordan 1&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/cWV7tpK.jpg', 'off-white-canary-yellow-release', '', '2021-01-15 17:02:49', '2021-01-15 17:02:49'),
(43, 'The True Story Behind Banned Jordans', '&lt;p&gt;Today, the hype behind Air Jordan 1s is at an untouched high. Yet, this shouldn''t be a surprise at all. The Jordan 1 has been at the forefront of mainstream society since it dropped in 1984. The story goes that in Michael Jordan''s freshman year he wore a couple of Jordan 1s that didn''t fit to the NBA''s uniform code and was quickly fined for each game he played wearing them. Nike opted to pay the steep fine that Jordan received to keep the sneakers on the court. This story made these sneakers a cultural legend. Read me here&lt;/p&gt;\n&lt;p&gt;&lt;a href=&quot;https://stockx.com/news/what-are-banned-jordans/&quot;&gt;https://stockx.com/news/what-are-banned-jordans/&lt;/a&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/hgFOkxv.png&quot; alt=&quot;Air jordan 1&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/hgFOkxv.png', 'true-story-behind-jordan-1-banned', '', '2021-01-15 17:22:31', '2021-01-15 17:22:31'),
(44, 'Official Photos of 2021âs Air Jordan 5 âRaging Bullâ', '&lt;p&gt;The &ldquo;Red Suede&rdquo; Air Jordan 5 was originally released alongside the &ldquo;3M&rdquo; pair as part of the &ldquo;Raging Bulls&rdquo; Pack also referenced as the &ldquo;Toro Bravo&rdquo; Pack in 2009. Both pairs came housed in a special wooden box with a bull''s eye in Red.&lt;/p&gt;\n&lt;p&gt;Look for the Air Jordan 5 &ldquo;Raging Bull&rdquo; to release on April 10th at select retailers and Nike.com. The retail price tag is set at $190 USD.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Ik7qlxW.jpg&quot; alt=&quot;Air jordan 5 Raging Bull&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/7uEnDiL.jpg&quot; alt=&quot;Air jordan 5 Raging Bull&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/TeNU4MK.jpg&quot; alt=&quot;Air jordan 5 Raging Bull&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Pk0sQ35.jpg&quot; alt=&quot;Air jordan 5 Raging Bull&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/OwAcWqN.jpg&quot; alt=&quot;Air jordan 5 Raging Bull&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/Pk0sQ35.jpg', '2021-raging-bull-official-photos', '', '2021-01-19 17:46:50', '2021-01-19 17:46:50'),
(45, 'Nike Reveals Newest Crater Model', '&lt;p&gt;Nike Crater Impact\nStyle Code: DB2477-100\nRelease Date: 2021\nPrice: $110&lt;/p&gt;\n&lt;p&gt;The shoe will be releasing in a handful of color options beginning this spring, which includes this upcoming offering. Dressed in a Sail mesh upper highlighted with Orange contrasting accents and Volt-colored insoles. The recycled Crater Foam and other sustainable materials are used on the midsole and rubber outsole.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/z4j6Tae.jpg&quot; alt=&quot;Nike Crater Impact&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/1WMl8RA.jpg&quot; alt=&quot;Nike Crater Impact&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/2VdRJJW.jpg&quot; alt=&quot;Nike Crater Impact&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/EEpO3Xr.jpg&quot; alt=&quot;Nike Crater Impact&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/z4j6Tae.jpg', 'nike-reveals-crater-model', '', '2021-01-19 17:49:47', '2021-01-19 17:49:47'),
(46, 'How to spot fake air jordan 8', '&lt;h1&gt;How to Spot Fake Air Jordan 8s?&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/1BmRdzj.jpg&quot; alt=&quot;How to spot fake Air Jordan 8&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In this world of scammers, we should know about an original and fake version of different things. Some people have experience of recognizing legit sneakers by just merely looking at the shoes. Afraid of scammers and thinking about how to spot fake Air Jordan 8s? Before you make a purchase, you need to learn about how to spot the fake one. If you want to know the difference between original and fake Air Jordan 8 shoes, here are the details:&lt;/p&gt;\n&lt;h3&gt;Air Jordan 8 Shoebox:&lt;/h3&gt;\n&lt;p&gt;When you buy Air Jordan 8s sneakers, first have an in-depth look at the shoebox; the original branded box is a high-quality print and finish. There is a unique logo on the cover or side of the box; correctly notice that logo by searching google.  Do a quick google search of the style number and see what sneakers are returned in the results. Use a barcode scanner app to scan the barcode and ensure that all the details according to the product should be correct.&lt;/p&gt;\n&lt;h3&gt;Air Jordan 8 Size tag and tongue badge authentication:&lt;/h3&gt;\n&lt;p&gt;The size tag inside the Air Jordan 8 shoe, has thick wrapping and bold letter print. If the size tag has thin letters with thin wrapping, then these are not original. The tight and neat woolen embroidery on a page indicates that it is not a replica.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/vv7Zu4Q.jpg&quot; alt=&quot;How to spot fake Air Jordan 8&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Stitching:\nIf you want to verify the original vs fake Air Jordan 8 shoes, look at their stitching. The stitching on fake shoes is extremely thin. This is because the thread is not correctly visible. The legit shoes have stitching lines that are very defined and extremely visible.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/k4qq94u.jpg&quot; alt=&quot;How to spot fake Air Jordan 8&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Air Jordan 8 Pull tab:&lt;/h3&gt;\n&lt;p&gt;Notice the pull tab on the shoe''s side; make sure that the tab''s stitching is single lined with even gaps. Check that according to the colorway; the tab color is also correctly aligned. Air Jordan''s logo is marked on the tab, aligning with the strap color, and is also an enate logo. &lt;/p&gt;\n&lt;h3&gt;Air Jordan 8 Strap:&lt;/h3&gt;\n&lt;p&gt;Air Jordan 8 shoes have the numbers 23 embossed on the strap. The numbers are well defined and the embossing is extremely prominent. There is no stitching on the numbers themself. Make sure that the stitching around the number is evenly spaced. Pull the heel tab and correctly notice its stitching style; a rectangular pattern aligns at the strap''s end.&lt;/p&gt;\n&lt;h3&gt;How do I know my Air Jordan 8s are fake summary?&lt;/h3&gt;\n&lt;p&gt;It might be possible, you didn''t get the point like which one sneaker is fake Air Jordan, but the above-discussed outline is a practical guide for you. Furthermore, a quick 60 seconds solution is also best for authentication that important to consider, such as:&lt;/p&gt;\n&lt;p&gt;Check out the inside tag size of the sneakers. Usually, the fake Air Jordan 8 has thick text. \nCheck the inside stitching of your shoes; sometimes, the replica AJ8 pairs come with thin stitching. \nCheck the visibility of Jumpman on the tongue because Air Jordan 8 sneakers have equal likely Jumpman stitching that is too thin in the sneakers. \nVerify the Air Jordan 8s box because the replica box can be too curvy. &lt;/p&gt;\n&lt;p&gt;Meanwhile, the above are essential advice to buy an authentic Air Jordan 8 and save your money while buying the fake one. Also, choose an exact place to buy your Air Jordan 8.&lt;/p&gt;', 'https://i.imgur.com/1BmRdzj.jpg', 'how-to-spot-fake-air-jordan-8', '', '2021-01-24 15:57:11', '2021-01-24 15:57:11'),
(47, 'Nike LeBron 8 âSouth Beachâ Returning in 2021', '&lt;p&gt;Originally released in 2010, the Nike LeBron 8 &ldquo;South Beach&rdquo; will be returning during Spring 2021.&lt;/p&gt;\r\n&lt;p&gt;A nod to the beginning of LeBron&rsquo;s career in Miami. This Nike LeBron 8 created the popular &ldquo;South Beach&rdquo; theme that has been often imitated but never duplicated.&lt;/p&gt;\r\n&lt;p&gt;Dressed in a Pink Flash, Filament Green, and Black color scheme. No leaked photos have surfaced, but the &ldquo;South Beach&rdquo; LeBron 8 is expected to look exactly like 2010&rsquo;s original release.&lt;/p&gt;\r\n&lt;p&gt;Nike LeBron 8 &ldquo;South Beach&rdquo;\r\nColor: Retro/Pink Flash-Filament Green-Black\r\nStyle Code: CZ0328-400\r\nRelease Date: Spring 2021\r\nPrice: TBA&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/ZSv56u5.png&quot; alt=&quot;Lebron 9&quot; /&gt;\r\n&lt;img src=&quot;https://i.imgur.com/J6eMmQD.png&quot; alt=&quot;Lebron 9&quot; /&gt;\r\n&lt;img src=&quot;https://i.imgur.com/d8CvHOp.png&quot; alt=&quot;Lebron 9&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/ZSv56u5.png', 'lebron-8-south-beach-returning', '', '2021-02-07 15:45:40', '2021-02-07 15:45:40'),
(48, 'Nike Air Max CB 94 OG Returning This Month', '&lt;p&gt;Nike reveals another one of Charles Barkley&rsquo;s classic Air Max CB 94 colorways that will be returning early 2021.&lt;/p&gt;\n&lt;p&gt;Dressed in its original White, Black, and Purple color scheme. This Nike Air Max CB 94 features a clean White leather upper paired with Purple contrasting accents, ventilated perforations and Black detailing. Its signature lacing system with visible Max Air unit in the heel completes the design.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/AMxHIbB.png&quot; alt=&quot;Air Max CB 94&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/k2kxaP3.png&quot; alt=&quot;Air Max CB 94&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/gnKCE5i.png&quot; alt=&quot;Air Max CB 94&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/gkDZlHY.png&quot; alt=&quot;Air Max CB 94&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/eW6lwCK.png&quot; alt=&quot;Air Max CB 94&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/AMxHIbB.jpg', 'nike-air-max-cb-94-og-returning', '', '2021-02-07 20:44:44', '2021-02-07 20:44:44'),
(49, 'Fake Vs Real Air Jordan 1 Dior High', '&lt;h1&gt;How To Spot Fake Air Jordan 1 Retro High Dior&lt;/h1&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/KYN1l72.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;As soon as the highly-anticipated Dior x Air Jordan 1s dropped, it only took a week or so before fans started complaining about counterfeit products being sold in the market. In this day and age, it becomes extremely easy for companies to create close first copies of products, making it even harder to pick out a fake product. \nThere are videos posted by companies, for example, an extremely popular Chinese counterfeit seller Chan who showed first copies of both high and low-top versions of the shoes. Keeping that in mind, it becomes even more important for shoe lovers to be extra vigilant when buying admittedly expensive shoes. We have created a list that will be one of the easiest ways to check the legitimacy of your Dior Jordan 1&rsquo;s.&lt;/p&gt;\n&lt;h1&gt;Air Jordan 1 High Dior Real vs. Fake&lt;/h1&gt;\n&lt;p&gt;As a highly awaited collaboration 2020, the Air Jordans were under the radar of some of the country&rsquo;s most popular shoe enthusiasts. With the luxury powerhouse Dior and a popular sportswear industry leader like Nike, the result was a minimalist, two-toned color design that allows for unlimited styling. &lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior left outer swoosh&lt;/h2&gt;\n&lt;p&gt;Look for the outer side of the shoe that has the left &ldquo;swoosh&rdquo;. The stitching on the authentic shoe has a much darker, almost black shading. However, the counterfeit with a fake &ldquo;swoosh&rdquo; looks much lighter than the original Air Dior, and the oblique pattern is almost faded. \nThe shape of the swoosh is different for both pairs. Plus, you&rsquo;ll find the Air Dior logo on the leather flap looking much smaller in the fake one. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/lCU5P3J.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior right outer swoosh&lt;/h2&gt;\n&lt;p&gt;Both sides of the shoes are going to be indicators of fake vs. real Air Jordans. The heel of the authentic shoe is much higher than that of the fake one, but there is also a chance that there are minor differences in sizing that can create the difference even in authentic Nike Air Jordan Dior. \nMoreover, the monogram pattern on the fake Air Jordans is likely to be darker, as the authentic ones are always like and legible. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zAAZIx6.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior interior side of the shoe&lt;/h2&gt;\n&lt;p&gt;One great way to spot a fake Air Jordan is by having a look at the text inside the shoes. The counterfeit shoes use a different font for the &ldquo;8500&rdquo; text. The 8500 is significant because it stands for the fact that Dior AJ1s Retro Highs were stocked for only an amount of 8500 pairs. \nYou are likely to never see authentic AJ1s with a different font for the number. \nDifference in footbed &lt;/p&gt;\n&lt;p&gt;The fake AJ1s will have their text on the footbed improperly font-weighted. The Dior monogram on them is thinly embossed as opposed to the authentic AJ1s. The text is also thin on the former, while the latter uses a thicker font.&lt;/p&gt;\n&lt;p&gt;You will also notice the difference in stitching for both shoes. The Original Air Jordan 1s will have barely noticeable stitches, while the counterfeit will have thick and dense looking stitching. &lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior wings logo check&lt;/h2&gt;\n&lt;p&gt;Another tip would be checking if the details are defined. The photo below points out reference points where you should look into it. Check the spacing of the word Air Dior, the placement, and the font thickness/kerning. The wings on the fake show are also badly positioned. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/YTGLvSe.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior toebox check&lt;/h2&gt;\n&lt;p&gt;The toe box looks bulkier in the authentic version, while the fake one has a flatter looking toe box.  The counterfeit Air Jordan 1 Dior sneakers have perforation holes that are too big and too wide, and that gives the shoes a different look than the look of the authentic ones.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/fxTXmYi.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Air Jordan 1 High Dior sneaker box&lt;/h2&gt;\n&lt;p&gt;The fake Air Jordan 1 Dior usually comes in a black fake Nike box which is very low quality. What you should expect in your real pair is a high quality sturdy white Dior/Airbox.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Oavukv6.jpg&quot; alt=&quot;Air Jordan 1 Retro High Dior&quot; /&gt;&lt;/p&gt;', 'https://i.imgur.com/KYN1l72.jpg', 'fake-air-jordan-1-high-dior', '', '2021-02-10 19:32:47', '2021-02-10 19:32:47'),
(50, 'Ugg Boots, should you buy a pair', '&lt;p&gt;If you''re anything like me - fashion-wise anyway - the first purchase of any item is always, &quot;How am I going to look?&quot; This is especially true when the item is something as luxurious as a pair of Ugg boots. Beyond the actual cost, there are a ton of reasons why Ugg boots are the perfect footwear for anyone and any style.&lt;/p&gt;\n&lt;p&gt;Here are five just for starters: They''re not just for the kids anymore! The simple and obvious answer is: they are for everyone. Kids, teenagers, and adults are falling in love with their modern, Australian-made shoes.&lt;/p&gt;\n&lt;p&gt;They have a fantastic selection of styles and colors. The best part is, you don''t have to buy the same style as everyone else. Trendy, funky, quirky, or classy - no matter what your style is, there are a wide variety of unique colors and styles to choose from.&lt;/p&gt;\n&lt;p&gt;They''re comfortable- If you''re a guy who likes to wear five-inch boots, Ugg boots will more than likely feel comfortable with your current footwear. The wool lining means that your feet will feel warm and toasty in the cold of the early spring sun as well as offer comfortable arch support to those days when you just can''t bear to be without your shoes.&lt;/p&gt;\n&lt;p&gt;They''re lightweight- You might think that Ugg boots will feel heavy and hot, but they are incredibly lightweight - most of them. Made from pure wool, sheepskin, and especially suede, Ugg boots are unbelievably lightweight, whether your choice of the boot is the classic multi-strap model or one that closes with a buckle and a dual ankle strap.&lt;/p&gt;\n&lt;p&gt;Long-lasting, durable and comfortable, these boots are some of the trendiest footwear around. Most recently, celebrities have been seen sporting them at music festivals such as Coachella and performances on the Late, Late Show with Kanye West. If you match their funky hues to a wardrobe containing mostly muted neutrals and clean prints, however, you have to wonder how celebrities can wear such comfortable shoes while looking so put together.&lt;/p&gt;\n&lt;p&gt;They are unique- In an age where people seem to always want to stand out from the crowd, Ugg boots fit right in. With their vibrant color combinations, eye-catching design, and simple, defined shapes they are perfectly suited to set off an outfit or individual feature.&lt;/p&gt;\n&lt;p&gt;They are durable- As durable as they come, the simple styling and elastic sheepskin lacing mean that your boots will withstand your rough days outside.&lt;/p&gt;\n&lt;p&gt;Tailored, resplendent twills and soft lining offer solid construction and more comfort than your average winter boot. Ugg boots are made for keeping your feet work. There''s a reason why these boots are warm, cozy, and soft: they''re made with sheepskin. So why wouldn''t you want them for your feet? Consider the conditions that you''ll be wearing them in. Without socks, Uggs will help keep your feet nice and snug while still helping you make a statement. Uggs are also perfect for winter though, where your feet will be under plenty of snow and ice. Not only will your feet remain snug and comfortable, but the sheepskin will also ease with the frigid temperatures. Everyone should have a pair of comfortable and cozy Ugg boots in their closet, and the right pair will let you strut about with panache!&lt;/p&gt;', 'https://i.imgur.com/xxvLTk5.jpg', 'should-i-buy-ugg-boots', '', '2021-03-06 16:47:15', '2021-03-06 16:47:15'),
(51, 'A Closer Look at the Travis Scott x Fragment x Air Jordan 1 Low', '&lt;p&gt;Having a similar color blocking as the Air Jordan 1 High, this low-top Air Jordan 1 features a White leather base with Blue and Royal Blue overlays. Travis Scott&rsquo;s reverse Swoosh branding appears on the lateral side while &ldquo;Cactus Jack&rdquo; branding on the tongue and a stitched up smiley face on the left heel, while Hiroshi Fujiwara&rsquo;s double lightning bolt motif can be seen on the right.&lt;/p&gt;\n&lt;p&gt;Look for the Travis Scott x Fragment x Air Jordan 1 Low OG to release later this Fall 2021 at select retailers. Stay tuned for more updates.&lt;/p&gt;\n&lt;p&gt;Travis Scott x Fragment x Air Jordan 1 Low OG\nStyle Code: DM7866-140\nRelease Date: Fall 2021\nPrice: TBA&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/noZ3zXx.png&quot; /&gt; &lt;br/&gt;\n&lt;img src=&quot;https://i.imgur.com/n2RYYh4.png&quot; /&gt; &lt;br/&gt;\n&lt;img src=&quot;https://i.imgur.com/O2XTQWh.png&quot; /&gt; &lt;br/&gt;\n&lt;img src=&quot;https://i.imgur.com/iv2kI4E.png&quot; /&gt;', 'https://i.imgur.com/n2RYYh4.png', 'closer-look-at-travis-1-fragment', '', '2021-05-04 20:22:58', '2021-05-04 20:22:58'),
(52, 'Nike Dunk Low South Korea Release Date', '&lt;p&gt;As a follow up to 2018&rsquo;s Air Jordan 3 &ldquo;Seoul&rdquo; release, Nike will once again be paying homage to South Korea with a special edition Dunk Low.&lt;/p&gt;\n&lt;p&gt;Nike Dunk Low &ldquo;South Korea&rdquo;\nColor: Black/White-Red-Blue\nStyle Code: DM7708-100\nRelease Date: 2021\nPrice: $110&lt;/p&gt;\n&lt;p&gt;This &ldquo;South Korea&rdquo; offering of the Nike Dunk Low comes dressed in a color blocking resembling the Korean flag &ndash; which appears on the left tongue. The shoe features a White leather base with Black overlays and mismatching Red and Blue Swoosh logos and translucent outsoles. Finishing off the design are Korean characters in the rear atop a White midsole.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/TJozcf0.png&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/OIAYEFe.png&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/GdgY110.png&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/CkAgpms.png&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Ev6Y1L5.png&quot; /&gt;', 'https://i.imgur.com/Ev6Y1L5.png', 'nike-dunk-low-south-korea', '', '2021-05-16 04:26:41', '2021-05-16 04:26:41'),
(53, 'Undefeated Nike Kobe 5 Protro What If Release Date', '&lt;p&gt;Undefeated Nike Kobe 5 Protro What If Release Date&lt;/p&gt;\n&lt;p&gt;The three color options will include: &ldquo;Multi-Color/Metallic Gold-Multi-Color,&rdquo; &ldquo;Metallic Gold/Multi-Color-Field Purple&rdquo; and &ldquo;White/Metallic Gold-Rapid Teal.&rdquo; Each pair will feature Undefeated branding on the tongues, insoles, and heels.&lt;/p&gt;\n&lt;p&gt;Undefeated x Nike Kobe 5 Protro &ldquo;Hall of Fame&rdquo;\nColor: Metallic Gold/Field Purple-Multi-Color\nStyle Code: DA6809-700\nRelease Date: May 15, 2021\nPrice: $190&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/Uoe44AV.jpg&quot; /&gt;', 'https://i.imgur.com/Uoe44AV.jpg', 'Undefeated-kobe-5', '', '2021-05-16 04:30:07', '2021-05-16 04:30:07'),
(54, 'adidas Yeezy Quantum âOnyxâ Releasing in September', '&lt;p&gt;adidas Yeezy Quantum &ldquo;Onyx&rdquo; Releasing in September&lt;/p&gt;\r\n&lt;p&gt;adidas Yeezy Quantum &ldquo;Onyx&rdquo;\r\nColor: Onyx/Onyx-Onyx\r\nStyle Code: TBA\r\nRelease Date: September 2021\r\nPrice: $250&lt;/p&gt;\r\n&lt;p&gt;This offering of the adidas Yeezy Quantum features features a Primeknit upper in a mix of marbled Black and Grey shades with reflective paneling detailed in the heel. The shoe is its lifestyle iteration and will not be available in the performance BSKTBL version.&lt;/p&gt;\r\n\r\n&lt;img src=&quot;https://imgur.com/elFAJBh.jpg&quot; /&gt;\r\n&lt;img src=&quot;https://imgur.com/4REqTsx.png&quot; /&gt;\r\n&lt;img src=&quot;https://imgur.com/zVORREg.png&quot; /&gt;\r\n&lt;img src=&quot;https://imgur.com/xklpWow.png&quot; /&gt;', 'https://imgur.com/xklpWow.png', 'adidas-yeezy-quantum-onyx', '', '2021-05-16 01:00:10', '2021-05-16 01:00:10'),
(55, 'Fear Of God Essentials Hoodie Fake Vs Real Guide', '&lt;h1&gt;&lt;/h1&gt;\r\n&lt;p&gt;Fear Of God Essentials Hoodie Fake Vs Real Guide&lt;/p&gt;\r\n&lt;p&gt;Trying to spot fake Fear OF God Essentials hoodies? Read our guide so you don&rsquo;t get scammed.&lt;/p&gt;\r\n&lt;p&gt;This fake vs real Fear Of God Essentials guide will assist you with identifying real vs fake hoodies. Don&rsquo;t get scammed out here.&lt;/p&gt;\r\n&lt;h2&gt;Fake vs real FOG Essentials hoodie second wash tag&lt;/h2&gt;\r\n&lt;p&gt;In the image with the real vs fake Fear Of God Essentials hoodies below, You can see the image has multiple font weights which Are fake. The font-weight should be the same across the entire tag.&lt;/p&gt;\r\n&lt;img src=&quot;https://i.imgur.com/UGAhuiQ.png&quot; /&gt;\r\n&lt;h2&gt;The neck tag of your FOG Essentials hoodie&lt;/h2&gt;\r\n&lt;p&gt;The neck tag on the fake hoody has the wrong thickness on the text.\r\nThe ESSENTIALS thick is thinner on a real pair when compared to the replica version of the hoody.&lt;/p&gt;\r\n&lt;p&gt;The last flaw that we&rsquo;ve spotted on the fake neck tag is the &ldquo;FEAR OF GOD&rdquo; text which looks smaller and boxier than the authentic hoodie&rsquo;s text,&lt;/p&gt;\r\n&lt;img src=&quot;https://i.imgur.com/OIk2Yjd.png&quot; /&gt;\r\n&lt;img src=&quot;https://i.imgur.com/EbmGfFI.png&quot; /&gt;\r\n&lt;h2&gt;The &ldquo;ESSENTIALS&rdquo; text on the rubber tag&lt;/h2&gt;\r\n&lt;p&gt;The fake FOG hoodie has its &lsquo;ESSENTIALS&rdquo; text in a very thin font starting with the text. The authentic hoodie&rsquo;s text is much thicker. This is the inverse of the issue on the neck tag.&lt;/p&gt;\r\n&lt;p&gt;The authentic Fear Of God Essentials hoodie has its stitching that is set deep inside the patch, as no threads come out. The replica hoody stitching isn&rsquo;t deeply set and is very shallow.&lt;/p&gt;\r\n&lt;img src=&quot;https://i.imgur.com/GTv4nY2.png&quot; /&gt;\r\n&lt;img src=&quot;https://i.imgur.com/0o8oF1K.png&quot; /&gt;\r\n&lt;h2&gt;The FEAR OF GOD cardboard label&lt;/h2&gt;\r\n&lt;p&gt;In the image with the real vs fake Fear Of God Essentials hoodies above, we have pointed out how the fake item&rsquo;s text has incorrect font weight. This is where replicas always have the most trouble. &lt;/p&gt;\r\n&lt;img src=&quot;https://i.imgur.com/Q8vTKzx.png&quot; /&gt;', 'https://i.imgur.com/SqqSAV5.jpg', 'fear-of-god-essentials-fake-vs-real', '', '2021-05-16 00:50:06', '2021-05-16 00:50:06'),
(56, '"Yayoi Kusama: Infinity Mirror Rooms" Exhibition', '&lt;p&gt;Originally scheduled to open 1 year ago. London&rsquo;s Tate Modern has finally opened its new exhibition of work by Yayoi Kusama as galleries and museums are allowed to reopen. &lt;/p&gt;\n&lt;p&gt;The two Infinity Mirror Rooms featured in the exhibition are Infinity Mirrored Room &ndash; Filled with the Brilliance of Life &mdash; one of Kusama&rsquo;s largest installations, created for her 2012 retrospective at Tate Modern &mdash; and the Chandelier of Grief, which creates an endlessly repeating series of rotating chandeliers.&lt;/p&gt;', 'https://i.imgur.com/yEpaHxq.jpg', 'Yayoi-kusama-infinity-room', '', '2021-05-18 13:01:00', '2021-05-18 13:01:00'),
(57, 'Nike''s Offline 2.0 "Black" Combines Comfort With Technical Details', '&lt;p&gt;First and foremost, the design has been given a more technical update. We see a mesh foot covering now adorned with a less padded, but more tactile-looking aesthetic that&rsquo;s overlayed with a crisscrossed design of 3M-speckled rope laces. Working down, Nike adds a midfoot panel that&rsquo;s embroidered with a small Swoosh logo on the lateral side but not on the medial.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/U3nJM3X.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/8HH5b0W.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/2PRln9v.jpg&quot; /&gt;', 'https://i.imgur.com/2PRln9v.jpg', 'nike-offline-20-black', '', '2021-05-18 13:04:59', '2021-05-18 13:04:59'),
(58, 'First Look at the adidas YEEZY KNIT RNNR', '&lt;p&gt;First Look at the adidas YEEZY KNIT RNNR&lt;/p&gt;\n&lt;p&gt;The KNIT RNNR was first teased all the way back in August 2020, and was originally thought to be called the &ldquo;TRRL RNNR&rdquo; or the &ldquo;Turreliens.&rdquo; The colorway seen above is dubbed &ldquo;Case Power Yellow&rdquo; and offers a two-tone look with yellow on the midsole and upper contrasted by a sandy tan collar. Though the shoe is sheathed entirely in a knit material, it&rsquo;s very likely there&rsquo;s some type of standard cushioning setup present in the cored-out midsole as a 100% knit sneaker would not be durable enough for daily outdoor wear. The size is also stamped on the lateral heel in black, but this could very well be a feature of sample pairs.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/ierRnMQ.jpg&quot; /&gt;', 'https://i.imgur.com/ierRnMQ.jpg', 'adidas-yeezy-knit-rnnr', '', '2021-06-06 03:17:31', '2021-06-06 03:17:31'),
(59, 'BMW Unveils Its Race-Ready M4 GT3', '&lt;p&gt;BMW Unveils Its Race-Ready M4 GT3&lt;/p&gt;\n&lt;p&gt;Based on the M4 Competition, the main difference between the old M6 GT3 and the new M4 GT3 is what&rsquo;s under its hood: the 4.4-liter P63 V8 has now been replaced by a 3.0-liter P58 straight-six turbocharged engine, which not only shaves 40kg off its weight but also boosts power output from 580 horsepower to 590 horsepower. The racer also comes with a Competition Package which includes equipment that has been tested specifically for use in endurance races, such as additional headlights, spring travel sensors, a rear radar and camera, and a system for measuring both tire temperate and pressure.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/Xqw2Nbv.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/cHrIOlv.jpg&quot; /&gt;', 'https://i.imgur.com/Xqw2Nbv.jpg', 'bmw-unviels-its-race', '', '2021-06-06 03:21:06', '2021-06-06 03:21:06'),
(60, 'YUMS Sneakers Made Famous By Soulja Boy Are Back', '&lt;p&gt;YUMS Sneakers Made Famous By Soulja Boy Are Back&lt;/p&gt;\n&lt;p&gt;Maintaining the iconic look of the 2000s classic brand, the &ldquo;Sweet Series&rdquo; was designed by celebrated graffiti artist and Chief Creative Officer, Tex Moton. The &ldquo;Cupcake,&rdquo; &ldquo;Sugar,&rdquo; &ldquo;Rainbow Sherbet&rdquo; and &ldquo;Mixed Berry Tart&rdquo; colorways express tonal and multi-color designs that come in unisex sizing and accompanied by matching headwear. The sneakers are crafted of rich leather and suede with playful design obscured by a transparent rubber outsole segment.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/TSRSBX8.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/fHgYmlg.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/YgPqdE2.jpg&quot; /&gt;', 'https://i.imgur.com/TSRSBX8.jpg', 'yums-sneakers-soulja-boy', '', '2021-06-06 03:25:58', '2021-06-06 03:25:58'),
(61, 'Patek Philippe Drops Two New White Gold Aquanaut Chronographs', '&lt;p&gt;Patek Philippe Drops Two New White Gold Aquanaut Chronographs&lt;/p&gt;\n&lt;p&gt;Patek has selected two distinct colorways reflecting those already used by the time-only Ref. 5168G models, the first is a blue/black gradient dial with blue rubber strap and the second a matte khaki green dial and matching rubber strap. Both dials feature the stamped Aquanaut grid pattern with gold hands and applied Arabic numeral hour markers.&lt;/p&gt;\n&lt;p&gt;Both watches use Patek&rsquo;s 4Hz CH 28-520 C automatic flyback chronograph movement with a central chronograph seconds hand and a 60-minute chronograph sub dial at the six o&rsquo;clock position.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/M9Pg6Qy.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/VcsJUCe.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/B6CP4pA.jpg&quot; /&gt;', 'https://i.imgur.com/M9Pg6Qy.jpg', 'Gold-Aquanaut-Chronographs', '', '2021-06-06 03:37:17', '2021-06-06 03:37:17'),
(62, 'New York City''s Little Island Park is Now Open to the Public', '&lt;p&gt;New York City''s Little Island Park is Now Open to the Public&lt;/p&gt;\n&lt;p&gt;The new park is constructed along 13th street in Hudson River Park and covers 2.4 acres of ground. Within its walls, visitors will be able to enjoy over 350 species of flowers, trees and shrubs, a plaza with seating and food and beverages stalls dubbed &ldquo;The Play Ground,&rdquo; a stage and lawn area named &ldquo;The Glade,&rdquo; and a stunning amphitheater titled &ldquo;The Amph&rdquo; that hosts 687 people. Starting in June, the park will host various local performers and artists as well as throw a barrage of programs for people of all ages.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/Vp4pEjv.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/iXjCmCQ.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/rYsmjQv.jpg&quot; /&gt;', 'https://i.imgur.com/Vp4pEjv.jpg', 'new-york-city-little-island', '', '2021-06-06 03:43:10', '2021-06-06 03:43:10'),
(63, 'First Look: Nike LeBron 19', '&lt;p&gt;Take a closer look below, and you can expect the Nike LeBron 19 to release in July 2021 at select retailers and Nike.com. The retail price tag is set at $200 USD.&lt;/p&gt;\n&lt;p&gt;The LeBron 19 boasts a double-chambered Air Max unit in the heel and a newly shaped Zoom Air forefoot unit for a reliable underfoot ride for James. According to Nike Basketball footwear designer Jason Petrie, the new platform was inspired by the futuristic magic behind the movie.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/Qtyd6Dy.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/1EVyw2I.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/JWSZvKT.jpg&quot; /&gt;', 'https://i.imgur.com/Qtyd6Dy.jpg', 'first-look-lebron-19', '', '2021-06-08 16:28:19', '2021-06-08 16:28:19'),
(64, 'Air Jordan 12 Playoffs 2022 Release Date', '&lt;p&gt;Dressed in a Black, White, and True Red color scheme. This &ldquo;Playoffs&rdquo; edition of the Air Jordan 12 will come constructed in original form featuring a Black leather upper with White appearing on the mudguard, midsole, and rubber outsole. Other details includes Metallic Silver upper eyelets and Red covering the branded areas.&lt;/p&gt;\n&lt;p&gt;Air Jordan 12 &ldquo;Playoffs&rdquo;\nColor: Black/White-True Red\nStyle Code: TBA\nRelease Date: Spring 2022\nPrice: $190&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/befbBok.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Sulo3H0.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/rKzITzI.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/AnF5OM1.jpg&quot; /&gt;', 'https://i.imgur.com/befbBok.jpg', 'air-jordan-12-playoffs-release', '', '2021-06-08 16:30:40', '2021-06-08 16:30:40'),
(65, 'This Air Jordan 1 High OG Pays Tribute To MJâs Fraternity', '&lt;p&gt;Founded on November 17th, 1911, Omega Psi Phi is the first fraternal organization founded at a historically black university.&lt;/p&gt;\n&lt;p&gt;DUniversity Gold, Purple, and White. Air Jordan 1 features White leather side panels, nylon tongues, and midsole paired with Gold and Purple overlays nodding to the colors of the fraternity.&lt;/p&gt;\n&lt;p&gt;Look for the Air Jordan 1 High OG &ldquo;Omega Psi Phi&rdquo; to release during Spring 2022 at select retailers and Nike.com. The retail price tag is set at $170 USD.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/0XuYUxp.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/vFcB8TY.jpg&quot; /&gt;', 'https://i.imgur.com/0XuYUxp.jpg', 'jordans-fraternity-tribute', '', '2021-06-11 18:20:17', '2021-06-11 18:20:17'),
(66, '2021âs Air Jordan 5 âQuai 54â', '&lt;p&gt;Dressed in a White, University Red, and Black color scheme. This Air Jordan 5 features geometric prints, which are inspired by traditional African design and Parisian haute couture elements, on the laces, liner, and insole. The Quai 54 logo appears underneath the translucent netting and heel labels. 3M reflective tongues atop a White/Red rubber sole completes the design.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/m1BlgJZ.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/90FsdEo.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/TBUsbok.jpg&quot; /&gt;', 'https://i.imgur.com/m1BlgJZ.jpg', 'air-jordan-quai-54-2021', '', '2021-06-11 18:22:15', '2021-06-11 18:22:15');
INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(67, 'Nike Dunk Low âCamoâ on feet photos', '&lt;p&gt;This Nike Dunk Low highlights various camo prints utilized as its base with Black nubuck overlays. Oil Green shows up on the Swoosh, tongue tag, trim tips, and outsole. Different subtleties incorporate a Green &quot;NIKE&quot; weaving on the left heel, while the right highlights a b-ball logo in Orange. A White padded sole with Orange marking on the insoles finishes the plan.&lt;/p&gt;\n&lt;p&gt;Nike Dunk Low SE &ldquo;Camo&rdquo;\nColor: Black/Oil Green-White-Total Orange\nStyle Code: DH0957-001\nRelease Date: Spring 2021\nPrice: $110&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/ohTLIt4.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/LST6CAu.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/vYgprP8.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/ldBpsMD.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/10Oewku.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/bXCwOgR.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/3Vwkiqg.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/ZiUpzdo.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/uJIT1eF.jpg&quot; /&gt;', 'https://i.imgur.com/ohTLIt4.jpg', 'nike-dunk-camo-on-feet', '', '2021-06-13 16:38:30', '2021-06-13 16:38:30'),
(68, 'Off-White x Air Jordan 2 Low âBlack/Blueâ', '&lt;p&gt;Dressed in a Black, Blue, and Grey color scheme. This Off-White x Air Jordan 2 Low will feature a Black base paired with Blue accents and Red laces. It will also include the same detailing such as Michael Jordan&rsquo;s signature on the lateral side, Off-White branding on the medial portion, exposed-foam collars atop a cracked midsole.&lt;/p&gt;\n&lt;p&gt;Off-White x Air Jordan 2 Low\nColor: Black/Blue-Grey\nStyle Code: TBA\nRelease Date: Fall 2021\nPrice: TBA&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/4E3ZT0v.jpg&quot; alt=&quot;Off-White x Air Jordan 2&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/UZMq2DW.jpg&quot; alt=&quot;Off-White x Air Jordan 2&quot; /&gt;', 'https://i.imgur.com/UZMq2DW.jpg', 'off-white-jordan-2', '', '2021-06-20 21:19:53', '2021-06-20 21:19:53'),
(69, 'Air Jordan 13 âDel Solâ Releasing January 2022', '&lt;p&gt;Look for the Air Jordan 13 &ldquo;Del Sol&rdquo; to release in January 2022 at select retailers and Nike.com. The retail price tag is set at $190 USD.&lt;/p&gt;\n&lt;p&gt;Air Jordan 13 &ldquo;Del Sol&rdquo;\nColor: White/University Red-Del Sol-Black\nStyle Code: 414571-167\nRelease Date: January 2022\nPrice: $190&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/HmksAsR.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/6HhjuPy.jpg&quot; /&gt;', 'https://i.imgur.com/6HhjuPy.jpg', 'air-jordan-13-del-sol', '', '2021-06-20 21:22:21', '2021-06-20 21:22:21'),
(70, 'adidas Yeezy Boost 350 V2 MX Oat', '&lt;p&gt;The adidas Yeezy Boost 350 V2 MX Oat comes dressed in a buttery Yellow Primeknit upper topped off by the colorful swirling pattern made up of Orange, Blue and Golden Yellow hues. Other details include translucent stripe on the lateral and the return of the pull tab on the heel. Finishing details include a translucent Boost-cushioned sole and tonal butter Yellow laces.&lt;/p&gt;\n&lt;img src=&quot;https://i.imgur.com/ctLoQjg.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/UZMw1bm.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Bfp2YU5.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/8WToVit.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/xCPOoLO.jpg&quot; /&gt;\n&lt;img src=&quot;https://i.imgur.com/Gg9BZ1e.jpg&quot; /&gt;', 'https://i.imgur.com/Gg9BZ1e.jpg', 'yeezy-boost-350-mx-oat', '', '2021-06-20 21:25:51', '2021-06-20 21:25:51'),
(71, 'How to Spot Fake Vs Real Travis Scott Air Max 270 React Cactus Trails', '&lt;h1&gt;How to Spot Fake Vs Real Travis Scott Air Max 270 React Cactus Trails&lt;/h1&gt;\n&lt;h2&gt;Cactus Jack Air Max 270 React Size Tag&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zP71obn.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the image above, we have highlighted the fake pair have their &ldquo;CT2864-200&rdquo; text appearing too thin compared to the text met on the authentic pair. The replica pair also has used a different font than the authentic Travis Scott 270.&lt;/p&gt;\n&lt;p&gt;On the lower-left side of the size tag, you can spot how the fake 270s have their lines of text which indicate the country of manufacturing of the sneakers is too thick.&lt;/p&gt;\n&lt;h2&gt;Cactus Jack Air Max 270 React Swoosh&lt;/h2&gt;\n&lt;p&gt;Continuing the guide on how to spot fake Cactus Jack Air Max 270 React sneakers, we are going to investigate the fake vs real Cactus Jack 270 shoes for the Nike Swooshes on the rear and the toe of the shoe.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/tkTGNp5.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the fake vs real Travis Scott 270 image above, we have highlighted the fake pair Nike Swoosh is less defined and thinner than the Nike swoosh logo on the legit pairs.&lt;/p&gt;\n&lt;p&gt;On the other hand, the authentic Cactus Jack 270 pair has its Nike Swoosh logo is much thicker and more detailed.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/eKEiljl.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the Travis Scott 270 React real vs fake image above, we have pointed out how the replica pairSwoosh is awkwardly positioned. The fake pair, the Nike Swoosh is placed too low from the upper suede area. The authentic shoes have their Swoosh placed in the middle of the suede. The fake pairs tend to have a much thicker and  l\ness curvy than the one seen on the retail 270 pair.&lt;/p&gt;\n&lt;h2&gt;Travis Scott AM270 React tongue logo&lt;/h2&gt;\n&lt;p&gt;Pushing on in the guide on how to spot fake Air Max 270 React Travis Scott sneakers, we are going to investigate the Nike Swoosh logo on the blue plastic badge on the tongue.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/64lD9eN.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the real vs fake Cactus Trails 270 React image above, we have highlighted the fake Swoosh logo on the tongue&rsquo;s plastic badge looking too thick and too little curvy compared to the authentic Swoosh logo.&lt;/p&gt;\n&lt;p&gt;The authentic Cactus Trails 270 pair has its Swoosh on the tongue is much thinner, and besides, the retail pair has its Swoosh curvier than the fake sneakers&rsquo; Nike Swoosh logo.&lt;/p&gt;\n&lt;h2&gt;Travis Scott AM270 React Toe Box&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/9rnzaPP.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the fake vs real Travis Scott 270 React image above, we have highlighted out how the fake pair has a much thicker toebox and pretty swollen looking.&lt;/p&gt;\n&lt;p&gt;The authentic Travis Scott Air Max 270 React shoes have their toe box is much thinner, smaller, and less rounded compared to the fake pair of 270s.&lt;/p&gt;\n&lt;h2&gt;Travis Scott AM270 React Rear Details&lt;/h2&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/HlbuxcK.png&quot; alt=&quot;&amp;quot;Fake vs Real Travis Scott Air Max 270&amp;quot;&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;In the real vs fake Cactus Jack 270 image above, we have highlighted the fake sneakers have 3 lines above the text that are too thick as compared to the lines of the authentic shoes.&lt;/p&gt;\n&lt;p&gt;The first letter &ldquo;C&rdquo; in the &ldquo;Cactus&rdquo; text appears to be too thick and too curvy on the replica pairs, while the letter on the authentic shoes is thinner and less rounded than the fake shoes&rsquo; letter.&lt;/p&gt;\n&lt;p&gt;The brown suede patch, we have pointed out in the real vs fake Travis Scott Air Max 270 React image above how the fake shoes have their stitching on the edge of the patch and are much thinner than the stitching on the genuine sneaker.&lt;/p&gt;', 'https://i.imgur.com/fwrkgj9.jpg', 'fake-vs-real-travis-scott-air-max--270', '', '2021-06-25 21:17:46', '2021-06-25 21:17:46'),
(72, 'How to Spot Fake Air Jordan 1 Pine Green?', '&lt;h1&gt;How to Spot Fake Air Jordan 1 Pine Green?&lt;/h1&gt;\n&lt;p&gt;Online stores are active these days where fake products are being sold as originals. You need to be aware of how to spot fake Air Jordan 1 Pine Green. Nike fans can easily identify the replica or a fake, yet sometimes are too good to immediately identify. If you have the slightest doubt about the authenticity of the Nike shoes being sold to you, stop right there and review this guide.&lt;/p&gt;\n&lt;h1&gt;How to Identify Real or Fake Air Jordan 1 Pine Green?&lt;/h1&gt;\n&lt;p&gt;Shape, packaging, and text on the sneaker will help you to identify if the product is real or fake. Replicating the accuracy of the text printed on the interior tongue label is not an easy job and that&rsquo;s where you can spot a fake pair. If the text is not positioned in a uniform manner and has some irregularities, it&rsquo;s probably a fake AJ 1.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/dPwZQdM.png&quot; alt=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; title=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Overall Form of the Shoes&lt;/h2&gt;\n&lt;p&gt;Air Jordan 1 Pine Green is popular due to its unique and timeless design and shape. These sneakers are manufactured with quality leather and air units in the sole and it is not possible to produce an exact copy. There are some common mistakes that manufacturers may commit while replicating the product. Related to the overall shape and form of the article, focus on these points:&lt;/p&gt;\n&lt;p&gt;The heel and the toe box don&rsquo;t have subtle curves and proper alignment&lt;/p&gt;\n&lt;p&gt;The midsole is too thin or too thick&lt;/p&gt;\n&lt;p&gt;The color texture does not seem smooth&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/uj8AXXZ.png&quot; alt=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; title=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/btRprBz.png&quot; alt=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; title=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Placement of Nike Swoosh on Toungue&lt;/h2&gt;\n&lt;p&gt;Interior tongue label is usually the most important factor that can help you to spot the fake Air Jordan 1 Pine Green. This label has s few lines of text. You will notice that text is too thin in replicas as compared to normal text and &ldquo;Swoosh&rdquo; is placed too high or too low. The uniform text formation can help to identify the real Nike. The stitching of the label can also be used to spot the replicas. For the whole process, you can compare your product with the authentic information available online.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/CUGdijF.png&quot; alt=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; title=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;The Texture&lt;/h2&gt;\n&lt;p&gt;If you buy Nike, it means paying for quality. The leather texture of the shoes is the most important factor that adds to the quality and appearance of the sneakers. If the leather texture of a little bit off, you won&rsquo;t be able to tell the difference. Spotting the poor texture is a tricky task. The leather must be balanced without too many crinkles and mess. Original Air Jordan 1 Pine Green generally has wrinkles going upward, take a look at the photos below for an example&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/qODLr3K.png&quot; alt=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; title=&quot;How to Spot Fake Air Jordan 1 Pine Green&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Final Verdict\nPackaging of the box, price of the shoes, background of the seller, and many other factors can help you to spot fake Air Jordan 1 Pine Green. Pay attention to the details that generally go unnoticed and enjoy the real charm of authentic Air Jordan 1 Pine Green.&lt;/p&gt;', 'https://i.imgur.com/dPwZQdM.png', 'how-to-spot-fake-jordan-1-pine-green', '', '2021-07-12 00:15:28', '2021-07-12 00:15:28'),
(73, 'Nike X off white Air Jordan 5 sail Fake Vs Real', '&lt;h1&gt;Nike X off white Air Jordan 5 sail Fake Vs Real&lt;/h1&gt;\n&lt;p&gt;Nike is a legendry brand, and every item offers you the utmost satisfaction and comfort. Unfortunately, many people try to scam others by using Nike''s name on their low-quality products. You might have bought your pair of sneakers quite expensive thinking it was genuine Nike, but later it will turn out fake. &lt;/p&gt;\n&lt;p&gt;The worst thing in the whole process is that you have wasted money and time, and now you can&rsquo;t do anything.&lt;/p&gt;\n&lt;p&gt;The best thing is to learn to differentiate between fake and genuine Nike x off-white Air Jordan 5 sail. Why the sail 5? Because it is one of the popular Nike x sneakers and the fake pieces are commonly available in the market.&lt;/p&gt;\n&lt;p&gt;Do not worry if you are learning how to find the difference between fake and natural because this guide will teach you thoroughly about it. So let&rsquo;s get started.&lt;/p&gt;\n&lt;p&gt;How to test:\nWhen you are checking the sneakers, these things&lt;/p&gt;\n&lt;p&gt;Medial text:\nMedial text on both left and right side of the sneakers are the best way to detect which Nike x is fake and which one is genuine.\nYou can judge with different things like spelling errors, writing style, thickness, and sometimes the color used in the inscription is different.\nThe difference can be fake Nike X off-white Air Jordan 5 sail will have a thin texture. A Jordan will not feel right compared to the genuine one.\nThe word writing style will be slightly different because few fonts have copyrights, and the scammer cannot use it exactly.\nThere is a difference in spelling or overall words. There can be a difference of text on either shoes or any one side, so it is better to check properly.&lt;/p&gt;\n&lt;p&gt;So if any of these things do not match, that means there is something fishy. It is better to run off immediately.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zMJLqIR.png&quot; alt=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; title=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Nike X off white Air Jordan 5 sail Size tag:&lt;/h1&gt;\n&lt;p&gt;The second thing you need to compare is the size tag. Size tag is never consistent on fake Nike x Off-white Jordan 5 Sail shoes. Here is how you can find the difference\nFirst of all, look at the code text style. You will find that the fake texture is a pretty thing, and you will feel the difference instantly. On the other hand, the authentic Nike x off-white Jordan sneakers style code is thick and vivid.\nAfterward, look at the style of UPC and Manufacturing country text. You will find thin texture and writing style on the fake pair, and on genuine, it will be thick and clear, and if you have a pair or two of Nike sneakers before, you will instantly see the difference.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/jFzU0A2.png&quot; alt=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; title=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Nike X off white Air Jordan 5 sail Red lines on the midsole:&lt;/h1&gt;\n&lt;p&gt;It is something you can catch immediately. The genuine Nike x has thick perfect lines in red on the sides, whereas the red lines are flawed on the fake pair. You will find a difference in the sequence, thickness, and shape.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/1zBgSzd.png&quot; alt=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; title=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Nike X off white Air Jordan 5 sail tongue:&lt;/h1&gt;\n&lt;p&gt;The genuine Nike x Sail 5 Jumpman on the tongue is thicker than a fake shoe. You will find that the hand on the fake one looks thinner and genuine; it feels bulky. The difference is instant spot able.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/tK1XjlP.png&quot; alt=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; title=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;Nike X off white Air Jordan 5 sail Overall shape:&lt;/h1&gt;\n&lt;p&gt;Take a close look at the overall look of your shoes. The fake Nike x off-white Air Jordan 5 sail sneakers have fewer bumps, and they are less curvy. On the contrary genuine Nike x off-white Air Jordan 5 sail sneakers are more defined in shape. The authentic pairs of Nike x off-white Air Jordan 5 sail are bumpy.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/zXNCvVP.png&quot; alt=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; title=&quot;Nike X off white Air Jordan 5 sail Fake Vs Real&quot; /&gt;&lt;/p&gt;\n&lt;p&gt;Let&rsquo;s wrap it up:\nYou can easily differentiate between real and fake Nike x off-white Air Jordan 5 sail. All you need is to consider for a while before making a purchase.&lt;/p&gt;', 'https://soleinsider.s3.amazonaws.com/wbxmAYv.jpeg', 'nike-off-white-sail-fake-vs-real', '', '2021-08-06 00:59:39', '2021-08-06 00:59:39'),
(74, 'LVMH Acquires Majority Stake In Off-Whiteâ¢ Brand', '&lt;p&gt;Abloh, who established the brand, will hold 40% proprietorship in the organization following the arrangement. The creator is set to keep his general imaginative chief job for the brand, while New Guards Group who birthed Off-White&trade; with Abloh will, in any case, be the brand''s working accomplice. &lt;/p&gt;\n&lt;p&gt;Reports expressed that with a 60 percent stake, LVMH plans to work close by Abloh to create, make and develop new and existing brands that go past the design domain. With an accomplice like LVMH, Off-White&trade; will have a huge number of devices promptly accessible to assist it with growing its own image portfolio. The French extravagance combination has a broad scope of interests in design, beauty care products, gems, aromas, and even wines and spirits. The declaration doesn''t influence Virgil Abloh''s job at Louis Vuitton, where he is still the menswear line''s creative head.&lt;/p&gt;', 'https://soleinsider.s3.amazonaws.com/KAiyH7F.jpeg', 'LVMH-acquires-off-white', '', '2021-08-06 00:59:26', '2021-08-06 00:59:26'),
(75, 'Megan Thee Stallion, Naomi Osaka and More Chosen as New Sports Illustrated Swimsuit Models', '&lt;p&gt;Megan Thee Stallion has become the first historically speaking rapper to be show up on the front of Sports Illustrated''s Swimsuit Issue, joining tennis-star Naomi Osaka and model Leyna Bloom in three separate covers that emphasis on the topic of local area. &lt;/p&gt;\n&lt;p&gt;Albeit them three share little practically speaking, &quot;each is an update that magnificence comes in numerous structures,&quot; as indicated in a press articulation by SI supervisor in-boss, MJ Day. Osaka and Bloom similarly have broken show by turning into the primary Japanese-Haitian and transsexual lady to effortlessness the front of the SI Swimsuit Issue, individually. Megan Thee Stallion cheered the magazine for continually being on the &quot;cutting edge with regards to variety and incorporation since they don''t fear change.&quot;&lt;/p&gt;', 'https://soleinsider.s3.amazonaws.com/Sxai5wK.jpeg', 'megan-sports-illustrated ', '', '2021-08-06 00:59:14', '2021-08-06 00:59:14'),
(76, 'Kobe Bryantâs adidas Models Returning in 2022', '&lt;p&gt;Prior to marking with Nike in 2003, Kobe endorsed with Adidas back in 1996. One of the principal models he wore during his NBA tenderfoot season was the EQT Elevation, presently called the Crazy 97 EQT. To celebrate NBA All-Star returning in Cleveland in 2022, the Crazy 97 EQT will return in its unique &quot;Lakers&quot; Purple and Gold colorway, a similar pair he wore when he won the 1997 NBA Dunk Contest. Will deliver in another Blue and Orange colorway gesturing back to the ''97 All-Star Weekend in Cleveland. &lt;/p&gt;\r\n&lt;p&gt;The Kobe 1, presently called the Crazy 1, was Kobe Bryant''s first signature shoe that was initially delivered in 2001, which will likewise be returning. The first &quot;Daylight&quot; colorway is set for April to correspond with the McDonald''s All-American Game just as the first White and Black &quot;Stormtrooper&quot; colorway is additionally set for a re-discharge.&lt;/p&gt;\r\n&lt;p&gt;adidas Crazy 97 EQT &ldquo;Lakers&rdquo;\r\nStyle Code: GY4520\r\nRelease Date: February 2022\r\nPrice: TBA&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/R7rfleo.jpeg&quot; alt=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; title=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;adidas Crazy 1 &ldquo;Stormtrooper&rdquo;\r\nStyle Code: GY3810\r\nRelease Date: 2022\r\nPrice: TBA&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/LMshCqN.jpeg&quot; alt=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; title=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;adidas Crazy 97 EQT\r\nStyle Code: GY9125\r\nRelease Date: February 2022\r\nPrice: TBA&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/mYGc8dp.jpeg&quot; alt=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; title=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; /&gt;&lt;/p&gt;\r\n&lt;p&gt;adidas Crazy 1 &ldquo;Sunshine&rdquo;\r\nStyle Code: GY3808\r\nRelease Date: April 2022\r\nPrice: TBA&lt;/p&gt;\r\n&lt;p&gt;&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/aF2mXrn.png&quot; alt=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; title=&quot;Kobe Bryant&rsquo;s adidas Models Returning in 2022&quot; /&gt;&lt;/p&gt;', 'https://soleinsider.s3.amazonaws.com/aF2mXrn.png', 'kobe-adidas-models-returning', '', '2021-08-07 13:20:17', '2021-08-07 13:20:17'),
(77, 'sacai X ACRONYM Collaboration Officially Launching in January 2022', '&lt;p&gt;sacai X ACRONYM Collaboration Officially Launching in January 2022&lt;/p&gt;\r\n&lt;p&gt;The spirit of bonding comes through in the collection visually, with ACRONYM&rsquo;s innovative technical details melded into Tokyo-based sacai&rsquo;s signature fabrics and shapes. The collaboration marks the first time ACRONYM has released a dress silhouette, showcasing the brand&rsquo;s monochromatic color scheme and complimenting sacai&rsquo;s androgynous aesthetic. Pops of natural colors and woven textures also dot the women&rsquo;s offerings.&lt;/p&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/BvZwMKU.jpeg&quot; /&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/U9RPCmL.jpeg&quot; /&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/dqMajGF.jpeg&quot; /&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/3cHDiY7.jpeg&quot; /&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/b2B8cFb.jpeg&quot; /&gt;\r\n&lt;img src=&quot;https://soleinsider.s3.amazonaws.com/oyopUnW.jpeg&quot; /&gt;', 'https://soleinsider.s3.amazonaws.com/b2B8cFb.jpeg', 'sacai-X-ACRONYM', '', '2021-08-06 00:51:21', '2021-08-06 00:51:21'),
(78, 'How to spot fake vs real yeezy slides', '&lt;h1&gt;How to Spot Fake Yeezy Slides&lt;/h1&gt;\n&lt;p&gt;Adidas Yeezy Slides are Kanye West''s Yeezy slip-on sandals. There are a few tonal hues to choose from when it debuted in December 2019. Since joining the Three Stripes in 2013, we have displayed hundreds of hands-free, laceless footwear, but just a handful has received a retail release. If you want to identify fake Yeezy slides quickly, scan the barcode and check if any relevant searches have been done for the barcode on your pair.&lt;/p&gt;\n&lt;p&gt;Here are five best steps that describe how to spot fake Yeezy slides.&lt;/p&gt;\n&lt;h2&gt;Look at the Adidas Yeezy Slides barcode.&lt;/h2&gt;\n&lt;p&gt;The first step in determining whether a pair of Adidas Yeezy Slides is legitimate is to check the barcodes. Even though the model seems simple, it is difficult to duplicate without high-quality materials. If you look at a pair of slides, you will see that the soles of these shoes are shaped like shark teeth; this is what sets this model apart from others.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/j194yMm.png&quot; alt=&quot;Fake vs real yeezy slides&quot; title=&quot;Yeezy Barcode&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Look at the Adidas Yeezy Slides size label.&lt;/h2&gt;\n&lt;p&gt;We will now take a short check at the little white stickers inside the shoes for the second technique of authenticating Yeezy Slides. These stickers are meant to be affixed to the inside panels of your Yeezys and represent the shoe''s size. The font''s replica scaling tag failed miserably in this instance. We can see this by comparing the size of the numerals on the actual model with their tininess and asymmetry in the correct image.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/qHwMugY.jpg&quot; alt=&quot;Fake vs real yeezy slides&quot; title=&quot;Yeezy Size Label&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Look Adidas Yeezy Slides etched writing.&lt;/h2&gt;\n&lt;p&gt;When it comes to authenticating Adidas Yeezy Slides, we will now look at the wording on the internal panel of the actual vs. fake Yeezy Slides to see how it compares. This wording may be seen on the internal side panel of every genuine pair of Yeezy Slides. Replica companies never correctly reproduce the typefaces.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/RKuGZMG.jpg&quot; alt=&quot;Fake vs real yeezy slides&quot; title=&quot;Yeezy Slides&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the Adidas Yeezy Slides box&lt;/h2&gt;\n&lt;p&gt;We have arrived at the last technique for the day. When you get your Yeezy slides, the packaging is the first thing you notice. Genuine boxes have a smoother surface, whereas counterfeit ones have a grainy and rough surface. The original box''s lettering and numbers are more prominent but less bold, and the replica maker should have sought to replicate this appearance. The replicas always fail to copy the fonts correctly. &lt;/p&gt;\n&lt;h2&gt;Check Adidas Yeezy Slides for marks or creases&lt;/h2&gt;\n&lt;p&gt;The markings and creases on imitation Yeezy Slides are the subjects of the eighth and last phase in our tutorial on verifying Yeezy Slides. Some imitation Yeezy slides indeed leave the manufacturers with a few wrinkles, which may seem strange.&lt;/p&gt;\n&lt;h1&gt;Check the sizing. Do Yeezy Slides run small?&lt;/h1&gt;\n&lt;p&gt;Yeezy slides are true to size so always purchase them in your normal size. If you''re slides fit incorrectly than your normal size then they may be replicas.&lt;/p&gt;\n&lt;h1&gt;Check the footbed of your Yeezy Slides.&lt;/h1&gt;\n&lt;p&gt;The engraving on the fake pair slides will never look as finely finished as the original pair. The replica pairs the logo will not be as deep and are pale and asymmetrical. This gives away the replica immediately.If the logo does not pop immediately when you look at it then it may be a fake fair.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/dHOBjfD.jpg&quot; alt=&quot;Fake vs real yeezy slides&quot; title=&quot;Yeezy Slides&quot; /&gt;&lt;/p&gt;\n&lt;h1&gt;How can I spot fake Yeezy Slides in 60 seconds?&lt;/h1&gt;\n&lt;ul&gt;\n&lt;li&gt;Search the barcode of the Yeezy Slides using google and see if the results match your pair.&lt;/li&gt;\n&lt;li&gt;Check the size tag inconsistencies and bad printing quality.&lt;/li&gt;\n&lt;li&gt;Check the text on the interior panel of your slides and make sure all the engraving has the same depth and appearance.&lt;/li&gt;\n&lt;li&gt;Check the font of the box and overall quality of the boxes materials.&lt;/li&gt;\n&lt;li&gt;Lastly, remember to also have a look at the slides for any sort of marks or creases. Fake pairs tend to come with defects from the factory like markings and creases&lt;/li&gt;\n&lt;/ul&gt;', 'https://i.imgur.com/NFh3cqf.jpg', 'fake-vs-real-yeezy-slides', '', '2021-12-10 01:58:56', '2021-12-10 01:58:56'),
(79, 'Real vs Fake Gucci Slides', '&lt;h1&gt;Difference between real and fake Gucci slides&lt;/h1&gt;\n&lt;p&gt;How can you know whether the Gucci slides you are going to purchase on the internet are original? &lt;/p&gt;\n&lt;p&gt;Even products offered at a luxury consignment shop can be fake. An authorized Gucci merchant is the only method to guarantee that you will not wind up with a counterfeit pair of shoes.&lt;/p&gt;\n&lt;h1&gt;Step to ensure that your Gucci Slide is real or fake&lt;/h1&gt;\n&lt;p&gt;Make sure you do not wind up with a phony pair of slides or shoes by following these easy instructions. &lt;/p&gt;\n&lt;h1&gt;Know your Gucci boxes inside out&lt;/h1&gt;\n&lt;p&gt;The company has employed only two box designs: the classic black-and-white box and the famous brown box. The whole box except for the lid should be black for the latter. It makes the package seem seamless by having a black frame.&lt;/p&gt;\n&lt;h1&gt;Check the dust bags.&lt;/h1&gt;\n&lt;p&gt;Gucci dust bags are also available in black and white or brown, much like the boxes. Because dust bags have evolved so much throughout the years, it is difficult to tell them apart. All of these features should be present and correct in high-end products.&lt;/p&gt;\n&lt;h1&gt;Check the sticker label''s information.&lt;/h1&gt;\n&lt;p&gt;The information on the box''s sticker label should match what you ordered. Make careful to double-check this information thoroughly since most counterfeiters will not bother to alter it. Serial number, model name, color, size, barcodes, and a line representation of the object are all standard features of a genuine Gucci label. Make sure you do not end up with a label that includes images of the goods or handwriting.&lt;/p&gt;\n&lt;h1&gt;Become familiar with high-quality resources.&lt;/h1&gt;\n&lt;p&gt;It has a given that luxury goods specialists should be familiar with high-quality materials. Hardware and leather are the two most important components. Visit a few shops to get a sense of what real leather is like to the touch, smell, and sight of it. Quality hardware weighs and shines differently than painted plastic hardware. Learn about, inquire about, and seek out a variety of high-end materials.&lt;/p&gt;\n&lt;h1&gt;Look for the 8-digit serial number&lt;/h1&gt;\n&lt;p&gt;A serial number is hidden somewhere in the shoe for each type. The style number is six digits long, and the sizing is six digits long. The shoe''s serial number is often located on the lining''s heel tab. Shoes for women may have it outside the sole just above the size number in certain instances. Check the label on the shoebox. A pair of shoes should have the same number of digits printed.&lt;/p&gt;', 'https://i.imgur.com/Z9gyAFw.png', 'real-vs-fake-gucci-slides', '', '2022-02-15 18:18:15', '2022-02-15 18:18:15'),
(80, 'Real Vs. Fake Reverse Mocha Travis Scott Air Jordan 1 Low: How to Spot the Right Pair in 15 Seconds', '&lt;h2&gt;Real Vs. Fake Reverse Mocha Travis Scott Air Jordan 1 Low:&lt;/h2&gt;\n&lt;h3&gt;How to Spot the Right Pair in 15 Seconds:&lt;/h3&gt;\n&lt;p&gt;It''s quite easy but requires greater attention to the details. So, uncover Real Vs. Fake Reverse Mocha Travis Scott AJ1 Low by looking at these essential aspects: &lt;/p&gt;\n&lt;h2&gt;Look for the Interior Tongue label:&lt;/h2&gt;\n&lt;p&gt;The labels are the first hint to help differentiate between fake Vs. Real pairs. Note that the original Travis Scott Jordan 1 will never have misplaced text or fonts that are out of shape; they are thinner, smaller, and always up to the mark. That said, the variable thickness, misplaced text, and letters of fake pairs will always reveal their identity. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/SFGElXj.png&quot; alt=&quot;Travis Scott Air Jordan 1 Low&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Find Traces on Suede Fabric:&lt;/h2&gt;\n&lt;p&gt;The colored panels on the Reverse Mocha colorway use soft suede fabric that, when touched, will leave shades of traces behind. However, fake pairs are devoid of giving this suede effect and might lack intensity due to the grade of the leather used in making them. &lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/9XPYtWX.png&quot; alt=&quot;Travis Scott Air Jordan 1 Low&quot; /&gt;&lt;/p&gt;\n&lt;h3&gt;Check the Level of Toe Box:&lt;/h3&gt;\n&lt;p&gt;If you are a sneakerhead, you definitely can''t miss the authentic spot of Toe box shape and level in comparing the difference between real vs. fake Air Jordan. The genuine pairs are all about curves and round toe boxes, giving the white leather a bulkier and bigger outlook. &lt;/p&gt;\n&lt;p&gt;That&rsquo;s not the case when you examine the replica of Travis Scott Air Jordan 1 Low; they have a lean toe box with little or no curve, thus giving less accommodation space for the white part above the midsole.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/knqu7L4.png&quot; alt=&quot;Travis Scott Air Jordan 1 Low&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Find the Correct Medial Text:&lt;/h2&gt;\n&lt;p&gt;The medial text &ldquo;cactus Jack&rdquo; Logo is yet another clear indication to uncover replica Reverse Mocha Travis Scott Air Jordan 1 Low. The text, along with the three pairs of the line above, is way thinner if compared with the real ones. Also, the letter &quot;S&quot; is carved above the sole leaving a greater space at the end of the logo. It&rsquo;s quite the opposite of the real ones.&lt;/p&gt;\n&lt;p&gt;&lt;img src=&quot;https://i.imgur.com/Hh6N0Av.png&quot; alt=&quot;Travis Scott Air Jordan 1 Low&quot; /&gt;&lt;/p&gt;\n&lt;h2&gt;Check the Stitching Impression:&lt;/h2&gt;\n&lt;p&gt;Finally, never miss out on the stitching that is too dense on the fake Air Jordan 1 and leaves spaces between the logo that is darker in color. The real Air Jordan gives a much fuller logo with bright red color.&lt;/p&gt;\n&lt;h2&gt;Final Thought!&lt;/h2&gt;\n&lt;p&gt;You can now easily uncover Fake Vs. Real Reverse Mocha Travis Scott Air Jordan 1 Low by giving it your smart glance. Look for the essential details as elaborated in this guide. We are glad to help you buy an authentic Air Jordan pair. &lt;/p&gt;', 'https://i.imgur.com/nGBm5Js.jpg', 'real-vs-fake-travis-scott-1-mocha', '', '2022-10-04 19:34:45', '2022-10-04 19:34:45'),
(81, 'How To Spot A Fake rolex', '&lt;h1&gt;How To Spot A Fake rolex&lt;/h1&gt;\n&lt;p&gt;Spotting a fake Rolex can be a challenge, as counterfeiters have become increasingly skilled at creating convincing replicas. However, with a bit of knowledge and attention to detail, it''s possible to spot a fake Rolex and avoid falling victim to a scam. Here are some key tips for spotting fake Rolexes:&lt;/p&gt;\n&lt;h2&gt;Packaging&lt;/h2&gt;\n&lt;p&gt;Check the packaging. Authentic Rolex watches come in a variety of packaging, including a box, a sleeve, and a certificate of authenticity. Counterfeiters often produce fake packaging that doesn''t match the quality or design of the real thing, so if the packaging looks off, it''s a good indication that the watch may be fake.&lt;/p&gt;\n&lt;h2&gt;Quality&lt;/h2&gt;\n&lt;p&gt;Examine the quality of the materials. Authentic Rolexes are made with high-quality materials and construction techniques, so if the watch looks cheap or poorly made, it''s a red flag. Pay attention to the materials used for the case, bracelet, and dial, as well as the overall fit and finish of the watch. If anything looks off or subpar, it''s likely that the watch is fake.&lt;/p&gt;\n&lt;h2&gt;Logo&lt;/h2&gt;\n&lt;p&gt;Look for the Rolex logo and crown. The Rolex logo and crown are key identifiers for authentic Rolex watches. The logo should be clear and crisp, and the crown should be well-crafted and properly aligned with the case. Counterfeiters often produce fake Rolexes with blurry or poorly-made logos and crowns, so if the logo or crown on the watch you''re looking at is off, it''s a good indication that the watch is fake.&lt;/p&gt;\n&lt;h2&gt;Movement&lt;/h2&gt;\n&lt;p&gt;Check the movement. Authentic Rolex watches have high-quality movements that are built to last and run smoothly. If the movement of the watch you''re looking at is rough or irregular, it''s a sign that it may be fake. Additionally, authentic Rolex watches have a serial number engraved on the caseback, which you can use to verify the authenticity of the watch.&lt;/p&gt;\n&lt;h2&gt;Seller&lt;/h2&gt;\n&lt;p&gt;Buy from reputable sellers. One of the best ways to avoid buying a fake Rolex is to buy from reputable sellers. This can include official Rolex retailers, as well as other trusted watch retailers and resellers. While it''s not foolproof, buying from reputable sellers can greatly reduce the chances of getting a fake or counterfeit watch.&lt;/p&gt;\n&lt;h2&gt;Service&lt;/h2&gt;\n&lt;p&gt;Use an authentication service. If you''re still not sure whether the Rolex you''re looking at is real or fake, you can try using an authentication service. These services are provided by experts who are trained to spot fake or counterfeit watches and can help you verify the authenticity of the watch you''re looking at.&lt;/p&gt;\n&lt;p&gt;In conclusion, spotting a fake Rolex can be challenging, but by following the tips outlined above, you can greatly reduce the chances of getting scammed and ensure that you''re getting an authentic, high-quality watch.&lt;/p&gt;', 'https://i.imgur.com/7xlENz6.jpg', 'how-to-spot-a-fake-rolex', '', '2023-01-04 01:20:13', '2023-01-04 01:20:13'),
(82, 'How To Spot A Fake Air Jordan 3 Sneakers', '&lt;h1&gt;How To Spot A Fake Air Jordan 3&lt;/h1&gt;\n&lt;p&gt;The Air Jordan 3 is a highly coveted sneaker, with many collectors and sneaker enthusiasts seeking out authentic pairs. However, with the rise of sneaker culture and the increasing demand for rare and limited edition Air Jordan 3s, it''s not uncommon for fake or counterfeit versions of the shoe to appear on the market. Spotting a fake Air Jordan 3 can be challenging, especially if you''re not familiar with the details and nuances of the authentic version. In this article, we''ll go over some key tips and tricks for spotting fake Air Jordan 3s and help you avoid falling victim to counterfeiters.&lt;/p&gt;\n&lt;p&gt;Check the packaging. One of the easiest ways to spot a fake Air Jordan 3 is to look at the packaging. Authentic Air Jordan 3s come in a box with the Nike and Jordan Brand logos, as well as the model number (e.g. &quot;CD6847-100&quot;) and size information. The box should also have a sticker with a barcode and serial number on it. Counterfeiters often produce fake packaging that doesn''t match the quality or design of the real thing, so if the packaging looks off, it''s a good indication that the shoes may be fake.&lt;/p&gt;\n&lt;p&gt;Examine the quality of the materials. Another way to spot a fake Air Jordan 3 is to examine the quality of the materials used in the construction of the shoe. Authentic Air Jordan 3s are made with high-quality materials and construction techniques, so if the shoes look cheap or poorly made, it''s a red flag. Pay attention to the stitching, the materials used for the upper and midsole, and the overall fit and finish of the shoe. If anything looks off or subpar, it''s likely that the shoes are fake.&lt;/p&gt;\n&lt;p&gt;Look for the Jordan Brand logo. The Jordan Brand logo is a key identifier for authentic Air Jordan 3s. It''s usually located on the tongue of the shoe and should be an embossed or raised logo, not a flat or printed one. Counterfeiters often produce fake Air Jordan 3s with a flat or printed logo, so if the logo on the shoes you''re looking at is flat or printed, it''s a good indication that they''re fake.&lt;/p&gt;\n&lt;p&gt;Check the size and style information. Authentic Air Jordan 3s will have the model number and size information printed on the insole or on a tag inside the shoe. If the model number or size information is missing or doesn''t match the shoes you''re looking at, it''s a sign that they may be fake. Additionally, be sure to check the style information to ensure that the shoes you''re looking at are the correct style and colorway. Counterfeiters often produce fake Air Jordan 3s in rare or limited edition colorways, so if the shoes you''re looking at are advertised as a rare or limited edition release, be extra vigilant and double-check the details.&lt;/p&gt;\n&lt;p&gt;Buy from reputable sellers. One of the best ways to avoid buying fake Air Jordan 3s is to buy from reputable sellers. This can include official Nike and Jordan Brand retailers, as well as other trusted sneaker retailers and resellers. While it''s not foolproof, buying from reputable sellers can greatly reduce the chances of getting fake or counterfeit shoes.&lt;/p&gt;\n&lt;p&gt;Look for authenticators. If you''re still not sure whether the Air Jordan 3s you''re looking at are real or fake, you can try using an authenticator service. These services are provided by experts who are trained to spot fake or counterfeit sneakers and can help you verify the authenticity of the shoes you''re looking at.&lt;/p&gt;\n&lt;p&gt;In conclusion, spotting fake Air Jordan 3s can be challenging, but by following the tips outlined above, you can greatly reduce&lt;/p&gt;', 'https://i.imgur.com/4WjnXB1.png', 'how-to-spot-fake-jordan-3s', '', '2023-01-04 01:22:18', '2023-01-04 01:22:18'),
(83, 'Real Vs Fake Air Jordan 2 How To Tell', '&lt;p&gt;Air Jordan 2s have been one of the most iconic and beloved sneakers since their initial release in 1986. Designed by Bruce Kilgore, the Air Jordan 2s were the first sneakers made in Italy and the first to feature Nike&rsquo;s patented Air-Sole unit. Since their introduction, these sneakers have become an icon of both basketball and streetwear culture, worn by everyone from Michael Jordan himself to fans and collectors around the world.&lt;/p&gt;\n&lt;p&gt;As with any popular sneaker, the Air Jordan 2 has been subject to counterfeiting. Unfortunately, this has led to the rise of fake Air Jordan 2s in the market. These counterfeit shoes may look almost identical to the real thing, but they lack the quality and authenticity of the original.&lt;/p&gt;\n&lt;p&gt;In this article, we&rsquo;ll explore the differences between real and fake Air Jordan 2s to help you avoid getting scammed when buying a pair of these iconic sneakers.&lt;/p&gt;\n&lt;p&gt;The box\nOne of the easiest ways to identify fake Air Jordan 2s is by examining the box they come in. Authentic Air Jordan 2s come in a sturdy box with the iconic Nike Air logo on the lid. The box should have a label on the side with the size, color, and style number of the shoes. The box should also have the SKU number printed on the label, which should match the SKU number on the shoes&rsquo; tag.&lt;/p&gt;\n&lt;p&gt;Fake Air Jordan 2s often come in flimsy boxes that lack the Nike Air logo or any other branding. The label on the side of the box may have misspellings or incorrect information, and the SKU number may not match the number on the shoes&rsquo; tag.&lt;/p&gt;\n&lt;p&gt;The materials\nThe quality of materials used in the construction of Air Jordan 2s is one of the biggest differences between real and fake pairs. Authentic Air Jordan 2s are made with high-quality leather, suede, and other materials that are carefully chosen to ensure durability and comfort.&lt;/p&gt;\n&lt;p&gt;Fake Air Jordan 2s, on the other hand, are often made with cheap materials that lack the durability and quality of the authentic sneakers. The leather may be thin and flimsy, the suede may be rough and inconsistent, and the overall build quality may be poor.&lt;/p&gt;\n&lt;p&gt;The shape and size\nThe shape and size of the sneakers can also be a dead giveaway when it comes to identifying fake Air Jordan 2s. Authentic Air Jordan 2s have a sleek and streamlined silhouette that is designed to fit the foot comfortably. The sneakers should be true to size, with enough room in the toe box to allow for movement and comfort.&lt;/p&gt;\n&lt;p&gt;Fake Air Jordan 2s, however, may have an incorrect shape or size. The sneakers may be too bulky or too narrow, and the toe box may be too small or too large. This can make them uncomfortable to wear and cause pain and blisters.&lt;/p&gt;\n&lt;p&gt;The stitching\nThe stitching on Air Jordan 2s is another key factor to consider when identifying fake pairs. Authentic Air Jordan 2s have clean and consistent stitching, with no loose threads or frayed edges. The stitching should be even and straight, with no crooked or uneven lines.&lt;/p&gt;\n&lt;p&gt;Fake Air Jordan 2s may have sloppy or uneven stitching, with loose threads and frayed edges. The stitching may also be crooked or inconsistent, which can be a clear sign that the shoes are not authentic.&lt;/p&gt;\n&lt;p&gt;The details\nThe details on Air Jordan 2s are what make them truly unique and iconic. From the textured panels to the embossed Nike logo, every detail on these sneakers is carefully crafted to create a one-of-a-kind look and feel.&lt;/p&gt;\n&lt;p&gt;Fake Air Jordan 2s may have incorrect or missing details, which can be a clear sign that they are not authentic. The embossed Nike logo&lt;/p&gt;', 'https://i.imgur.com/jZrIMgM.png', 'real-vs-fake-air-jordan-2', '', '2023-03-09 02:25:31', '2023-03-09 02:25:31'),
(84, 'Lost And Found Air Jordan 1s real vs fake', '&lt;p&gt;Spotting fakes in the Lost And Found Air Jordan 1s? Easy peasy! Just take a peek at the label inside the tongue. The real deal always stands out from the copycats because their text is never wonky or too thin.&lt;/p&gt;\n&lt;p&gt;Here''s the lowdown on checking if your Air Jordan 1 Lost &amp;amp; Found is legit:&lt;/p&gt;\n&lt;h2&gt;Interior tongue label:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Fake ones have text that''s all stretched out and thick, especially the &quot;SWOOSH&quot; part. &lt;/li&gt;\n&lt;li&gt;Plus, look for &quot;MADE IN CHINA&quot; and &quot;FABRIQUE EN CHINE&quot; &ndash; if it''s too skinny, it''s a fake!&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Size tag:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Pay attention to the numbers and letters &ndash; if they''re looking too thin or small, it''s a red flag.&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Hourglass vs. tubular:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;The real pair has that classic hourglass shape, wider at the top and bottom, and slim in the middle. Fakes? They''re more like a tube, straight as an arrow.&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h1&gt;Distressing:&lt;/h1&gt;\n&lt;ul&gt;\n&lt;li&gt;Real ones have that authentic worn look, with little white dots on the leather. &lt;/li&gt;\n&lt;li&gt;Fakes try, but their dots are bigger and less convincing.&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Air Jordan logo&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Look at those wings! Real ones have ''em just right &ndash; not too close, not too thick. Fakes? They''re way off the mark.&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Perforations:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Check the toe box holes &ndash; if they''re big, it''s a fake. Real ones are smaller and more precise.&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Toe box:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Size matters! Fakes skimp on the space inside the toe box. Real ones? Roomy and tall!&lt;/li&gt;\n&lt;/ul&gt;\n&lt;h2&gt;Receipt:&lt;/h2&gt;\n&lt;ul&gt;\n&lt;li&gt;Last but not least, check the receipt. But don''t rely solely on it &ndash; some fakes come with sneaky swaps.&lt;/li&gt;\n&lt;/ul&gt;', 'https://i.imgur.com/6Ov83o5.jpg', 'lost-and-found-air-jordan-1s-real-vs-fake', '', '2023-12-03 04:50:33', '2023-12-03 04:50:33');
INSERT INTO `articles` (`id`, `title`, `content`, `cover`, `slug`, `keywords`, `created_at`, `updated_at`) VALUES
(85, 'The SSC SC-01 Is A $42,000 Tesla Competitor ', '&lt;p&gt;Hey, guess what''s revving up? The Small Sports Car (SSC) crew just unleashed China''s soon-to-be &ldquo;national sports car&rdquo; promising the ultimate driving rush!&lt;/p&gt;\n&lt;p&gt;Set to hit the scene in 2023, the SC-01 is packing some seriously cool specs. Apparently, it''s sizing up at 4,085mm long, 1,820mm wide, and 1,162mm tall (that&rsquo;s around 161x72x46 inches), putting it in the same ballpark as the Alpine A110 or the Audi TT.&lt;/p&gt;\n&lt;p&gt;But hold up, here''s where it gets wild! It''s tipping the scales at just 1,300kg (or 2,866 pounds)! That''s a whole lot lighter than most EVs out there. Even the Tesla Model 3, which is a bit of a heavyweight, comes in at 1,612 to 1,831kg (that''s 3,554-4,036 pounds). The Audi TT? It''s up to 1,540kg (3,395 pounds), while the Alpine A110 weighs less at 1,103kg (2,432 pounds).&lt;/p&gt;\n&lt;p&gt;Here''s the kicker: This bad boy is packing electric motors on all four wheels, delivering a sweet 429hp (320 kW/435 PS). With that power-to-weight ratio, it&rsquo;s tearing to 62 mph (100 km/h) in just 3.9 seconds!&lt;/p&gt;\n&lt;p&gt;You''d expect all that punch might drain the battery quick, right? Well, SSC claims this beast can cover up to 310 miles (500 km) per charge on the NEDC cycle. Not too shabby for a speed demon like this!&lt;/p&gt;\n&lt;p&gt;They''re shaking things up, too! No typical skateboard battery setup here. Nope, they''re spreading the battery love like a traditional sports car, parking it right in the middle for that perfect balance.&lt;/p&gt;\n&lt;p&gt;And check this out: keeping the driver low to the ground, a spaceframe chassis, and those horizontal, pushrod shock absorbers are giving it that classic mid-engine sports car feel.&lt;/p&gt;\n&lt;p&gt;In the spirit of small sports cars, they''re keeping it simple inside. Chinese-made components that are easy to get hold of and replace. Production''s kicking off in late 2023, and the sticker price? Hold on to your seat, it&rsquo;s expected to start at just &yen;300,000 (which converts to around $41,957 USD)!&lt;/p&gt;\n&lt;p&gt;Sadly, it''s not clear if they&rsquo;ll offer this bad boy outside of China for now. But man, if this ride lives up to the hype, it''s gonna be one heck of a thrill!&lt;/p&gt;', 'https://i.imgur.com/NVfWFsc.jpg', 'the-ssc-sc-01-is-a-42000-tesla-competitor', '', '2023-12-03 14:19:32', '2023-12-03 14:19:32'),
(86, '10 Tips to Spotting Fake Sneakers', '&lt;h1&gt;Sneakerhead Secrets: 10 Tricks to Spotting Fake Sneakers&lt;/h1&gt;\n&lt;p&gt;The sneaker game is bigger than ever, with collectors and resellers hunting for the hottest drops. But with demand skyrocketing, counterfeit sneakers have flooded the market, making it tough for even seasoned sneakerheads to tell real from fake. Whether you''re buying from a reseller, a marketplace, or even a retail store, knowing how to authenticate your kicks is a must.&lt;/p&gt;\n&lt;p&gt;Here are &lt;strong&gt;10 expert tricks&lt;/strong&gt; to help you spot fake sneakers and avoid getting scammed.&lt;/p&gt;\n&lt;h2&gt;1. Check the Box and Packaging&lt;/h2&gt;\n&lt;p&gt;Legit sneakers always come in high-quality boxes with sharp prints, strong cardboard, and no flimsy construction. Look out for:&lt;br /&gt;\n? &lt;strong&gt;Misspelled words&lt;/strong&gt; or incorrect font styles&lt;br /&gt;\n? &lt;strong&gt;Overly glossy or faded colors&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Incorrect sizing labels&lt;/strong&gt; (e.g., missing retail price or inconsistent fonts)  &lt;/p&gt;\n&lt;p&gt;Real sneaker boxes are sturdy, and the logos should be crisp and clear, not smudged or blurry.&lt;/p&gt;\n&lt;h2&gt;2. Inspect the Stitching&lt;/h2&gt;\n&lt;p&gt;Counterfeit sneakers often have sloppy or uneven stitching. Compare the stitching pattern to an authentic pair online. Look for:&lt;br /&gt;\n? &lt;strong&gt;Loose threads or excess glue&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Uneven spacing or wavy lines&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Different stitching from the brand&rsquo;s standard&lt;/strong&gt;  &lt;/p&gt;\n&lt;p&gt;Nike, Adidas, and other top brands use precise, uniform stitching&mdash;so if it looks off, it probably is.&lt;/p&gt;\n&lt;h2&gt;3. Compare the Fonts and Logos&lt;/h2&gt;\n&lt;p&gt;Brand logos are one of the easiest ways to detect fakes. Check:&lt;br /&gt;\n? &lt;strong&gt;Font thickness and letter spacing&lt;/strong&gt; (Nike, Adidas, and Yeezy logos are always consistent)&lt;br /&gt;\n? &lt;strong&gt;Logo positioning&lt;/strong&gt; (Should be centered and symmetrical)&lt;br /&gt;\n? &lt;strong&gt;Print clarity&lt;/strong&gt; (Fake logos can look slightly faded or oversized)  &lt;/p&gt;\n&lt;p&gt;For example, a fake &lt;strong&gt;Jordan Jumpman logo&lt;/strong&gt; may have odd proportions or look stretched.&lt;/p&gt;\n&lt;h2&gt;4. Feel the Materials&lt;/h2&gt;\n&lt;p&gt;Authentic sneakers use &lt;strong&gt;premium materials&lt;/strong&gt;. Counterfeits often use cheaper alternatives that don&rsquo;t feel right. Check for:&lt;br /&gt;\n? &lt;strong&gt;Leather texture&lt;/strong&gt; (Real leather feels soft and grainy, fake leather feels plasticky)&lt;br /&gt;\n? &lt;strong&gt;Mesh breathability&lt;/strong&gt; (Real mesh allows air to pass through, fake mesh feels stiff)&lt;br /&gt;\n? &lt;strong&gt;Sole firmness&lt;/strong&gt; (Legit sneaker soles should feel sturdy, not too soft or flimsy)  &lt;/p&gt;\n&lt;p&gt;A simple &lt;strong&gt;touch test&lt;/strong&gt; can often tell you if the materials feel high-quality or fake.&lt;/p&gt;\n&lt;h2&gt;5. Check the Smell&lt;/h2&gt;\n&lt;p&gt;Yes, &lt;strong&gt;the smell&lt;/strong&gt; is a big giveaway! Real sneakers have a &lt;strong&gt;fresh factory scent&lt;/strong&gt;, while fake sneakers often smell like:&lt;br /&gt;\n? &lt;strong&gt;Strong glue or chemicals&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Cheap plastic or rubber&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Synthetic paint odors&lt;/strong&gt;  &lt;/p&gt;\n&lt;p&gt;If the smell is overwhelming or unusual, it&rsquo;s likely a red flag.&lt;/p&gt;\n&lt;h2&gt;6. Verify the Serial Number and Tags&lt;/h2&gt;\n&lt;p&gt;Real sneakers come with unique &lt;strong&gt;serial numbers&lt;/strong&gt; that should match across the box and the shoe label. Look for:&lt;br /&gt;\n? &lt;strong&gt;Different serial numbers on left and right shoes&lt;/strong&gt; (Nike often does this)&lt;br /&gt;\n? &lt;strong&gt;Authentic label fonts and placement&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Matching SKU number on box and inside the shoe&lt;/strong&gt;  &lt;/p&gt;\n&lt;p&gt;You can also compare the tag with official product images on the brand&rsquo;s website.&lt;/p&gt;\n&lt;h2&gt;7. Look at the Insoles and Inside Details&lt;/h2&gt;\n&lt;p&gt;Fake sneakers often cut corners when it comes to interior details. Check:&lt;br /&gt;\n? &lt;strong&gt;Brand logos inside the shoe&lt;/strong&gt; (Fake ones might be blurry or incorrectly placed)&lt;br /&gt;\n? &lt;strong&gt;Insole texture&lt;/strong&gt; (Authentic insoles are firm with cleanly printed logos)&lt;br /&gt;\n? &lt;strong&gt;Exposed glue or rough stitching&lt;/strong&gt; (Cheap manufacturing often shows inside)  &lt;/p&gt;\n&lt;p&gt;A good trick is to remove the insoles and compare them to legit pairs online.&lt;/p&gt;\n&lt;h2&gt;8. Test the Weight and Flexibility&lt;/h2&gt;\n&lt;p&gt;Fakes are often &lt;strong&gt;lighter or too flexible&lt;/strong&gt; because of low-quality materials. Try:&lt;br /&gt;\n? &lt;strong&gt;Weighing the shoe&lt;/strong&gt; (Legit sneakers have a proper weight balance)&lt;br /&gt;\n? &lt;strong&gt;Bending the sole&lt;/strong&gt; (Fake sneakers might bend too easily or feel flimsy)&lt;br /&gt;\n? &lt;strong&gt;Tapping the material&lt;/strong&gt; (Real sneakers have a solid, premium feel)  &lt;/p&gt;\n&lt;p&gt;If the shoe feels too light or bends unnaturally, it&rsquo;s probably fake.&lt;/p&gt;\n&lt;h2&gt;9. Examine the Outsole and Traction&lt;/h2&gt;\n&lt;p&gt;Sneaker brands use &lt;strong&gt;advanced traction patterns&lt;/strong&gt; for grip and durability. Fake sneakers often have:&lt;br /&gt;\n? &lt;strong&gt;Shallow or incorrect traction patterns&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Wrong colors or poor rubber quality&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Smooth or overly glossy soles&lt;/strong&gt;  &lt;/p&gt;\n&lt;p&gt;For example, a real &lt;strong&gt;Air Jordan 1&lt;/strong&gt; outsole should have deep, well-defined grooves, while fakes often look faded or too shiny.&lt;/p&gt;\n&lt;h2&gt;10. Buy from Trusted Sources&lt;/h2&gt;\n&lt;p&gt;One of the &lt;strong&gt;best ways&lt;/strong&gt; to avoid fakes is to &lt;strong&gt;only buy from trusted sellers&lt;/strong&gt;. Stick to:&lt;br /&gt;\n? &lt;strong&gt;Official brand websites and stores&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;Verified resellers like GOAT, StockX, or Stadium Goods&lt;/strong&gt;&lt;br /&gt;\n? &lt;strong&gt;In-person sneaker conventions or reputable sneaker shops&lt;/strong&gt;  &lt;/p&gt;\n&lt;p&gt;If you&rsquo;re buying from eBay, Facebook Marketplace, or Instagram sellers, always &lt;strong&gt;ask for detailed pictures, receipts, and legit checks&lt;/strong&gt; before purchasing.&lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;Final Thoughts&lt;/h2&gt;\n&lt;p&gt;Spotting fake sneakers takes practice, but by following these &lt;strong&gt;10 sneakerhead secrets&lt;/strong&gt;, you can avoid scams and ensure your collection stays authentic. The more you research and compare, the easier it will be to &lt;strong&gt;tell real from fake&lt;/strong&gt;.  &lt;/p&gt;\n&lt;p&gt;Have you ever encountered fake sneakers? Share your experiences in the comments below!  &lt;/p&gt;\n&lt;p&gt;???? &lt;strong&gt;Stay authentic, stay fresh!&lt;/strong&gt; ????  &lt;/p&gt;', 'https://i.imgur.com/Btdsu3e.jpeg', '10-fake-sneaker-tips', '', '2025-02-08 21:50:35', '2025-02-08 21:50:35'),
(87, 'Allen Iverson: The Legacy of a Cultural and Basketball Icon', '&lt;h1&gt;&lt;strong&gt;Allen Iverson: The Legacy of a Cultural and Basketball Icon&lt;/strong&gt;&lt;/h1&gt;\n&lt;p&gt;Few players in NBA history have had a greater cultural and stylistic impact on the game than &lt;strong&gt;Allen Iverson&lt;/strong&gt;. Known as &ldquo;The Answer,&rdquo; Iverson wasn&rsquo;t just a basketball player&mdash;he was a movement. His influence stretched beyond the hardwood, reshaping the league&rsquo;s attitude toward individuality, toughness, and authenticity.  &lt;/p&gt;\n&lt;p&gt;From his electrifying crossovers to his fearless scoring ability, Iverson left an indelible mark on the game, inspiring generations of players who came after him. But his legacy isn&rsquo;t just about stats&mdash;it&rsquo;s about the impact he had on the culture of basketball and beyond.  &lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;&lt;strong&gt;The Underdog Story: Defying the Odds&lt;/strong&gt;&lt;/h2&gt;\n&lt;p&gt;Iverson&rsquo;s journey to the NBA was far from conventional. Born in &lt;strong&gt;Hampton, Virginia&lt;/strong&gt;, he faced numerous challenges growing up. Despite being a &lt;strong&gt;two-sport star in football and basketball&lt;/strong&gt;, his career almost ended before it began when he was sentenced to prison following a controversial brawl in a bowling alley. Though later pardoned by the governor, the incident put a target on his back.  &lt;/p&gt;\n&lt;p&gt;But &lt;strong&gt;talent and resilience&lt;/strong&gt; prevailed. Iverson earned a scholarship to &lt;strong&gt;Georgetown University&lt;/strong&gt;, where he played under legendary coach &lt;strong&gt;John Thompson&lt;/strong&gt;, who became a mentor and protector. In two seasons at Georgetown, he showcased an &lt;strong&gt;explosive offensive game&lt;/strong&gt;, setting the stage for what was to come in the NBA.  &lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;&lt;strong&gt;Revolutionizing the Game: The Iverson Effect&lt;/strong&gt;&lt;/h2&gt;\n&lt;p&gt;Selected &lt;strong&gt;first overall in the 1996 NBA Draft&lt;/strong&gt; by the &lt;strong&gt;Philadelphia 76ers&lt;/strong&gt;, Iverson quickly made his presence felt. Despite standing only &lt;strong&gt;6 feet tall&lt;/strong&gt;, he dominated the league with his unmatched speed, agility, and fearless scoring ability.  &lt;/p&gt;\n&lt;h3&gt;&lt;strong&gt;Defining On-Court Moments&lt;/strong&gt;&lt;/h3&gt;\n&lt;ul&gt;\n&lt;li&gt;&lt;strong&gt;The Crossover on Michael Jordan (1997)&lt;/strong&gt; &ndash; Iverson&rsquo;s now-legendary move against &lt;strong&gt;MJ&lt;/strong&gt; became an iconic moment that symbolized his confidence and fearlessness.  &lt;/li&gt;\n&lt;li&gt;&lt;strong&gt;2001 MVP Season&lt;/strong&gt; &ndash; Leading a &lt;strong&gt;below-average Sixers team to the NBA Finals&lt;/strong&gt;, Iverson &lt;strong&gt;won MVP&lt;/strong&gt; and delivered one of the most famous Finals performances ever, including the &lt;strong&gt;step-over on Tyronn Lue&lt;/strong&gt; in Game 1.  &lt;/li&gt;\n&lt;li&gt;&lt;strong&gt;Four-time Scoring Champion&lt;/strong&gt; &ndash; Iverson led the league in scoring four times, proving that size doesn&rsquo;t define dominance.  &lt;/li&gt;\n&lt;/ul&gt;\n&lt;p&gt;Iverson&rsquo;s &lt;strong&gt;relentless scoring, ball-handling wizardry, and never-back-down attitude&lt;/strong&gt; made him one of the most exciting players of all time.  &lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;&lt;strong&gt;The Cultural Impact: More Than Just Basketball&lt;/strong&gt;&lt;/h2&gt;\n&lt;p&gt;Iverson didn&rsquo;t just change how basketball was played&mdash;he changed how it was &lt;strong&gt;perceived&lt;/strong&gt;.  &lt;/p&gt;\n&lt;h3&gt;&lt;strong&gt;1. The Dress Code and Hip-Hop Influence&lt;/strong&gt;&lt;/h3&gt;\n&lt;p&gt;Iverson brought &lt;strong&gt;hip-hop culture&lt;/strong&gt; into the NBA. From his &lt;strong&gt;braids, tattoos, baggy clothes, and jewelry&lt;/strong&gt;, he represented the streets, and for many young fans, he was a symbol of &lt;strong&gt;authenticity&lt;/strong&gt;. His influence was so powerful that the NBA eventually implemented a &lt;strong&gt;dress code policy in 2005&lt;/strong&gt; to curb what some viewed as an overly urban image.  &lt;/p&gt;\n&lt;p&gt;Despite the backlash, Iverson&rsquo;s style became mainstream, paving the way for future players to express themselves freely.  &lt;/p&gt;\n&lt;h3&gt;&lt;strong&gt;2. The Toughness and Attitude&lt;/strong&gt;&lt;/h3&gt;\n&lt;p&gt;Iverson played every game as if it were his last. He was often the smallest player on the court, but his &lt;strong&gt;heart and toughness&lt;/strong&gt; made him larger than life. He played through &lt;strong&gt;countless injuries&lt;/strong&gt;, embodying the spirit of a warrior.  &lt;/p&gt;\n&lt;h3&gt;&lt;strong&gt;3. Inspiring the Next Generation&lt;/strong&gt;&lt;/h3&gt;\n&lt;p&gt;Many of today&rsquo;s NBA stars&mdash;&lt;strong&gt;LeBron James, Stephen Curry, Kyrie Irving, and Damian Lillard&lt;/strong&gt;&mdash;cite Iverson as one of their biggest inspirations. His &lt;strong&gt;style of play, confidence, and swagger&lt;/strong&gt; changed how young players approached the game.  &lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;&lt;strong&gt;The Legacy: What Iverson Left Behind&lt;/strong&gt;&lt;/h2&gt;\n&lt;p&gt;Even after retiring, Iverson&rsquo;s influence remains.  &lt;/p&gt;\n&lt;p&gt;&lt;strong&gt;Hall of Fame Induction (2016)&lt;/strong&gt; &ndash; Cementing his place among the greatest ever.&lt;br /&gt;\n&lt;strong&gt;Reebok&rsquo;s Enduring Relationship&lt;/strong&gt; &ndash; His signature &lt;strong&gt;Reebok Answer and Question sneakers&lt;/strong&gt; remain some of the most iconic basketball shoes ever.&lt;br /&gt;\n&lt;strong&gt;Cultural Icon Beyond Sports&lt;/strong&gt; &ndash; Iverson&rsquo;s impact stretches beyond basketball into &lt;strong&gt;music, fashion, and urban culture&lt;/strong&gt;.  &lt;/p&gt;\n&lt;p&gt;Despite never winning an NBA championship, Iverson&rsquo;s &lt;strong&gt;legacy is untouchable&lt;/strong&gt;. He wasn&rsquo;t just a player&mdash;he was a movement, a symbol of resilience, and a reminder that heart and talent can defy any odds.  &lt;/p&gt;\n&lt;hr /&gt;\n&lt;h2&gt;&lt;strong&gt;Final Thoughts&lt;/strong&gt;&lt;/h2&gt;\n&lt;p&gt;Allen Iverson wasn&rsquo;t just &ldquo;The Answer&rdquo; for the &lt;strong&gt;Philadelphia 76ers&lt;/strong&gt;&mdash;he was &lt;strong&gt;the answer for an entire generation&lt;/strong&gt; of basketball fans and players. His influence is still seen today in the way the game is played, the way athletes express themselves, and the way underdogs are embraced.  &lt;/p&gt;', 'https://i.imgur.com/F3ZTLNu.jpeg', 'allen-iversons-legacy', '', '2025-02-09 18:27:56', '2025-02-09 18:27:56');
